import React, { useEffect } from 'react';

interface ToastProps {
    message: string;
    type: 'success' | 'error' | 'info';
    onClose: () => void;
    duration?: number;
}

export const Toast: React.FC<ToastProps> = ({ message, type, onClose, duration = 3000 }) => {
    useEffect(() => {
        const timer = setTimeout(() => {
            onClose();
        }, duration);

        return () => clearTimeout(timer);
    }, [onClose, duration]);

    const bgColors = {
        success: 'bg-green-600',
        error: 'bg-red-600',
        info: 'bg-blue-600'
    };

    const icons = {
        success: 'fa-circle-check',
        error: 'fa-circle-exclamation',
        info: 'fa-circle-info'
    };

    return (
        <div className={`fixed top-5 right-5 z-50 flex items-center gap-3 px-6 py-4 rounded-lg shadow-lg text-white ${bgColors[type]} animate-fade-in-down transition-all transform hover:scale-105 cursor-pointer`} onClick={onClose}>
            <i className={`fa-solid ${icons[type]} text-xl`}></i>
            <span className="font-medium">{message}</span>
            <button onClick={(e) => { e.stopPropagation(); onClose(); }} className="ml-4 opacity-70 hover:opacity-100">
                <i className="fa-solid fa-xmark"></i>
            </button>
        </div>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import { DataInputPage } from './components/DataInputPage';
import { ReportDashboardPage } from './components/reports/ReportDashboardPage';
import { AdminSidebar } from './components/admin/AdminSidebar';
import { SessionList } from './components/admin/SessionList';
import { SettingsPage } from './components/admin/SettingsPage';
import { storageService } from './services/storageService';
import type { AppData, LicenseClassData, StudentRecord, ReportMetadata, SavedSession } from './types';
import { processExcelData } from './services/excelProcessor';
import { Toast } from './components/ui/Toast';

type AppView = 'dashboard' | 'create' | 'detail' | 'settings';

const App: React.FC = () => {
    // Navigation State
    const [currentView, setCurrentView] = useState<AppView>('dashboard');

    // Data State
    const [savedSessions, setSavedSessions] = useState<SavedSession[]>([]);

    // Working State (New or Selected Session)
    const [appData, setAppData] = useState<AppData | null>(null);
    const [studentRecords, setStudentRecords] = useState<StudentRecord[] | null>(null);
    const [selectedSession, setSelectedSession] = useState<SavedSession | null>(null);

    // UI State
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);
    const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info' } | null>(null);

    // Initial Metadata Template
    const [reportMetadata, setReportMetadata] = useState<ReportMetadata>({
        meetingTime: '18 giờ 00 phút',
        meetingLocation: 'Trung tâm dạy nghề và Sát hạch lái xe Đông Đô',
        organizer: 'Giám đốc Công an tỉnh',
        attendees: [
            { id: '1', name: 'Đồng chí: Trung tá Dương Kim Giang', role: 'Chức vụ: Phó Trưởng phòng, Chủ tịch Hội đồng' },
            { id: '2', name: 'Đồng chí: Trung tá Trần Duy Giang', role: 'Chức vụ: Đội trưởng, Phó Chủ tịch Hội đồng' },
            { id: '3', name: 'Ông: Vũ Tiến Tuế', role: 'Chức vụ: Giám đốc Trung tâm sát hạch, Ủy viên' },
            { id: '4', name: 'Đồng chí: Vương Mai Phương', role: 'Thư ký' },
        ],
        technicalErrorSBD: '02,153,369',
    });

    // Load sessions on mount
    const loadSessions = async () => {
        const sessions = await storageService.getAllSessions();
        setSavedSessions(sessions);
    };

    useEffect(() => {
        loadSessions();
    }, []);

    const showToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
        setToast({ message, type });
    };

    const handleExcelSubmit = (records: StudentRecord[]) => {
        setIsLoading(true);
        setError(null);
        try {
            const processedData = processExcelData(records);
            setStudentRecords(records);
            setAppData(processedData);
            showToast('Xử lý dữ liệu thành công! Vui lòng kiểm tra và lưu báo cáo.', 'info');
        } catch (e) {
             setError(`Lỗi xử lý file Excel: ${(e as Error).message}`);
             showToast('Lỗi xử lý file Excel', 'error');
        } finally {
            setIsLoading(false);
        }
    };

    // Calculated Grand Total for the currently active data
    const grandTotal = useMemo<LicenseClassData | null>(() => {
        if (!appData) return null;

        const allRows = [...appData.firstTime.rows, ...appData.retake.rows];
        if (allRows.length === 0) return null;

        return allRows.reduce((acc, row) => {
            acc.totalApplications += row.totalApplications;
            acc.totalParticipants += row.totalParticipants;
            acc.theory.total += row.theory.total;
            acc.theory.pass += row.theory.pass;
            acc.theory.fail += row.theory.fail;
            acc.simulation.total += row.simulation.total;
            acc.simulation.pass += row.simulation.pass;
            acc.simulation.fail += row.simulation.fail;
            acc.practicalCourse.total += row.practicalCourse.total;
            acc.practicalCourse.pass += row.practicalCourse.pass;
            acc.practicalCourse.fail += row.practicalCourse.fail;
            acc.onRoad.total += row.onRoad.total;
            acc.onRoad.pass += row.onRoad.pass;
            acc.onRoad.fail += row.onRoad.fail;
            acc.finalPass += row.finalPass;
            return acc;
        }, {
            class: 'a+b',
            totalApplications: 0,
            totalParticipants: 0,
            theory: { total: 0, pass: 0, fail: 0 },
            simulation: { total: 0, pass: 0, fail: 0 },
            practicalCourse: { total: 0, pass: 0, fail: 0 },
            onRoad: { total: 0, pass: 0, fail: 0 },
            finalPass: 0,
        });
    }, [appData]);

    const handleClearData = () => {
        setAppData(null);
        setStudentRecords(null);
        setError(null);
    };

    const handleSaveSession = async (name: string, reportDate: Date) => {
        if (!appData || !grandTotal || !studentRecords) return;
        setIsLoading(true);

        try {
            const newSession: SavedSession = {
                id: Date.now().toString(),
                name: name,
                createdAt: Date.now(),
                reportDate: reportDate.toISOString(),
                studentRecords: studentRecords,
                appData: appData,
                grandTotal: grandTotal,
                reportMetadata: reportMetadata
            };

            await storageService.saveSession(newSession);
            await loadSessions();

            // Reset and go to dashboard
            handleClearData();
            setCurrentView('dashboard');
            showToast('Đã lưu kỳ sát hạch thành công!', 'success');
        } catch (err) {
            showToast('Lỗi khi lưu dữ liệu!', 'error');
            console.error(err);
        } finally {
            setIsLoading(false);
        }
    };

    const handleUpdateSession = async (name: string, reportDate: Date, metadata: ReportMetadata) => {
        if (!selectedSession) return;
        setIsLoading(true);

        try {
            const updatedSession: SavedSession = {
                ...selectedSession,
                name: name,
                reportDate: reportDate.toISOString(),
                reportMetadata: metadata
            };

            await storageService.saveSession(updatedSession);
            await loadSessions();

            // Update local selected session state so the view refreshes immediately
            setSelectedSession(updatedSession);
            setReportMetadata(metadata);

            showToast('Đã cập nhật kỳ sát hạch!', 'success');
        } catch (err) {
            showToast('Lỗi khi cập nhật dữ liệu!', 'error');
            console.error(err);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDeleteSession = async (id: string) => {
        try {
            await storageService.deleteSession(id);
            await loadSessions();
            if (selectedSession?.id === id) {
                setSelectedSession(null);
                setCurrentView('dashboard');
            }
            showToast('Đã xóa kỳ sát hạch.', 'info');
        } catch (err) {
            showToast('Lỗi khi xóa dữ liệu!', 'error');
        }
    };

    const handleSelectSession = async (session: SavedSession) => {
        setIsLoading(true);

        // In local mode, session usually has full data, but getSessionById ensures it
        let fullSession = session;
        if (!session.appData || !session.studentRecords) {
             const loaded = await storageService.getSessionById(session.id);
             if (loaded) fullSession = loaded;
        }

        setSelectedSession(fullSession);
        setAppData(fullSession.appData);
        setStudentRecords(fullSession.studentRecords);
        setReportMetadata(fullSession.reportMetadata);
        setCurrentView('detail');
        setIsLoading(false);
    };

    const handleNavChange = (view: AppView) => {
        if (view === 'create') {
            handleClearData();
            setSelectedSession(null);
        }
        if (view === 'dashboard') {
            loadSessions();
        }
        setCurrentView(view);
    };

    const renderMainContent = () => {
        if (isLoading && !appData && currentView === 'dashboard') {
             return <div className="flex h-full items-center justify-center"><i className="fa-solid fa-spinner animate-spin text-4xl text-blue-500"></i></div>;
        }

        // 1. Dashboard View
        if (currentView === 'dashboard') {
            return (
                <SessionList 
                    sessions={savedSessions} 
                    onSelectSession={handleSelectSession} 
                    onDeleteSession={handleDeleteSession}
                    onCreateNew={() => handleNavChange('create')}
                    onRefresh={async () => { await loadSessions(); }}
                />
            );
        }

        // 2. Create View (Input -> Preview)
        if (currentView === 'create') {
            // If we have calculated data, show Preview Report
            if (appData) {
                 return (
                    <div className="h-full bg-gray-200">
                         {/* Header helper for "Back to input" */}
                         <div className="bg-white border-b px-4 py-2 flex justify-between items-center print:hidden">
                            <h2 className="font-bold text-gray-700">Tạo kỳ sát hạch mới - Xem trước</h2>
                            <button 
                                onClick={handleClearData} 
                                className="text-sm text-red-600 hover:text-red-800"
                            >
                                <i className="fa-solid fa-arrow-left"></i> Quay lại nhập liệu
                            </button>
                         </div>
                         <div className="h-[calc(100%-45px)] overflow-hidden">
                            <ReportDashboardPage 
                                summaryData={appData} 
                                studentRecords={studentRecords}
                                grandTotal={grandTotal} 
                                reportMetadata={reportMetadata}
                                mode="preview"
                                onSaveSession={handleSaveSession}
                            />
                         </div>
                    </div>
                );
            }

            // Else show Input Form
            return (
                <div className="h-full bg-gray-50 flex justify-center p-6 overflow-y-auto">
                    <div className="w-full max-w-4xl bg-white rounded-xl shadow-lg h-fit min-h-[600px] flex flex-col">
                         <DataInputPage 
                            onExcelSubmit={handleExcelSubmit}
                            isLoading={isLoading}
                            error={error}
                            onClearData={handleClearData}
                            reportMetadata={reportMetadata}
                            onMetadataChange={setReportMetadata}
                        />
                    </div>
                </div>
            );
        }

        // 3. Detail View (View Only/Edit)
        if (currentView === 'detail' && selectedSession && appData) {
             return (
                 <div className="h-full bg-gray-200 flex flex-col">
                     <div className="bg-white border-b px-6 py-3 flex justify-between items-center print:hidden shadow-sm z-20">
                        <div className="flex items-center gap-3">
                            <button 
                                onClick={() => setCurrentView('dashboard')} 
                                className="w-8 h-8 rounded-full bg-gray-100 hover:bg-gray-200 flex items-center justify-center text-gray-600 transition-colors"
                            >
                                <i className="fa-solid fa-arrow-left"></i>
                            </button>
                            <div>
                                <h2 className="font-bold text-lg text-gray-800">Chi tiết Kỳ Sát Hạch</h2>
                                <p className="text-xs text-gray-500">Đã lưu: {new Date(selectedSession.createdAt).toLocaleString('vi-VN')}</p>
                            </div>
                        </div>
                     </div>
                     <div className="flex-1 overflow-hidden relative z-0">
                         {isLoading ? (
                             <div className="flex h-full items-center justify-center">Loading full details...</div>
                         ) : (
                            <ReportDashboardPage 
                                summaryData={appData} 
                                studentRecords={studentRecords}
                                grandTotal={grandTotal} 
                                reportMetadata={reportMetadata}
                                mode="view"
                                initialReportDate={selectedSession.reportDate}
                                sessionName={selectedSession.name}
                                onUpdateSession={handleUpdateSession}
                            />
                         )}
                     </div>
                </div>
            );
        }

        // 4. Settings View
        if (currentView === 'settings') {
            return <SettingsPage />;
        }

        return null;
    };

    return (
         <div className="flex h-screen bg-gray-100 text-gray-800 font-sans overflow-hidden">
            {/* Sidebar Navigation */}
            <AdminSidebar currentView={currentView === 'detail' ? 'dashboard' : currentView} onChangeView={handleNavChange} />

            {/* Main Content Area */}
            <main className="flex-1 h-full relative flex flex-col min-w-0">
                {renderMainContent()}
            </main>

            {/* Global Toast */}
            {toast && (
                <Toast 
                    message={toast.message} 
                    type={toast.type} 
                    onClose={() => setToast(null)} 
                />
            )}
        </div>
    );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import type { AppData, LicenseClassData, StudentRecord, ReportMetadata } from '../../types';
import { GeneralReport } from './GeneralReport';
import { StudentListReport } from './StudentListReport';
import { isStudentPassed, isStudentAbsent } from '../../services/reportUtils';
import { exportGeneralReportToExcel, exportStudentListToExcel } from '../../services/excelGenerator';
import { ReportMetadataModal } from '../ReportMetadataModal';

interface ReportDashboardPageProps {
    summaryData: AppData;
    studentRecords: StudentRecord[] | null;
    grandTotal: LicenseClassData | null;
    reportMetadata: ReportMetadata;

    // Props mới cho tính năng lưu trữ
    mode?: 'preview' | 'view'; // 'preview' khi tạo mới, 'view' khi xem từ DB
    onSaveSession?: (sessionName: string, reportDate: Date) => void;
    // New prop for updating existing session
    onUpdateSession?: (sessionName: string, reportDate: Date, metadata: ReportMetadata) => void;
    initialReportDate?: string; // ISO String
    sessionName?: string; // Initial name for view mode
}

type ReportView = 'summary' | 'passed' | 'failed' | 'absent';

export const ReportDashboardPage: React.FC<ReportDashboardPageProps> = ({ 
    summaryData, 
    studentRecords, 
    grandTotal, 
    reportMetadata,
    mode = 'preview',
    onSaveSession,
    onUpdateSession,
    initialReportDate,
    sessionName: initialSessionName
}) => {
    const [view, setView] = useState<ReportView>('summary');
    const [reportDate, setReportDate] = useState<Date>(initialReportDate ? new Date(initialReportDate) : new Date());
    const [sessionName, setSessionName] = useState(initialSessionName || `Kỳ sát hạch ngày ${new Date().toLocaleDateString('vi-VN')}`);

    // Editing states
    const [isEditing, setIsEditing] = useState(false);
    const [localMetadata, setLocalMetadata] = useState<ReportMetadata>(reportMetadata);
    const [isMetadataModalOpen, setIsMetadataModalOpen] = useState(false);

    // Sync props to state when switching sessions in view mode
    useEffect(() => {
        if (mode === 'view') {
            if (initialReportDate) setReportDate(new Date(initialReportDate));
            if (initialSessionName) setSessionName(initialSessionName);
            setLocalMetadata(reportMetadata);
            setIsEditing(false); // Reset edit mode when switching sessions
        }
    }, [initialReportDate, initialSessionName, reportMetadata, mode]);

    // Cập nhật tên mặc định khi ngày thay đổi trong mode preview
    useEffect(() => {
        if (mode === 'preview' && !initialReportDate) {
             setSessionName(`Kỳ sát hạch ngày ${reportDate.toLocaleDateString('vi-VN')}`);
        }
    }, [reportDate, mode, initialReportDate]);

    const hasDetailedData = studentRecords && studentRecords.length > 0;

    // Reset view to summary if detailed data becomes unavailable
    useEffect(() => {
        if (!hasDetailedData) {
            setView('summary');
        }
    }, [hasDetailedData]);

    const { passedStudents, failedStudents, absentStudents } = useMemo(() => {
        if (!hasDetailedData) {
            return { passedStudents: [], failedStudents: [], absentStudents: [] };
        }
        const passed: StudentRecord[] = [];
        const failed: StudentRecord[] = [];
        const absent: StudentRecord[] = [];

        for (const record of studentRecords!) {
            if (isStudentAbsent(record)) {
                absent.push(record);
            } else if (isStudentPassed(record)) {
                passed.push(record);
            } else {
                failed.push(record);
            }
        }
        return { passedStudents: passed, failedStudents: failed, absentStudents: absent };
    }, [studentRecords, hasDetailedData]);

    const handleDownload = () => {
        switch(view) {
            case 'summary':
                exportGeneralReportToExcel(summaryData, grandTotal, reportDate, localMetadata);
                break;
            case 'passed':
                exportStudentListToExcel(passedStudents, 'Danh_Sach_Dat', reportDate);
                break;
            case 'failed':
                exportStudentListToExcel(failedStudents, 'Danh_Sach_Truot', reportDate);
                break;
            case 'absent':
                exportStudentListToExcel(absentStudents, 'Danh_Sach_Vang', reportDate);
                break;
        }
    };

    const handleSaveClick = () => {
        if (mode === 'preview' && onSaveSession) {
            onSaveSession(sessionName, reportDate);
        } else if (mode === 'view' && onUpdateSession) {
            onUpdateSession(sessionName, reportDate, localMetadata);
            setIsEditing(false);
        }
    };

    const handleCancelEdit = () => {
        setIsEditing(false);
        // Reset to initial values
        if (initialReportDate) setReportDate(new Date(initialReportDate));
        if (initialSessionName) setSessionName(initialSessionName);
        setLocalMetadata(reportMetadata);
    };

    const renderActiveReport = () => {
        switch(view) {
            case 'summary':
                return <GeneralReport appData={summaryData} grandTotal={grandTotal} reportDate={reportDate} reportMetadata={localMetadata} />;
            case 'passed':
                return <StudentListReport title="DANH SÁCH THÍ SINH ĐẠT SÁT HẠCH LÁI XE Ô TÔ" students={passedStudents} reportType="passed" reportDate={reportDate} />;
            case 'failed':
                return <StudentListReport title="DANH SÁCH THÍ SINH TRƯỢT SÁT HẠCH LÁI XE Ô TÔ" students={failedStudents} reportType="failed" reportDate={reportDate} />;
            case 'absent':
                 return <StudentListReport title="DANH SÁCH THÍ SINH VẮNG SÁT HẠCH LÁI XE Ô TÔ" students={absentStudents} reportType="absent" reportDate={reportDate} />;
            default:
                return null;
        }
    };

    const TabButton: React.FC<{reportView: ReportView; label: string; icon: string}> = ({reportView, label, icon}) => (
        <button
            onClick={() => setView(reportView)}
            className={`px-4 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 ${
                view === reportView 
                    ? 'bg-blue-600 text-white shadow' 
                    : 'text-gray-600 hover:text-blue-600 hover:bg-gray-100'
            }`}
        >
            <i className={`fa-solid ${icon}`}></i> {label}
        </button>
    );

    return (
        <div className="flex flex-col h-full">
            {/* Control Bar */}
            <div className="bg-white border-b border-gray-200 p-4 print:hidden flex flex-col xl:flex-row gap-4 justify-between xl:items-center sticky top-0 z-10 shadow-sm">

                {/* Left: View Switcher */}
                <div className="flex flex-wrap items-center gap-2">
                   <TabButton reportView="summary" label="Báo cáo chung" icon="fa-chart-pie" />
                   {hasDetailedData && (
                       <>
                        <TabButton reportView="passed" label="DS Đạt" icon="fa-circle-check" />
                        <TabButton reportView="failed" label="DS Trượt" icon="fa-circle-xmark" />
                        <TabButton reportView="absent" label="DS Vắng" icon="fa-user-slash" />
                       </>
                   )}
                </div>

                {/* Right: Actions */}
                <div className="flex flex-col sm:flex-row items-end sm:items-center gap-3">

                    {/* Mode specific controls */}
                    {(mode === 'preview' || isEditing) ? (
                        <div className="flex items-center gap-2 bg-blue-50 p-2 rounded-lg border border-blue-100 animate-fade-in">
                             <div className="flex flex-col">
                                <label className="text-[10px] text-blue-600 font-bold uppercase mb-0.5">Tên kỳ sát hạch</label>
                                <input 
                                    type="text"
                                    value={sessionName}
                                    onChange={(e) => setSessionName(e.target.value)}
                                    className="px-2 py-1.5 border border-blue-200 rounded-md text-sm w-48 sm:w-64 focus:ring-2 focus:ring-blue-500 outline-none"
                                    placeholder="Nhập tên kỳ..."
                                />
                             </div>

                             <div className="flex flex-col">
                                <label className="text-[10px] text-blue-600 font-bold uppercase mb-0.5">Ngày báo cáo</label>
                                <input 
                                    type="date" 
                                    value={reportDate.toISOString().split('T')[0]}
                                    onChange={(e) => setReportDate(new Date(e.target.value))}
                                    className="px-2 py-1.5 border border-blue-200 rounded-md text-sm w-36 focus:ring-2 focus:ring-blue-500 outline-none"
                                />
                             </div>

                             {isEditing && (
                                <button
                                    onClick={() => setIsMetadataModalOpen(true)}
                                    className="px-3 py-1.5 mt-4 bg-white border border-gray-300 text-gray-700 rounded-md hover:bg-gray-100 text-sm font-medium"
                                    title="Sửa thông tin biên bản"
                                >
                                    <i className="fa-solid fa-pen-to-square"></i>
                                </button>
                             )}
                        </div>
                    ) : (
                        // View Only Mode (Not Editing)
                        <div className="flex items-center gap-4 mr-4">
                            <div className="text-right">
                                <div className="text-xs text-gray-500">Ngày báo cáo</div>
                                <div className="font-semibold text-sm">{reportDate.toLocaleDateString('vi-VN')}</div>
                            </div>
                        </div>
                    )}

                    <div className="flex items-center gap-2 mt-4 sm:mt-0">
                         <button
                            onClick={handleDownload}
                            className="px-3 py-2 bg-teal-600 text-white rounded-md hover:bg-teal-700 transition-colors flex items-center gap-2 text-sm font-medium shadow-sm"
                            title="Tải file Excel"
                        >
                            <i className="fa-solid fa-file-excel"></i> <span className="hidden sm:inline">Excel</span>
                        </button>
                        <button
                            onClick={() => window.print()}
                            className="px-3 py-2 bg-gray-500 text-white rounded-md hover:bg-gray-600 transition-colors flex items-center gap-2 text-sm font-medium shadow-sm"
                            title="In báo cáo"
                        >
                            <i className="fa-solid fa-print"></i> <span className="hidden sm:inline">In</span>
                        </button>

                        {/* Action Buttons based on Mode */}
                        {mode === 'preview' && (
                            <button
                                onClick={handleSaveClick}
                                className="px-5 py-2 bg-indigo-600 text-white rounded-md hover:bg-indigo-700 transition-colors flex items-center gap-2 text-sm font-bold shadow-md ml-2 animate-pulse hover:animate-none border-2 border-indigo-500 hover:border-indigo-600"
                            >
                                <i className="fa-solid fa-floppy-disk"></i> Lưu Kỳ Sát Hạch
                            </button>
                        )}

                        {mode === 'view' && !isEditing && (
                            <button
                                onClick={() => setIsEditing(true)}
                                className="px-4 py-2 bg-orange-500 text-white rounded-md hover:bg-orange-600 transition-colors flex items-center gap-2 text-sm font-medium shadow-sm ml-2"
                            >
                                <i className="fa-solid fa-pen"></i> Sửa
                            </button>
                        )}

                        {mode === 'view' && isEditing && (
                            <>
                                <button
                                    onClick={handleSaveClick}
                                    className="px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 transition-colors flex items-center gap-2 text-sm font-medium shadow-sm ml-2"
                                >
                                    <i className="fa-solid fa-check"></i> Lưu
                                </button>
                                <button
                                    onClick={handleCancelEdit}
