                idleTimeoutMillis: 30000,
                connectionTimeoutMillis: 10000,
            };

            if (fileConfig.useSocket && fileConfig.instanceConnectionName) {
                config.host = `/cloudsql/${fileConfig.instanceConnectionName}`;
            } else {
                config.host = fileConfig.host;
                config.port = fileConfig.port ? parseInt(fileConfig.port) : 5432;
                config.ssl = { rejectUnauthorized: false }; // Allow self-signed certs for IP connections
            }
            return config;
        } catch (e) {
            console.error("⚠️ Error reading db-config.json:", e);
        }
    }

    // C. Fallback
    console.warn("⚠️ No valid DB configuration found. Using defaults.");
    return {
        user: 'postgres',
        password: 'password',
        database: 'Appbaocao',
        host: 'localhost',
        port: 5432
    };
};

const initPool = async () => {
    if (pool) {
        await pool.end();
    }

    const config = getDbConfig();

    // Validate config before connecting
    if (!config.password && process.env.NODE_ENV === 'production') {
        console.warn("❌ Missing DB_PASSWORD environment variable.");
    }

    console.log(`🔌 Connecting to DB...`);
    if (config.host.startsWith('/')) console.log(`   Mode: Unix Socket (${config.host})`);
    else console.log(`   Mode: TCP (${config.host}:${config.port || 5432})`);

    pool = new Pool(config);

    // Initial connection test
    try {
        const client = await pool.connect();
