            return (
                <div className="bg-red-100 text-red-700 px-3 py-1 rounded text-xs flex items-center gap-2">
                    <i className="fa-solid fa-triangle-exclamation"></i> Disconnected
                    <button onClick={checkServer}><i className="fa-solid fa-rotate"></i></button>
                </div>
            );
        }

        return (
            <div className={`border px-3 py-1 rounded text-xs flex items-center gap-2 ${serverInfo.dbConnected ? 'bg-green-50 text-green-700 border-green-200' : 'bg-yellow-50 text-yellow-700 border-yellow-200'}`}>
                <div className="flex items-center gap-1">
                    <i className={`fa-solid ${serverInfo.dbConnected ? 'fa-database' : 'fa-link-slash'}`}></i>
                    <span>{serverInfo.dbConnected ? 'DB Connected' : 'DB Disconnected'}</span>
                </div>
                <span className="opacity-50">|</span>
                <span>v{serverInfo.version}</span>
            </div>
        );
    };

    // Determine if we are likely on Cloud Run based on Node Environment
    const isProduction = serverInfo?.mode === 'production';

    return (
        <div className="p-6 md:p-10 h-full overflow-y-auto bg-gray-100">
            <div className="mb-6 flex flex-col md:flex-row md:items-end justify-between gap-4">
                <div>
                    <h2 className="text-2xl font-bold text-gray-800">Cấu hình hệ thống</h2>
                    <p className="text-gray-500 mt-1">Quản lý kết nối và đồng bộ dữ liệu.</p>
                </div>
                <div className="w-full md:w-auto flex justify-end">
                    {renderServerStatus()}
                </div>
            </div>

            {/* Tabs */}
            <div className="flex border-b border-gray-200 mb-6 bg-white rounded-t-lg px-2 pt-2">
                <button
                    className={`py-3 px-6 font-medium text-sm focus:outline-none rounded-t-lg transition-colors ${activeTab === 'database' ? 'bg-blue-50 border-t-2 border-blue-500 text-blue-600 font-bold' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
                    onClick={() => setActiveTab('database')}
                >
                    <i className="fa-solid fa-database mr-2"></i> Cloud SQL
                </button>
                <button
                    className={`py-3 px-6 font-medium text-sm focus:outline-none rounded-t-lg transition-colors ${activeTab === 'data' ? 'bg-blue-50 border-t-2 border-blue-500 text-blue-600 font-bold' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
                    onClick={() => setActiveTab('data')}
                >
                    <i className="fa-solid fa-cloud-arrow-up mr-2"></i> Đồng bộ
                </button>
            </div>

            <div className="bg-white rounded-b-xl rounded-tr-xl shadow-sm border border-gray-200 p-6 max-w-4xl min-h-[400px]">
                {activeTab === 'database' && (
                    <div className="space-y-6">

                        {/* Production Warning Banner */}
                        {isProduction && (
                            <div className="bg-green-50 border border-green-200 rounded-lg p-4 mb-4">
                                <h4 className="font-bold text-green-800 flex items-center gap-2">
                                    <i className="fa-solid fa-cloud"></i> Đang chạy trên Cloud Run (Production)
                                </h4>
                                <p className="text-sm text-green-700 mt-1">
                                    Hệ thống sẽ tự động ưu tiên kết nối Cloud SQL thông qua Biến môi trường.
                                    Việc nhập form bên dưới chỉ có tác dụng kiểm tra kết nối (Test), không lưu vĩnh viễn.
                                </p>
                                <div className="mt-3 text-xs bg-white p-2 rounded border border-green-100 text-gray-600 font-mono">
                                    Cần thiết lập Env Vars trên Google Cloud Console:<br/>
                                    - INSTANCE_CONNECTION_NAME: project:region:instance<br/>
                                    - DB_USER, DB_PASSWORD, DB_NAME
