                                    {syncStatus === 'syncing' ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-cloud-arrow-up"></i>}
                                    {syncStatus === 'syncing' ? 'Đang đồng bộ...' : 'Đồng bộ ngay lên Cloud SQL'}
                                </button>
                            </div>
                        </div>
                         {syncStatus === 'completed' && syncResult && (
