const express = require('express');
const cors = require('cors');
const path = require('path');
const fs = require('fs');
const { Pool, Client } = require('pg');
const compression = require('compression');
const helmet = require('helmet');

const SERVER_VERSION = '3.5.0-cloudrun';
console.log(`\n🚀 STARTING SERVER v${SERVER_VERSION}`);
console.log(`🌍 NODE_ENV: ${process.env.NODE_ENV}`);

const app = express();
const port = process.env.PORT || 8080;

// Config file path (Ephemeral in Cloud Run - File này sẽ mất khi restart container)
const CONFIG_FILE = path.join(__dirname, 'db-config.json');

// Global Pool Variable
let pool = null;

// --- 1. DATABASE CONFIGURATION ---

const getDbConfig = () => {
    // A. Priority 1: Environment Variables (Ưu tiên tuyệt đối cho Cloud Run)
    // Cloud Run tự động inject các biến này nếu cấu hình đúng

    // Case 1: Kết nối qua Unix Socket (Khuyên dùng cho Cloud Run kết nối Cloud SQL)
    // Biến môi trường thường đặt tên là INSTANCE_CONNECTION_NAME hoặc CLOUD_SQL_CONNECTION_NAME
    const instanceConnectionName = process.env.INSTANCE_CONNECTION_NAME || process.env.CLOUD_SQL_CONNECTION_NAME;

    if (instanceConnectionName) {
        console.log(`☁️  Detected Cloud SQL Socket Config: ${instanceConnectionName}`);
        return {
            user: process.env.DB_USER || 'postgres',
            password: process.env.DB_PASSWORD,
            database: process.env.DB_NAME || 'Appbaocao',
            host: `/cloudsql/${instanceConnectionName}`, // Đường dẫn Unix Socket chuẩn
            max: 20, // Tăng connection pool cho production
            idleTimeoutMillis: 30000,
            connectionTimeoutMillis: 15000,
        };
    }

    // Case 2: Kết nối qua TCP (IP Public/Private)
    if (process.env.DB_HOST) {
        console.log(`☁️  Detected TCP Config: ${process.env.DB_HOST}`);
        return {
            user: process.env.DB_USER || 'postgres',
            password: process.env.DB_PASSWORD,
            database: process.env.DB_NAME || 'Appbaocao',
            host: process.env.DB_HOST,
            port: process.env.DB_PORT ? parseInt(process.env.DB_PORT) : 5432,
            ssl: { rejectUnauthorized: false }, // Thường cần thiết cho kết nối SSL public
            max: 20,
            idleTimeoutMillis: 30000,
            connectionTimeoutMillis: 15000,
        };
    }

    // B. Priority 2: Local Config File (Dành cho Dev hoặc cấu hình tay tạm thời)
    if (fs.existsSync(CONFIG_FILE)) {
        try {
            const fileConfig = JSON.parse(fs.readFileSync(CONFIG_FILE, 'utf8'));
            console.log("📂 Loaded DB config from db-config.json (Local/Temp)");

            const config = {
                user: fileConfig.user,
                password: fileConfig.password,
                database: fileConfig.database,
                max: 10,
                idleTimeoutMillis: 30000,
                connectionTimeoutMillis: 10000,
            };

            if (fileConfig.useSocket && fileConfig.instanceConnectionName) {
                config.host = `/cloudsql/${fileConfig.instanceConnectionName}`;
            } else {
                config.host = fileConfig.host;
                config.port = fileConfig.port ? parseInt(fileConfig.port) : 5432;
                config.ssl = { rejectUnauthorized: false };
            }
            return config;
        } catch (e) {
            console.error("⚠️ Error reading db-config.json:", e);
        }
    }

    // C. Fallback
    console.warn("⚠️ No valid DB configuration found. Waiting for manual setup...");
    return null;
};

const initPool = async () => {
    if (pool) {
        await pool.end();
    }

    const config = getDbConfig();

    if (!config) {
        console.log("⏳ Database not configured yet.");
        return;
    }

    // Log connection attempt (che mật khẩu)
    const logConfig = { ...config, password: config.password ? '****' : 'NO_PASSWORD' };
    console.log(`🔌 Connecting to DB...`, logConfig);

    pool = new Pool(config);

    // Initial connection test
    try {
        const client = await pool.connect();
        const res = await client.query('SELECT NOW() as now');
        client.release();
        console.log('✅ Database connected successfully at:', res.rows[0].now);
        initSchema();
    } catch (err) {
        console.error('❌ Database connection error:', err.message);
        // Không crash app để user vẫn vào được UI sửa cấu hình
    }
};

const initSchema = async () => {
    if (!pool) return;
    const createTableQuery = `
        CREATE TABLE IF NOT EXISTS sessions (
            id VARCHAR(255) PRIMARY KEY,
            data JSONB NOT NULL,
            report_date TIMESTAMPTZ,
            created_at BIGINT
        );
    `;
    try {
        await pool.query(createTableQuery);
        console.log("✅ Schema verified (Table 'sessions').");
    } catch (err) {
        console.error("❌ Schema initialization error:", err);
    }
};

// Khởi tạo kết nối khi server start
initPool();

// --- 2. MIDDLEWARE ---

// Quan trọng cho Cloud Run: Trust Proxy để nhận đúng IP client qua Load Balancer
app.enable('trust proxy');

// Bảo mật HTTP Headers
app.use(helmet({
    contentSecurityPolicy: false, // Tắt CSP đơn giản để tránh lỗi load script/style inline (có thể bật lại và config kỹ hơn sau)
}));

// Nén Gzip để tăng tốc độ tải
app.use(compression());

app.use(cors({ origin: '*' }));
app.use(express.json({ limit: '50mb' })); // Tăng giới hạn upload
app.use(express.urlencoded({ extended: true, limit: '50mb' }));

// --- 3. API ENDPOINTS ---

app.get('/api/server-status', (req, res) => {
    // Check if pool exists and is healthy
    const isConnected = !!pool && !pool.ended;

    // Determine config source for UI info
    let configSource = 'file/none';
    if (process.env.INSTANCE_CONNECTION_NAME) configSource = 'env-socket';
    else if (process.env.DB_HOST) configSource = 'env-tcp';

    res.json({
        success: true,
        version: SERVER_VERSION,
        mode: process.env.NODE_ENV || 'development',
        dbConnected: isConnected,
        configSource: configSource
    });
});

// Save DB Config (Warning: Ephemeral in Cloud Run)
app.post('/api/save-db-config', async (req, res) => {
    try {
        const config = req.body;
        // Lưu tạm vào file
        fs.writeFileSync(CONFIG_FILE, JSON.stringify(config, null, 2));
        // Thử kết nối lại
        await initPool();
        res.json({ success: true, message: "Cấu hình đã lưu (Lưu ý: Trên Cloud Run sẽ mất khi restart)." });
    } catch (e) {
        res.status(500).json({ success: false, error: e.message });
    }
});

// Test Connection Endpoint (Không lưu, chỉ test)
app.post('/api/check-db-connection', async (req, res) => {
    const { user, password, database, host, port, instanceConnectionName, useSocket } = req.body;

    const clientConfig = {
        user,
        password,
        database,
        connectionTimeoutMillis: 5000,
    };

    if (useSocket && instanceConnectionName) {
         clientConfig.host = `/cloudsql/${instanceConnectionName}`;
    } else {
        clientConfig.host = host;
        clientConfig.port = port ? parseInt(port) : 5432;
        clientConfig.ssl = { rejectUnauthorized: false };
    }

    const client = new Client(clientConfig);

    try {
        await client.connect();
        const result = await client.query('SELECT version()');
        await client.end();
        res.status(200).json({ success: true, details: { version: result.rows[0].version } });
    } catch (err) {
        res.status(200).json({ success: false, error: err.message });
    }
});

// Sessions API
app.get('/api/sessions', async (req, res) => {
    if (!pool) return res.status(503).json({ error: "Database not connected" });
    try {
        const result = await pool.query('SELECT data FROM sessions ORDER BY created_at DESC');
        const sessions = result.rows.map(row => row.data);
        res.json(sessions);
    } catch (err) {
        console.error("GET sessions error:", err.message);
        res.status(500).json({ error: 'Database Error', details: err.message });
    }
});

app.get('/api/sessions/:id', async (req, res) => {
    if (!pool) return res.status(503).json({ error: "Database not connected" });
    const { id } = req.params;
    try {
        const result = await pool.query('SELECT data FROM sessions WHERE id = $1', [id]);
        if (result.rows.length === 0) return res.status(404).json({ error: 'Session not found' });
        res.json(result.rows[0].data);
    } catch (err) {
        res.status(500).json({ error: 'Internal Server Error' });
    }
});

app.post('/api/sessions', async (req, res) => {
    if (!pool) return res.status(503).json({ error: "Database not connected" });
    const session = req.body;
    if (!session || !session.id) return res.status(400).json({ error: 'Invalid session data' });

    const query = `
        INSERT INTO sessions (id, data, report_date, created_at) VALUES ($1, $2, $3, $4)
        ON CONFLICT (id) DO UPDATE SET data = EXCLUDED.data, report_date = EXCLUDED.report_date;
    `;
    try {
        await pool.query(query, [session.id, JSON.stringify(session), session.reportDate, session.createdAt]);
        res.status(200).json({ message: 'Saved successfully', id: session.id });
    } catch (err) {
        console.error("Save error:", err);
        res.status(500).json({ error: 'Failed to save session' });
    }
});

app.delete('/api/sessions/:id', async (req, res) => {
    if (!pool) return res.status(503).json({ error: "Database not connected" });
    try {
        await pool.query('DELETE FROM sessions WHERE id = $1', [req.params.id]);
        res.status(200).json({ message: 'Deleted successfully' });
    } catch (err) {
        res.status(500).json({ error: 'Failed to delete session' });
    }
});

// Fallback: Tất cả các route không phải API sẽ trả về file index.html (cho React Router)
app.use(express.static(path.join(__dirname, 'dist')));

app.get('*', (req, res) => {
    // Trả về index.html nếu file tồn tại
    const indexFile = path.join(__dirname, 'dist', 'index.html');
    if (fs.existsSync(indexFile)) {
        res.sendFile(indexFile);
    } else {
        res.status(404).send('App build not found. Please run build script.');
    }
});

app.listen(port, '0.0.0.0', () => {
    console.log(`✅ Server listening on port ${port}`);
});

import React, { useState, useEffect } from 'react';
import { storageService } from '../../services/storageService';

export const SettingsPage: React.FC = () => {
    const [activeTab, setActiveTab] = useState<'database' | 'data' | 'general'>('database');
    const [serverInfo, setServerInfo] = useState<{ version: string; mode: string; dbConnected: boolean; configSource?: string } | null>(null);
    const [serverCheckLoading, setServerCheckLoading] = useState(true);

    // Default values
    const [dbConfig, setDbConfig] = useState({
        host: '35.198.214.82',
        port: '5432',
        user: 'postgres',
        password: '',
        database: 'Appbaocao',
        useSocket: false,
        instanceConnectionName: ''
    });

    const [status, setStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
    const [message, setMessage] = useState<React.ReactNode | null>(null);

    // Sync State
    const [localCount, setLocalCount] = useState(0);
    const [syncStatus, setSyncStatus] = useState<'idle' | 'syncing' | 'completed'>('idle');
    const [syncResult, setSyncResult] = useState<{success: number, failed: number} | null>(null);

    const checkServer = async () => {
        setServerCheckLoading(true);
        try {
            const res = await fetch('/api/server-status');
            if (res.ok) {
                const contentType = res.headers.get("content-type");
                if (contentType && contentType.includes("application/json")) {
                    const data = await res.json();
                    setServerInfo(data);
                } else {
                     setServerInfo(null);
                }
            } else {
                setServerInfo(null);
            }
        } catch (e) {
            setServerInfo(null);
        } finally {
            setServerCheckLoading(false);
        }
    };

    useEffect(() => {
        checkServer();
        setLocalCount(storageService.getLocalSessionCount());
    }, []);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value, type } = e.target;
        setDbConfig(prev => ({
            ...prev,
            [name]: type === 'checkbox' ? (e.target as HTMLInputElement).checked : value
        }));
        if (status !== 'idle') {
            setStatus('idle');
            setMessage(null);
        }
    };

    const safeFetch = async (url: string, options: RequestInit) => {
        try {
            const response = await fetch(url, options);
            const contentType = response.headers.get("content-type");
            if (!contentType || !contentType.includes("application/json")) {
                const text = await response.text();
                if (text.trim().startsWith('<')) {
                    throw new Error("API chưa sẵn sàng (Lỗi HTML).");
                }
                throw new Error(`Lỗi phản hồi Server (${response.status})`);
            }
            if (!response.ok) {
                const errData = await response.json();
                throw new Error(errData.error || `Lỗi HTTP ${response.status}`);
            }
            return await response.json();
        } catch (err) {
            throw err;
        }
    };

    const handleTestConnection = async () => {
        setStatus('loading');
        setMessage(null);
        try {
            const result = await safeFetch('/api/check-db-connection', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(dbConfig),
            });

            if (result.success) {
                setStatus('success');
                setMessage('Kết nối thử thành công!');
            } else {
                setStatus('error');
                setMessage(result.error || 'Kết nối thất bại');
            }
        } catch (err) {
            setStatus('error');
            setMessage((err as Error).message);
        }
    };

    const handleSaveAndConnect = async () => {
        setStatus('loading');
        setMessage('Đang lưu và kết nối...');
        try {
            // 1. Test
            const testResult = await safeFetch('/api/check-db-connection', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(dbConfig),
            });

            if (!testResult.success) throw new Error(`Kết nối thất bại: ${testResult.error}`);

            // 2. Save
            await safeFetch('/api/save-db-config', {
                 method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(dbConfig),
            });

            setStatus('success');
            setMessage(<span>Đã lưu cấu hình (Tạm thời).</span>);
            checkServer();
        } catch (err) {
            setStatus('error');
            setMessage((err as Error).message);
        }
    };

    const handleSync = async () => {
        if (!confirm('Bạn có muốn đẩy toàn bộ dữ liệu từ Trình duyệt lên Cloud SQL không?')) return;
        setSyncStatus('syncing');
        const result = await storageService.syncLocalToCloud();
        setSyncStatus('completed');
        setSyncResult({ success: result.success, failed: result.failed });
        setLocalCount(storageService.getLocalSessionCount());
    };

    const renderServerStatus = () => {
        if (serverCheckLoading) return (
            <span className="text-gray-400 text-xs flex items-center gap-2"><i className="fa-solid fa-spinner animate-spin"></i> Checking...</span>
        );

