import { storageService } from './services/storageService';
import type { AppData, LicenseClassData, StudentRecord, ReportMetadata, SavedSession, TrainingUnit } from './types';
import { processExcelData } from './services/excelProcessor';
import { Toast } from './components/ui/Toast';

type AppView = 'dashboard' | 'create' | 'detail' | 'settings' | 'training-units';

const App: React.FC = () => {
    // Navigation State
    const [currentView, setCurrentView] = useState<AppView>('dashboard');

    // Data State
    const [savedSessions, setSavedSessions] = useState<SavedSession[]>([]);

    // Working State (New or Selected Session)
    const [appData, setAppData] = useState<AppData | null>(null);
    const [studentRecords, setStudentRecords] = useState<StudentRecord[] | null>(null);
    const [selectedSession, setSelectedSession] = useState<SavedSession | null>(null);
    const [trainingUnits, setTrainingUnits] = useState<TrainingUnit[]>([]);

    // UI State
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);
    const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info' } | null>(null);

    // Initial Metadata Template
    const [reportMetadata, setReportMetadata] = useState<ReportMetadata>({
        meetingTime: '18 giờ 00 phút',
        meetingLocation: 'Trung tâm dạy nghề và Sát hạch lái xe Đông Đô',
        organizer: 'Giám đốc Công an tỉnh',
        attendees: [
            { id: '1', name: 'Đồng chí: Trung tá Dương Kim Giang', role: 'Chức vụ: Phó Trưởng phòng, Chủ tịch Hội đồng' },
            { id: '2', name: 'Đồng chí: Trung tá Trần Duy Giang', role: 'Chức vụ: Đội trưởng, Phó Chủ tịch Hội đồng' },
            { id: '3', name: 'Ông: Vũ Tiến Tuế', role: 'Chức vụ: Giám đốc Trung tâm sát hạch, Ủy viên' },
            { id: '4', name: 'Đồng chí: Vương Mai Phương', role: 'Thư ký' },
        ],
        technicalErrorSBD: '02,153,369',
    });

    // Load sessions on mount
    const loadSessions = async () => {
        const sessions = await storageService.getAllSessions();
        setSavedSessions(sessions);
    };

    useEffect(() => {
        loadSessions();
    }, []);

    const showToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
        setToast({ message, type });
    };

    const handleExcelSubmit = (records: StudentRecord[]) => {
        setIsLoading(true);
        setError(null);
        try {
            const processedData = processExcelData(records);
            setStudentRecords(records);
            setAppData(processedData);
            showToast('Xử lý dữ liệu thành công! Vui lòng kiểm tra và lưu báo cáo.', 'info');
        } catch (e) {
             setError(`Lỗi xử lý file Excel: ${(e as Error).message}`);
             showToast('Lỗi xử lý file Excel', 'error');
        } finally {
            setIsLoading(false);
        }
    };

    // Calculated Grand Total for the currently active data
    const grandTotal = useMemo<LicenseClassData | null>(() => {
        if (!appData) return null;

        const allRows = [...appData.firstTime.rows, ...appData.retake.rows];
        if (allRows.length === 0) return null;

        return allRows.reduce((acc, row) => {
            acc.totalApplications += row.totalApplications;
            acc.totalParticipants += row.totalParticipants;
            acc.theory.total += row.theory.total;
            acc.theory.pass += row.theory.pass;
            acc.theory.fail += row.theory.fail;
            acc.simulation.total += row.simulation.total;
            acc.simulation.pass += row.simulation.pass;
            acc.simulation.fail += row.simulation.fail;
            acc.practicalCourse.total += row.practicalCourse.total;
            acc.practicalCourse.pass += row.practicalCourse.pass;
            acc.practicalCourse.fail += row.practicalCourse.fail;
            acc.onRoad.total += row.onRoad.total;
            acc.onRoad.pass += row.onRoad.pass;
            acc.onRoad.fail += row.onRoad.fail;
            acc.finalPass += row.finalPass;
            return acc;
        }, {
            class: 'a+b',
            totalApplications: 0,
            totalParticipants: 0,
            theory: { total: 0, pass: 0, fail: 0 },
            simulation: { total: 0, pass: 0, fail: 0 },
            practicalCourse: { total: 0, pass: 0, fail: 0 },
            onRoad: { total: 0, pass: 0, fail: 0 },
            finalPass: 0,
        });
    }, [appData]);

    const handleClearData = () => {
        setAppData(null);
        setStudentRecords(null);
        setError(null);
        // trainingUnits are global config, do not clear them when clearing session data
    };

    const handleSaveSession = async (name: string, reportDate: Date) => {
        if (!appData || !grandTotal || !studentRecords) return;
        setIsLoading(true);

        try {
            const newSession: SavedSession = {
                id: Date.now().toString(),
                name: name,
                createdAt: Date.now(),
                reportDate: reportDate.toISOString(),
                studentRecords: studentRecords,
                appData: appData,
                grandTotal: grandTotal,
                reportMetadata: reportMetadata,
                trainingUnits: trainingUnits // Save units
            };

            await storageService.saveSession(newSession);
            await loadSessions();

            // Reset and go to dashboard
            handleClearData();
            setCurrentView('dashboard');
            showToast('Đã lưu kỳ sát hạch thành công!', 'success');
        } catch (err) {
            showToast('Lỗi khi lưu dữ liệu!', 'error');
            console.error(err);
        } finally {
            setIsLoading(false);
        }
    };

    const handleUpdateSession = async (name: string, reportDate: Date, metadata: ReportMetadata) => {
        if (!selectedSession) return;
        setIsLoading(true);

        try {
            const updatedSession: SavedSession = {
                ...selectedSession,
                name: name,
                reportDate: reportDate.toISOString(),
                reportMetadata: metadata,
                // trainingUnits usually don't change in this edit mode, 
                // but if we added unit editing in view mode, we would update it here.
                // For now, keep existing.
                trainingUnits: selectedSession.trainingUnits || []
            };

            await storageService.saveSession(updatedSession);
            await loadSessions();

            // Update local selected session state so the view refreshes immediately
            setSelectedSession(updatedSession);
            setReportMetadata(metadata);

            showToast('Đã cập nhật kỳ sát hạch!', 'success');
        } catch (err) {
            showToast('Lỗi khi cập nhật dữ liệu!', 'error');
            console.error(err);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDeleteSession = async (id: string) => {
        try {
            await storageService.deleteSession(id);
            await loadSessions();
            if (selectedSession?.id === id) {
                setSelectedSession(null);
                setCurrentView('dashboard');
            }
            showToast('Đã xóa kỳ sát hạch.', 'info');
        } catch (err) {
            showToast('Lỗi khi xóa dữ liệu!', 'error');
        }
    };

    const handleSelectSession = async (session: SavedSession) => {
        setIsLoading(true);

        // In local mode, session usually has full data, but getSessionById ensures it
        let fullSession = session;
        if (!session.appData || !session.studentRecords) {
             const loaded = await storageService.getSessionById(session.id);
             if (loaded) fullSession = loaded;
        }

        setSelectedSession(fullSession);
        setAppData(fullSession.appData);
        setStudentRecords(fullSession.studentRecords);
        setReportMetadata(fullSession.reportMetadata);
        setTrainingUnits(fullSession.trainingUnits || []); // Load units
        setCurrentView('detail');
        setIsLoading(false);
    };

    const handleNavChange = (view: AppView) => {
        if (view === 'create') {
            handleClearData();
            setSelectedSession(null);
        }
        if (view === 'dashboard') {
            loadSessions();
        }
        setCurrentView(view);
    };

    const renderMainContent = () => {
        if (isLoading && !appData && currentView === 'dashboard') {
             return <div className="flex h-full items-center justify-center"><i className="fa-solid fa-spinner animate-spin text-4xl text-blue-500"></i></div>;
        }

        // 1. Dashboard View
        if (currentView === 'dashboard') {
            return (
                <SessionList 
                    sessions={savedSessions} 
                    onSelectSession={handleSelectSession} 
                    onDeleteSession={handleDeleteSession}
                    onCreateNew={() => handleNavChange('create')}
                    onRefresh={async () => { await loadSessions(); }}
                />
            );
        }

        // 2. Training Units Management
        if (currentView === 'training-units') {
            return (
                <TrainingUnitManager 
                    trainingUnits={trainingUnits}
                    onUnitsImport={(units) => {
                        setTrainingUnits(units);
                        showToast(`Đã cập nhật ${units.length} đơn vị đào tạo!`, 'success');
                    }}
                />
            );
        }

        // 3. Create View (Input -> Preview)
        if (currentView === 'create') {
            // If we have calculated data, show Preview Report
            if (appData) {
                 return (
                    <div className="h-full bg-gray-200">
                         {/* Header helper for "Back to input" */}
                         <div className="bg-white border-b px-4 py-2 flex justify-between items-center print:hidden">
                            <h2 className="font-bold text-gray-700">Tạo kỳ sát hạch mới - Xem trước</h2>
                            <button 
                                onClick={handleClearData} 
                                className="text-sm text-red-600 hover:text-red-800"
                            >
                                <i className="fa-solid fa-arrow-left"></i> Quay lại nhập liệu
                            </button>
                         </div>
                         <div className="h-[calc(100%-45px)] overflow-hidden">
                            <ReportDashboardPage 
                                summaryData={appData} 
                                studentRecords={studentRecords}
                                grandTotal={grandTotal} 
                                reportMetadata={reportMetadata}
                                mode="preview"
                                onSaveSession={handleSaveSession}
                                trainingUnits={trainingUnits} // Pass units from global state
                            />
                         </div>
                    </div>
                );
            }

            // Else show Input Form
            return (
                <div className="h-full bg-gray-50 flex justify-center overflow-y-auto">
                    <div className="w-full max-w-5xl bg-white shadow-lg h-full flex flex-col">
                         <DataInputPage 
                            onExcelSubmit={handleExcelSubmit}
                            isLoading={isLoading}
                            error={error}
                            onClearData={handleClearData}
                            reportMetadata={reportMetadata}
                            onMetadataChange={setReportMetadata}
                        />
                    </div>
                </div>
            );
        }

        // 4. Detail View (View Only/Edit)
        if (currentView === 'detail' && selectedSession && appData) {
             return (
                 <div className="h-full bg-gray-200 flex flex-col">
                     <div className="bg-white border-b px-6 py-3 flex justify-between items-center print:hidden shadow-sm z-20">
                        <div className="flex items-center gap-3">
                            <button 
                                onClick={() => setCurrentView('dashboard')} 
                                className="w-8 h-8 rounded-full bg-gray-100 hover:bg-gray-200 flex items-center justify-center text-gray-600 transition-colors"
                            >
                                <i className="fa-solid fa-arrow-left"></i>
                            </button>
                            <div>
                                <h2 className="font-bold text-lg text-gray-800">Chi tiết Kỳ Sát Hạch</h2>
                                <p className="text-xs text-gray-500">Đã lưu: {new Date(selectedSession.createdAt).toLocaleString('vi-VN')}</p>
                            </div>
                        </div>
                     </div>
                     <div className="flex-1 overflow-hidden relative z-0">
                         {isLoading ? (
                             <div className="flex h-full items-center justify-center">Loading full details...</div>
                         ) : (
                            <ReportDashboardPage 
                                summaryData={appData} 
                                studentRecords={studentRecords}
                                grandTotal={grandTotal} 
                                reportMetadata={reportMetadata}
                                mode="view"
                                initialReportDate={selectedSession.reportDate}
                                sessionName={selectedSession.name}
                                onUpdateSession={handleUpdateSession}
                                trainingUnits={trainingUnits} // Pass units
                            />
                         )}
                     </div>
                </div>
            );
        }

        // 5. Settings View
        if (currentView === 'settings') {
            return <SettingsPage />;
        }

        return null;
    };

    return (
         <div className="flex h-screen bg-gray-100 text-gray-800 font-sans overflow-hidden">
            {/* Sidebar Navigation */}
            <AdminSidebar currentView={currentView === 'detail' ? 'dashboard' : currentView} onChangeView={handleNavChange} />

            {/* Main Content Area */}
            <main className="flex-1 h-full relative flex flex-col min-w-0">
                {renderMainContent()}
            </main>

            {/* Global Toast */}
            {toast && (
                <Toast 
                    message={toast.message} 
                    type={toast.type} 
                    onClose={() => setToast(null)} 
                />
            )}
        </div>
    );
};

export default App;

const express = require('express');
const cors = require('cors');
const path = require('path');
const fs = require('fs');
const { Pool, Client } = require('pg');

const SERVER_VERSION = '3.5.0';
console.log(`\n\n==================================================`);
console.log(`🚀 STARTING SERVER v${SERVER_VERSION}`);
console.log(`==================================================\n`);

const app = express();
const port = process.env.PORT || 8080;

// Config file path
const CONFIG_FILE = path.join(__dirname, 'db-config.json');

// Global Pool Variable
let pool = null;

// --- 1. DATABASE CONFIGURATION & INITIALIZATION ---

const getDbConfig = () => {
    // 1. Try reading from local config file first (created via UI)
    if (fs.existsSync(CONFIG_FILE)) {
        try {
            const fileConfig = JSON.parse(fs.readFileSync(CONFIG_FILE, 'utf8'));
            console.log("📂 Loaded DB config from db-config.json");

            const config = {
                user: fileConfig.user,
                password: fileConfig.password,
                database: fileConfig.database,
                max: 10,
                idleTimeoutMillis: 30000,
                connectionTimeoutMillis: 10000,
            };

            if (fileConfig.useSocket && fileConfig.instanceConnectionName) {
                config.host = `/cloudsql/${fileConfig.instanceConnectionName}`;
            } else {
                config.host = fileConfig.host;
                config.port = fileConfig.port ? parseInt(fileConfig.port) : 5432;
                config.ssl = { rejectUnauthorized: false };
            }
            return config;
        } catch (e) {
            console.error("⚠️ Error reading db-config.json:", e);
        }
    }

    // 2. Fallback to Environment Variables
    console.log("🌎 Using Environment Variables for DB config");
    const config = {
        user: process.env.DB_USER || 'postgres',
        password: process.env.DB_PASSWORD || 'Appbaocao1!',
        database: process.env.DB_NAME || 'Appbaocao',
        max: 10,
        idleTimeoutMillis: 30000,
        connectionTimeoutMillis: 10000,
    };

    const INSTANCE_CONNECTION_NAME = process.env.INSTANCE_CONNECTION_NAME;

    if (process.env.NODE_ENV === 'production' && INSTANCE_CONNECTION_NAME) {
        config.host = `/cloudsql/${INSTANCE_CONNECTION_NAME}`;
    } else {
        config.host = process.env.DB_HOST || '35.198.214.82';
        config.port = 5432;
        config.ssl = { rejectUnauthorized: false };
    }

    return config;
};

const initPool = async () => {
    if (pool) {
        await pool.end();
        console.log("Old connection pool closed.");
    }

    const config = getDbConfig();
    console.log(`🔌 Connecting to DB at: ${config.host} (User: ${config.user})`);

    pool = new Pool(config);

    // Test connection
    pool.query('SELECT NOW()', (err, res) => {
        if (err) {
            console.error('❌ Database connection error:', err.message);
        } else {
            console.log('✅ Database connected successfully at:', res.rows[0].now);
            initSchema();
        }
    });
};

const initSchema = async () => {
    if (!pool) return;

    // Table: sessions
    const createSessionsTable = `
        CREATE TABLE IF NOT EXISTS sessions (
            id VARCHAR(255) PRIMARY KEY,
            data JSONB NOT NULL,
            report_date TIMESTAMPTZ,
            created_at BIGINT
        );
    `;

    // Table: training_units
    const createTrainingUnitsTable = `
        CREATE TABLE IF NOT EXISTS training_units (
            id VARCHAR(255) PRIMARY KEY,
            code VARCHAR(50) NOT NULL,
            name VARCHAR(255) NOT NULL,
            created_at BIGINT
        );
    `;

    try {
        await pool.query(createSessionsTable);
        await pool.query(createTrainingUnitsTable);
        console.log("✅ Tables 'sessions' and 'training_units' verified/created.");
    } catch (err) {
        console.error("❌ Error initializing database schema:", err);
    }
};

// Initialize DB on startup
initPool();

// --- 2. MIDDLEWARE ---
app.enable('trust proxy');
app.use(cors({ origin: '*' }));
app.use(express.json({ limit: '50mb' })); // Increased limit for large Excel data
app.use(express.urlencoded({ extended: true, limit: '50mb' }));

// Debug Middleware
app.use('/api', (req, res, next) => {
    console.log(`[API Request] ${req.method} ${req.originalUrl}`);
    next();
});

// --- 3. API ENDPOINTS ---

// === A. System & Config ===

app.get('/_ping', (req, res) => {
    res.status(200).json({ status: 'ok', message: 'pong', version: SERVER_VERSION });
});

app.get('/api/server-status', (req, res) => {
    res.json({
        success: true,
        version: SERVER_VERSION,
        mode: process.env.NODE_ENV || 'development'
    });
});

// Save DB Config and Reconnect
app.post('/api/save-db-config', async (req, res) => {
    try {
        const config = req.body;
        // Basic validation
        if (!config.user || !config.database) {
            return res.status(400).json({ success: false, error: "Missing required fields" });
        }

        // Write to file
        fs.writeFileSync(CONFIG_FILE, JSON.stringify(config, null, 2));

        // Re-initialize pool
        await initPool();

        res.json({ success: true, message: "Configuration saved and connection reloaded." });
    } catch (e) {
        console.error("Save config error:", e);
        res.status(500).json({ success: false, error: e.message });
    }
});

// Test Connection (Ephemeral)
app.post('/api/check-db-connection', async (req, res) => {
    const { user, password, database, host, port, instanceConnectionName, useSocket } = req.body;

    console.log("🛠️ Testing connection...", { user, database, host });

    const clientConfig = {
        user,
        password,
        database,
        connectionTimeoutMillis: 5000,
    };

    if (useSocket && instanceConnectionName) {
         clientConfig.host = `/cloudsql/${instanceConnectionName}`;
    } else {
        clientConfig.host = host;
        clientConfig.port = port ? parseInt(port) : 5432;
        clientConfig.ssl = { rejectUnauthorized: false };
    }

    const client = new Client(clientConfig);

    try {
        await client.connect();
        const result = await client.query('SELECT NOW() as now, version() as version');
        await client.end();

        res.status(200).json({ 
            success: true, 
            message: `Kết nối thành công!`, 
            details: {
                version: result.rows[0].version
            }
        });
    } catch (err) {
        console.error("❌ Test failed:", err.message);
        res.status(200).json({ success: false, error: err.message });
    }
});

// === B. Business Logic (Sessions) ===

app.get('/api/sessions', async (req, res) => {
    if (!pool) return res.status(503).json({ error: "Database not connected" });
    try {
        const result = await pool.query('SELECT data FROM sessions ORDER BY created_at DESC');
        const sessions = result.rows.map(row => row.data);
        res.json(sessions);
    } catch (err) {
        console.error("GET /api/sessions error:", err.message);
        res.status(500).json({ error: 'Database Error', details: err.message });
    }
});

app.get('/api/sessions/:id', async (req, res) => {
    if (!pool) return res.status(503).json({ error: "Database not connected" });
    const { id } = req.params;
    try {
        const result = await pool.query('SELECT data FROM sessions WHERE id = $1', [id]);
        if (result.rows.length === 0) {
            return res.status(404).json({ error: 'Session not found' });
        }
        res.json(result.rows[0].data);
    } catch (err) {
        console.error(`GET /api/sessions/${id} error:`, err.message);
        res.status(500).json({ error: 'Internal Server Error' });
    }
});

app.post('/api/sessions', async (req, res) => {
    if (!pool) return res.status(503).json({ error: "Database not connected" });
    const session = req.body;

    // Validate that we have the student records (Excel data)
    if (!session || !session.id) {
        return res.status(400).json({ error: 'Invalid session data' });
    }

    const query = `
        INSERT INTO sessions (id, data, report_date, created_at)
        VALUES ($1, $2, $3, $4)
        ON CONFLICT (id) 
        DO UPDATE SET 
            data = EXCLUDED.data,
            report_date = EXCLUDED.report_date;
    `;

    // session object contains 'studentRecords' which holds the parsing results
    const values = [session.id, JSON.stringify(session), session.reportDate, session.createdAt];

    try {
        await pool.query(query, values);
        console.log(`💾 Saved session ${session.id} (${session.studentRecords?.length || 0} students)`);
        res.status(200).json({ message: 'Saved successfully', id: session.id });
    } catch (err) {
        console.error("POST /api/sessions error:", err.message);
        res.status(500).json({ error: 'Failed to save session' });
    }
});

app.delete('/api/sessions/:id', async (req, res) => {
    if (!pool) return res.status(503).json({ error: "Database not connected" });
    const { id } = req.params;
    try {
        await pool.query('DELETE FROM sessions WHERE id = $1', [id]);
        res.status(200).json({ message: 'Deleted successfully' });
    } catch (err) {
        console.error(`DELETE /api/sessions/${id} error:`, err.message);
        res.status(500).json({ error: 'Failed to delete session' });
    }
});

// === C. Training Units (NEW) ===

app.get('/api/training-units', async (req, res) => {
    if (!pool) return res.status(503).json({ error: "Database not connected" });
    try {
        // Sort by code length descending so longer codes match first in logic, but standard sort for display? 
        // Let's sort by creation time or name.
        const result = await pool.query('SELECT * FROM training_units ORDER BY created_at ASC');
        res.json(result.rows);
    } catch (err) {
        console.error("GET /api/training-units error:", err.message);
        res.status(500).json({ error: 'Database Error' });
    }
});

app.post('/api/training-units', async (req, res) => {
    if (!pool) return res.status(503).json({ error: "Database not connected" });
    const unit = req.body;

    if (!unit.id || !unit.code || !unit.name) {
        return res.status(400).json({ error: 'Missing required fields' });
    }

    const query = `
        INSERT INTO training_units (id, code, name, created_at)
        VALUES ($1, $2, $3, $4)
        ON CONFLICT (id) 
        DO UPDATE SET 
            code = EXCLUDED.code,
            name = EXCLUDED.name;
    `;
    const createdAt = unit.created_at || Date.now();

    try {
        await pool.query(query, [unit.id, unit.code, unit.name, createdAt]);
        res.status(200).json({ message: 'Saved successfully', unit });
    } catch (err) {
        console.error("POST /api/training-units error:", err.message);
        res.status(500).json({ error: 'Failed to save unit' });
    }
});

app.post('/api/training-units/batch', async (req, res) => {
    if (!pool) return res.status(503).json({ error: "Database not connected" });
    const units = req.body;

    if (!Array.isArray(units)) {
        return res.status(400).json({ error: 'Expected array of units' });
    }

    const client = await pool.connect();
    try {
        await client.query('BEGIN');
        // Option 1: Replace All (Delete all and insert) - User friendly for full list update
        // Option 2: Upsert. 
        // Let's go with Upsert based on ID, but new Excel import creates new IDs.
        // If the user wants to "Import", usually they want to Add/Update.

        for (const unit of units) {
             const query = `
                INSERT INTO training_units (id, code, name, created_at)
                VALUES ($1, $2, $3, $4)
                ON CONFLICT (id) DO UPDATE SET code = EXCLUDED.code, name = EXCLUDED.name;
            `;
            // If ID is missing (fresh import logic from frontend), frontend should provide one
            await client.query(query, [unit.id, unit.code, unit.name, unit.created_at || Date.now()]);
        }

        await client.query('COMMIT');
        res.status(200).json({ message: `Imported ${units.length} units` });
    } catch (err) {
        await client.query('ROLLBACK');
        console.error("Batch import error:", err.message);
        res.status(500).json({ error: 'Failed to import units' });
    } finally {
        client.release();
    }
});

