                            accept=".xlsx, .xls"
                            onChange={handleUnitFileChange}
                            disabled={isLoading}
                            className="block w-full text-sm text-gray-500 file:mr-4 file:py-2.5 file:px-4 file:rounded-lg file:border-0 file:text-sm file:font-semibold file:bg-teal-600 file:text-white hover:file:bg-teal-700 cursor-pointer bg-white border border-gray-300 rounded-lg disabled:opacity-50" 
                        />
                    </div>
                    {unitUploadError && (
                        <div className="mt-3 text-sm text-red-600 bg-red-50 p-2 rounded border border-red-100 flex items-center gap-2">
                            <i className="fa-solid fa-circle-exclamation"></i>
                            {unitUploadError}
                        </div>
                    )}
                </div>

                {isLoading && (
                    <div className="p-4 text-center text-blue-600 bg-blue-50">
                        <i className="fa-solid fa-spinner animate-spin mr-2"></i> Đang xử lý...
                    </div>
                )}

                <div className="overflow-x-auto">
                    {trainingUnits.length === 0 ? (
                        <div className="p-12 text-center text-gray-500">
                            <i className="fa-solid fa-building-columns text-4xl mb-3 text-gray-300"></i>
                            <p>Chưa có dữ liệu đơn vị nào.</p>
                            <p className="text-sm mt-1">Vui lòng thêm mới hoặc tải file Excel lên.</p>
                        </div>
                    ) : (
                        <table className="w-full text-left text-sm text-gray-600">
                            <thead className="bg-gray-100 text-gray-700 uppercase font-semibold text-xs">
                                <tr>
                                    <th className="px-6 py-4 w-16 text-center">STT</th>
                                    <th className="px-6 py-4 w-48">Mã Đơn Vị</th>
                                    <th className="px-6 py-4">Tên Đơn Vị Đào Tạo</th>
                                    <th className="px-6 py-4 w-32 text-center">Hành động</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-100">
                                {trainingUnits.map((u, index) => (
                                    <tr key={u.id} className="hover:bg-blue-50 transition-colors group">
                                        <td className="px-6 py-4 text-center font-medium text-gray-400">{index + 1}</td>
                                        <td className="px-6 py-4 font-bold text-blue-700 bg-blue-50/30">{u.code}</td>
                                        <td className="px-6 py-4 font-medium text-gray-900">{u.name}</td>
                                        <td className="px-6 py-4 text-center">
                                            <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                                <button 
                                                    onClick={() => handleEditClick(u)}
                                                    className="w-8 h-8 flex items-center justify-center text-blue-600 bg-blue-100 rounded hover:bg-blue-200"
                                                    title="Sửa"
                                                >
                                                    <i className="fa-solid fa-pen"></i>
                                                </button>
                                                <button 
                                                    onClick={() => handleDeleteClick(u.id)}
                                                    className="w-8 h-8 flex items-center justify-center text-red-600 bg-red-100 rounded hover:bg-red-200"
                                                    title="Xóa"
                                                >
                                                    <i className="fa-solid fa-trash"></i>
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    )}
                </div>

                {trainingUnits.length > 0 && (
                    <div className="p-4 border-t border-gray-100 bg-gray-50 text-right text-xs text-gray-500">
                        Tổng số: <strong>{trainingUnits.length}</strong> đơn vị
                    </div>
                )}
            </div>

            {/* Modal Add/Edit */}
            {isModalOpen && (
                <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center p-4">
                    <div className="bg-white rounded-lg shadow-xl w-full max-w-md animate-fade-in-down">
                        <div className="p-4 border-b flex justify-between items-center">
                            <h3 className="font-bold text-lg text-gray-800">
                                {editingUnit ? 'Cập nhật Đơn vị' : 'Thêm Đơn vị mới'}
                            </h3>
                            <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600">
                                <i className="fa-solid fa-xmark text-xl"></i>
                            </button>
                        </div>
                        <form onSubmit={handleSubmit} className="p-6 space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Mã Đơn Vị (Prefix)</label>
                                <input 
                                    type="text" 
                                    required
                                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                                    placeholder="VD: 2721"
                                    value={formData.code}
                                    onChange={(e) => setFormData({...formData, code: e.target.value})}
                                />
                                <p className="text-xs text-gray-500 mt-1">Dùng để nhận diện học viên qua Mã HV.</p>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Tên Đơn Vị</label>
                                <input 
                                    type="text" 
                                    required
                                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                                    placeholder="VD: Trung tâm Đông Đô"
                                    value={formData.name}
                                    onChange={(e) => setFormData({...formData, name: e.target.value})}
                                />
                            </div>
                            <div className="flex justify-end gap-3 pt-4">
                                <button 
                                    type="button"
                                    onClick={() => setIsModalOpen(false)}
                                    className="px-4 py-2 bg-gray-100 text-gray-700 rounded-md hover:bg-gray-200"
                                >
                                    Hủy
                                </button>
                                <button 
                                    type="submit"
                                    disabled={isLoading}
                                    className="px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 disabled:opacity-50"
                                >
                                    {isLoading ? 'Đang lưu...' : 'Lưu'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

import type { SavedSession, TrainingUnit } from '../types';

const API_URL = '/api/sessions';
const UNIT_API_URL = '/api/training-units';
const SESSION_STORAGE_KEY = 'driving_test_sessions';
const UNIT_STORAGE_KEY = 'driving_test_units';

console.log("[Storage] v3.5.1 - Hybrid Mode (Cloud SQL -> LocalStorage)");

// Helper function: Try API first, fallback to LocalStorage if API fails
const tryApiOrFallback = async <T>(
    apiCall: () => Promise<T>, 
    fallbackCall: () => T | Promise<T>
): Promise<T> => {
    try {
        // Attempt API call
        return await apiCall();
    } catch (e) {
        console.warn("[Storage] API unavailable (using LocalStorage fallback):", e);
        return fallbackCall();
    }
};

export const storageService = {
    // --- SESSIONS ---
    getAllSessions: async (): Promise<SavedSession[]> => {
        return tryApiOrFallback(
            async () => {
                const response = await fetch(API_URL);
                if (!response.ok) throw new Error(`Status ${response.status}`);
                const contentType = response.headers.get("content-type");
                if (!contentType || !contentType.includes("application/json")) {
                     throw new Error("Invalid content type (likely HTML 404)");
                }
                return await response.json();
            },
            () => {
                try {
                    return JSON.parse(localStorage.getItem(SESSION_STORAGE_KEY) || '[]');
                } catch { return []; }
            }
        );
    },

    saveSession: async (session: SavedSession): Promise<void> => {
        return tryApiOrFallback(
            async () => {
                const response = await fetch(API_URL, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(session),
                });
                if (!response.ok) throw new Error(`Save failed: ${response.status}`);
            },
            () => {
                const sessions = JSON.parse(localStorage.getItem(SESSION_STORAGE_KEY) || '[]');
                const index = sessions.findIndex((s: SavedSession) => s.id === session.id);
                if (index >= 0) sessions[index] = session;
                else sessions.unshift(session);
                localStorage.setItem(SESSION_STORAGE_KEY, JSON.stringify(sessions));
            }
        );
    },

    deleteSession: async (id: string): Promise<void> => {
        return tryApiOrFallback(
            async () => {
                const response = await fetch(`${API_URL}/${id}`, { method: 'DELETE' });
                if (!response.ok) throw new Error('Delete failed');
            },
            () => {
                const sessions = JSON.parse(localStorage.getItem(SESSION_STORAGE_KEY) || '[]');
                const newSessions = sessions.filter((s: SavedSession) => s.id !== id);
                localStorage.setItem(SESSION_STORAGE_KEY, JSON.stringify(newSessions));
            }
        );
    },

    getSessionById: async (id: string): Promise<SavedSession | undefined> => {
        return tryApiOrFallback(
            async () => {
                const response = await fetch(`${API_URL}/${id}`);
                if (response.status === 404) return undefined;
                if (!response.ok) throw new Error('Network error');
                return await response.json();
            },
            () => {
                const sessions = JSON.parse(localStorage.getItem(SESSION_STORAGE_KEY) || '[]');
                return sessions.find((s: SavedSession) => s.id === id);
            }
        );
    },

    // --- TRAINING UNITS (NEW) ---

    getAllTrainingUnits: async (): Promise<TrainingUnit[]> => {
        return tryApiOrFallback(
            async () => {
                const response = await fetch(UNIT_API_URL);
                if (!response.ok) throw new Error(`Status ${response.status}`);
                return await response.json();
            },
            () => {
                try {
                    return JSON.parse(localStorage.getItem(UNIT_STORAGE_KEY) || '[]');
                } catch { return []; }
            }
        );
    },

    saveTrainingUnit: async (unit: TrainingUnit): Promise<void> => {
        return tryApiOrFallback(
            async () => {
                const response = await fetch(UNIT_API_URL, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(unit),
                });
                if (!response.ok) throw new Error(`Save unit failed: ${response.status}`);
            },
            () => {
                const units = JSON.parse(localStorage.getItem(UNIT_STORAGE_KEY) || '[]');
                const index = units.findIndex((u: TrainingUnit) => u.id === unit.id);
                if (index >= 0) units[index] = unit;
                else units.push(unit);
                localStorage.setItem(UNIT_STORAGE_KEY, JSON.stringify(units));
            }
        );
    },

    importTrainingUnits: async (units: TrainingUnit[]): Promise<void> => {
        return tryApiOrFallback(
            async () => {
                const response = await fetch(`${UNIT_API_URL}/batch`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(units),
                });
                if (!response.ok) throw new Error(`Batch import failed`);
            },
            () => {
                // For LocalStorage import, we'll append/update (upsert by ID)
                const existing = JSON.parse(localStorage.getItem(UNIT_STORAGE_KEY) || '[]');
                const map = new Map<string, TrainingUnit>();

                // Load existing
                existing.forEach((u: TrainingUnit) => map.set(u.id, u));
                // Overlay new
                units.forEach(u => map.set(u.id, u));

                const finalUnits = Array.from(map.values());
                localStorage.setItem(UNIT_STORAGE_KEY, JSON.stringify(finalUnits));
            }
        );
    },

    deleteTrainingUnit: async (id: string): Promise<void> => {
        return tryApiOrFallback(
            async () => {
                const response = await fetch(`${UNIT_API_URL}/${id}`, { method: 'DELETE' });
                if (!response.ok) throw new Error('Delete unit failed');
            },
            () => {
                const units = JSON.parse(localStorage.getItem(UNIT_STORAGE_KEY) || '[]');
                const newUnits = units.filter((u: TrainingUnit) => u.id !== id);
                localStorage.setItem(UNIT_STORAGE_KEY, JSON.stringify(newUnits));
            }
        );
    },

    // --- Data Migration/Sync Utils ---

    getLocalSessionCount: (): number => {
        try {
            const sessions = JSON.parse(localStorage.getItem(SESSION_STORAGE_KEY) || '[]');
            return Array.isArray(sessions) ? sessions.length : 0;
        } catch { return 0; }
    },

    syncLocalToCloud: async (): Promise<{ success: number; failed: number; total: number }> => {
        let sessions: SavedSession[] = [];
        try {
            sessions = JSON.parse(localStorage.getItem(SESSION_STORAGE_KEY) || '[]');
        } catch { return { success: 0, failed: 0, total: 0 }; }

        if (!Array.isArray(sessions) || sessions.length === 0) {
            return { success: 0, failed: 0, total: 0 };
        }

        let success = 0;
        let failed = 0;

        for (const session of sessions) {
            try {
                const response = await fetch(API_URL, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(session),
                });

                if (response.ok) {
                    success++;
                } else {
                    console.error(`Failed to sync session ${session.id}:`, response.statusText);
                    failed++;
                }
            } catch (e) {
                console.error(`Error syncing session ${session.id}:`, e);
                failed++;
            }
        }

        return { success, failed, total: sessions.length };
    }
};

const express = require('express');
const cors = require('cors');
const path = require('path');
const fs = require('fs');
const { Pool, Client } = require('pg');

const SERVER_VERSION = '3.5.2';
console.log(`\n\n==================================================`);
console.log(`🚀 STARTING SERVER v${SERVER_VERSION}`);
console.log(`==================================================\n`);

const app = express();
const port = process.env.PORT || 8080;

// Config file path
const CONFIG_FILE = path.join(__dirname, 'db-config.json');

// Global Variables
let pool = null;
let isDbConnected = false;

// --- 1. DATABASE CONFIGURATION & INITIALIZATION ---

const getDbConfig = () => {
    // 1. Try reading from local config file first (created via UI)
    if (fs.existsSync(CONFIG_FILE)) {
        try {
            const fileConfig = JSON.parse(fs.readFileSync(CONFIG_FILE, 'utf8'));
            console.log("📂 Loaded DB config from db-config.json");

            const config = {
                user: fileConfig.user,
                password: fileConfig.password,
                database: fileConfig.database,
                max: 10,
                idleTimeoutMillis: 30000,
                connectionTimeoutMillis: 20000, // Increased timeout to 20s
            };

            if (fileConfig.useSocket && fileConfig.instanceConnectionName) {
                config.host = `/cloudsql/${fileConfig.instanceConnectionName}`;
            } else {
                config.host = fileConfig.host;
                config.port = fileConfig.port ? parseInt(fileConfig.port) : 5432;
                config.ssl = { rejectUnauthorized: false };
            }
            return config;
        } catch (e) {
            console.error("⚠️ Error reading db-config.json:", e);
        }
    }

    // 2. Fallback to Environment Variables (Default Mode)
    console.log("🌎 Using Environment Variables/Defaults for DB config");
    const config = {
        user: process.env.DB_USER || 'postgres',
        password: process.env.DB_PASSWORD || 'Appbaocao1!',
        database: process.env.DB_NAME || 'Appbaocao',
        max: 10,
        idleTimeoutMillis: 30000,
        connectionTimeoutMillis: 20000, // Increased timeout to 20s
    };

    const INSTANCE_CONNECTION_NAME = process.env.INSTANCE_CONNECTION_NAME;

    if (process.env.NODE_ENV === 'production' && INSTANCE_CONNECTION_NAME) {
        config.host = `/cloudsql/${INSTANCE_CONNECTION_NAME}`;
    } else {
        config.host = process.env.DB_HOST || '35.198.214.82';
        config.port = 5432;
        config.ssl = { rejectUnauthorized: false };
    }

    return config;
};

const initPool = async () => {
    if (pool) {
        await pool.end();
        console.log("Old connection pool closed.");
    }

    const config = getDbConfig();
    console.log(`🔌 Connecting to DB at: ${config.host} (User: ${config.user})`);

    pool = new Pool(config);

    // Initial Connection Test
    pool.connect((err, client, release) => {
        if (err) {
            console.error('❌ Database connection FAILED:', err.message);
            isDbConnected = false;
        } else {
            client.query('SELECT NOW()', (err, res) => {
                release();
                if (err) {
                    console.error('❌ Database query error:', err.message);
                    isDbConnected = false;
                } else {
                    console.log('✅ Database connected successfully at:', res.rows[0].now);
                    isDbConnected = true;
                    initSchema();
                }
            });
        }
    });

    // Listen for pool errors
    pool.on('error', (err, client) => {
        console.error('❌ Unexpected error on idle client', err);
        isDbConnected = false;
    });
};

const initSchema = async () => {
    if (!pool) return;

    const createSessionsTable = `
        CREATE TABLE IF NOT EXISTS sessions (
            id VARCHAR(255) PRIMARY KEY,
            data JSONB NOT NULL,
            report_date TIMESTAMPTZ,
            created_at BIGINT
        );
    `;

    const createTrainingUnitsTable = `
        CREATE TABLE IF NOT EXISTS training_units (
            id VARCHAR(255) PRIMARY KEY,
            code VARCHAR(50) NOT NULL,
            name VARCHAR(255) NOT NULL,
            created_at BIGINT
        );
    `;

    try {
        await pool.query(createSessionsTable);
        await pool.query(createTrainingUnitsTable);
        console.log("✅ Tables 'sessions' and 'training_units' verified/created.");
    } catch (err) {
        console.error("❌ Error initializing database schema:", err);
    }
};

// Initialize DB on startup
