            <div className="flex border-b border-gray-200 mb-6 bg-white rounded-t-lg px-2 pt-2">
                <button
                    className={`py-3 px-6 font-medium text-sm focus:outline-none rounded-t-lg transition-colors ${activeTab === 'database' ? 'bg-blue-50 border-t-2 border-blue-500 text-blue-600 font-bold' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
                    onClick={() => setActiveTab('database')}
                >
                    <i className="fa-solid fa-database mr-2"></i> Cloud SQL
                </button>
                <button
                    className={`py-3 px-6 font-medium text-sm focus:outline-none rounded-t-lg transition-colors ${activeTab === 'data' ? 'bg-blue-50 border-t-2 border-blue-500 text-blue-600 font-bold' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
                    onClick={() => setActiveTab('data')}
                >
                    <i className="fa-solid fa-cloud-arrow-up mr-2"></i> Đồng bộ Dữ liệu
                </button>
                <button
                    className={`py-3 px-6 font-medium text-sm focus:outline-none rounded-t-lg transition-colors ${activeTab === 'general' ? 'bg-blue-50 border-t-2 border-blue-500 text-blue-600 font-bold' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
                    onClick={() => setActiveTab('general')}
                >
                    <i className="fa-solid fa-sliders mr-2"></i> Chung
                </button>
            </div>

            {/* Content */}
            <div className="bg-white rounded-b-xl rounded-tr-xl shadow-sm border border-gray-200 p-6 max-w-4xl min-h-[400px]">
                {activeTab === 'database' && (
                    <div className="space-y-6">
                        <div className="bg-blue-50 border border-blue-200 rounded-md p-4 text-sm text-blue-800">
                            <i className="fa-solid fa-circle-info mr-2"></i>
                            Nhập thông tin Cloud SQL của bạn. Nhấn <strong>"Lưu & Kết nối"</strong> để áp dụng cho toàn bộ hệ thống.
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

                            {/* Connection Type Selection */}
                            <div className="md:col-span-2">
                                <label className="flex items-center gap-2 cursor-pointer w-fit">
                                    <input 
                                        type="checkbox" 
                                        name="useSocket"
                                        checked={dbConfig.useSocket}
                                        onChange={handleChange}
                                        className="rounded border-gray-300 text-blue-600 shadow-sm focus:border-blue-300 focus:ring focus:ring-blue-200 focus:ring-opacity-50"
                                    />
                                    <span className="text-sm font-medium text-gray-700">Sử dụng Unix Socket (Dành cho Cloud Run nội bộ)</span>
                                </label>
                            </div>

                            {!dbConfig.useSocket ? (
                                <>
                                    <div className="md:col-span-1">
                                        <label className="block text-sm font-medium text-gray-700 mb-1">Host (Public IP)</label>
                                        <input
                                            type="text"
                                            name="host"
                                            value={dbConfig.host}
                                            onChange={handleChange}
                                            className="w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-blue-500 focus:border-blue-500"
                                            placeholder="35.198.xxx.xxx"
                                        />
                                    </div>
                                    <div className="md:col-span-1">
                                        <label className="block text-sm font-medium text-gray-700 mb-1">Port</label>
                                        <input
                                            type="text"
                                            name="port"
                                            value={dbConfig.port}
                                            onChange={handleChange}
                                            className="w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-blue-500 focus:border-blue-500"
                                            placeholder="5432"
                                        />
                                    </div>
                                </>
                            ) : (
                                <div className="md:col-span-2">
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Instance Connection Name</label>
                                    <input
                                        type="text"
                                        name="instanceConnectionName"
                                        value={dbConfig.instanceConnectionName}
                                        onChange={handleChange}
                                        className="w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-blue-500 focus:border-blue-500"
                                        placeholder="project:region:instance"
                                    />
                                </div>
                            )}

                            <div className="md:col-span-1">
                                <label className="block text-sm font-medium text-gray-700 mb-1">Database Name</label>
                                <input
                                    type="text"
                                    name="database"
                                    value={dbConfig.database}
                                    onChange={handleChange}
                                    className="w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-blue-500 focus:border-blue-500"
                                />
                            </div>
                            <div className="md:col-span-1">
                                <label className="block text-sm font-medium text-gray-700 mb-1">Username</label>
                                <input
                                    type="text"
                                    name="user"
                                    value={dbConfig.user}
                                    onChange={handleChange}
                                    className="w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-blue-500 focus:border-blue-500"
                                />
                            </div>
                            <div className="md:col-span-1">
                                <label className="block text-sm font-medium text-gray-700 mb-1">Password</label>
                                <input
                                    type="password"
                                    name="password"
                                    value={dbConfig.password}
                                    onChange={handleChange}
                                    className="w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-blue-500 focus:border-blue-500"
                                />
                            </div>
                        </div>

                        {/* Actions & Result */}
                        <div className="pt-6 border-t border-gray-100 flex items-center justify-between">
                             {/* Left: Status Message */}
                            <div className="flex-1 mr-4">
                                {status === 'success' && (
                                    <div className="text-green-600 flex items-center gap-2 text-sm font-semibold bg-green-50 p-2 rounded">
                                        <i className="fa-solid fa-circle-check"></i>
                                        {message}
                                    </div>
                                )}
                                {status === 'error' && (
                                    <div className="text-red-600 flex items-center gap-2 text-sm bg-red-50 p-2 rounded">
                                        <i className="fa-solid fa-triangle-exclamation"></i>
                                        {message}
                                    </div>
                                )}
                            </div>

                            {/* Right: Buttons */}
                            <div className="flex items-center gap-3">
                                <button
                                    onClick={handleTestConnection}
                                    disabled={status === 'loading'}
                                    className="px-4 py-2 rounded-md font-medium text-gray-700 bg-white border border-gray-300 hover:bg-gray-50 transition-colors disabled:opacity-50"
                                >
                                    Chỉ Test Kết nối
                                </button>
                                <button
                                    onClick={handleSaveAndConnect}
                                    disabled={status === 'loading'}
                                    className={`px-4 py-2 rounded-md font-bold text-white flex items-center gap-2 shadow-sm transition-colors ${
                                        status === 'loading' ? 'bg-blue-400 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700'
                                    }`}
                                >
                                    {status === 'loading' ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-plug"></i>}
                                    Lưu & Kết nối
                                </button>
                            </div>
                        </div>
                    </div>
                )}

                {activeTab === 'data' && (
                    <div className="space-y-6">
                         <div className="bg-amber-50 border border-amber-200 rounded-md p-4 text-sm text-amber-800">
                            <i className="fa-solid fa-triangle-exclamation mr-2"></i>
                            <strong>Chế độ Hybrid:</strong> Dữ liệu được lưu ưu tiên trên Cloud SQL. Nếu mất kết nối, dữ liệu sẽ được lưu tạm ở Trình duyệt (LocalStorage).
                            Sử dụng tính năng này để đẩy dữ liệu cũ từ Trình duyệt lên Cloud.
                        </div>

                        <div className="grid grid-cols-1 gap-6">
                            <div className="p-6 bg-gray-50 rounded-lg border border-gray-200 flex flex-col items-center justify-center text-center">
                                <div className="text-4xl font-bold text-gray-800 mb-2">{localCount}</div>
                                <div className="text-gray-600 font-medium">Kỳ sát hạch đang lưu trên Trình duyệt</div>
                                <div className="text-xs text-gray-400 mt-1">Các kỳ này có thể chưa có trên Cloud SQL</div>

                                <div className="mt-6 w-full max-w-xs">
                                    <button 
                                        onClick={handleSync}
                                        disabled={localCount === 0 || syncStatus === 'syncing' || !serverInfo?.dbConnected}
                                        className={`w-full py-3 px-4 rounded-lg font-bold text-white shadow-md flex items-center justify-center gap-2 transition-all ${
                                            localCount === 0 || !serverInfo?.dbConnected
                                                ? 'bg-gray-400 cursor-not-allowed' 
                                                : syncStatus === 'syncing' 
                                                    ? 'bg-blue-400 cursor-wait' 
                                                    : 'bg-blue-600 hover:bg-blue-700 hover:scale-[1.02]'
                                        }`}
                                    >
                                        {syncStatus === 'syncing' ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-cloud-arrow-up"></i>}
                                        {syncStatus === 'syncing' ? 'Đang đồng bộ...' : 'Đồng bộ ngay lên Cloud SQL'}
                                    </button>
                                </div>
                                {!serverInfo?.dbConnected && <p className="text-xs text-red-500 mt-2">Cần kết nối Cloud SQL để đồng bộ.</p>}
                            </div>

                             {syncStatus === 'completed' && syncResult && (
                                <div className={`p-4 rounded-lg border ${syncResult.failed === 0 ? 'bg-green-50 border-green-200 text-green-700' : 'bg-yellow-50 border-yellow-200 text-yellow-800'}`}>
                                    <h4 className="font-bold flex items-center gap-2">
                                        {syncResult.failed === 0 ? <i className="fa-solid fa-check-circle"></i> : <i className="fa-solid fa-circle-exclamation"></i>}
                                        Kết quả đồng bộ:
                                    </h4>
                                    <ul className="list-disc pl-6 mt-2 text-sm">
                                        <li>Thành công: <strong>{syncResult.success}</strong> kỳ sát hạch</li>
                                        {syncResult.failed > 0 && <li>Thất bại: <strong>{syncResult.failed}</strong> kỳ (Kiểm tra log server)</li>}
                                    </ul>
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {activeTab === 'general' && (
                    <div className="text-center py-10 text-gray-500">
                        <i className="fa-solid fa-sliders text-4xl mb-3 text-gray-300"></i>
                        <p>Chưa có thiết lập chung nào.</p>
                    </div>
                )}
            </div>
        </div>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import { DataInputPage } from './components/DataInputPage';
import { ReportDashboardPage } from './components/reports/ReportDashboardPage';
import { AdminSidebar } from './components/admin/AdminSidebar';
import { SessionList } from './components/admin/SessionList';
import { SettingsPage } from './components/admin/SettingsPage';
import { TrainingUnitManager } from './components/admin/TrainingUnitManager';
import { storageService } from './services/storageService';
import type { AppData, LicenseClassData, StudentRecord, ReportMetadata, SavedSession, TrainingUnit } from './types';
import { processExcelData } from './services/excelProcessor';
import { Toast } from './components/ui/Toast';

type AppView = 'dashboard' | 'create' | 'detail' | 'settings' | 'training-units';

const App: React.FC = () => {
    // Navigation State
    const [currentView, setCurrentView] = useState<AppView>('dashboard');

    // Data State
    const [savedSessions, setSavedSessions] = useState<SavedSession[]>([]);

    // Working State (New or Selected Session)
    const [appData, setAppData] = useState<AppData | null>(null);
    const [studentRecords, setStudentRecords] = useState<StudentRecord[] | null>(null);
    const [selectedSession, setSelectedSession] = useState<SavedSession | null>(null);
    const [trainingUnits, setTrainingUnits] = useState<TrainingUnit[]>([]);

    // UI State
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);
    const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info' } | null>(null);

    // Initial Metadata Template
    const [reportMetadata, setReportMetadata] = useState<ReportMetadata>({
        meetingTime: '18 giờ 00 phút',
        meetingLocation: 'Trung tâm dạy nghề và Sát hạch lái xe Đông Đô',
        organizer: 'Giám đốc Công an tỉnh',
        attendees: [
            { id: '1', name: 'Đồng chí: Trung tá Dương Kim Giang', role: 'Chức vụ: Phó Trưởng phòng, Chủ tịch Hội đồng' },
            { id: '2', name: 'Đồng chí: Trung tá Trần Duy Giang', role: 'Chức vụ: Đội trưởng, Phó Chủ tịch Hội đồng' },
            { id: '3', name: 'Ông: Vũ Tiến Tuế', role: 'Chức vụ: Giám đốc Trung tâm sát hạch, Ủy viên' },
            { id: '4', name: 'Đồng chí: Vương Mai Phương', role: 'Thư ký' },
        ],
        technicalErrorSBD: '02,153,369',
    });

    // Load sessions & units on mount
    const loadData = async () => {
        const sessions = await storageService.getAllSessions();
        const units = await storageService.getAllTrainingUnits();
        setSavedSessions(sessions);
        setTrainingUnits(units);
    };

    useEffect(() => {
        const init = async () => {
             // 1. Check Server Connection
             try {
                const res = await fetch('/api/server-status');
                if (res.ok) {
                    const data = await res.json();
                    if (data.dbConnected) {
                        showToast('Đã kết nối Cloud SQL thành công!', 'success');
                    } else {
                        showToast('Không thể kết nối Cloud SQL. Đang dùng chế độ Offline.', 'info');
                    }
                }
             } catch (e) {
                 showToast('Mất kết nối Server. Đang dùng chế độ Offline.', 'info');
             }

             // 2. Load Data
             await loadData();
        };
        init();
    }, []);

    const showToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
        setToast({ message, type });
    };

    const handleExcelSubmit = (records: StudentRecord[]) => {
        setIsLoading(true);
        setError(null);
        try {
            const processedData = processExcelData(records);
            setStudentRecords(records);
            setAppData(processedData);
            showToast('Xử lý dữ liệu thành công! Vui lòng kiểm tra và lưu báo cáo.', 'info');
        } catch (e) {
             setError(`Lỗi xử lý file Excel: ${(e as Error).message}`);
             showToast('Lỗi xử lý file Excel', 'error');
        } finally {
            setIsLoading(false);
        }
    };

    // Calculated Grand Total for the currently active data
    const grandTotal = useMemo<LicenseClassData | null>(() => {
        if (!appData) return null;

        const allRows = [...appData.firstTime.rows, ...appData.retake.rows];
        if (allRows.length === 0) return null;

        return allRows.reduce((acc, row) => {
            acc.totalApplications += row.totalApplications;
            acc.totalParticipants += row.totalParticipants;
            acc.theory.total += row.theory.total;
            acc.theory.pass += row.theory.pass;
            acc.theory.fail += row.theory.fail;
            acc.simulation.total += row.simulation.total;
            acc.simulation.pass += row.simulation.pass;
            acc.simulation.fail += row.simulation.fail;
            acc.practicalCourse.total += row.practicalCourse.total;
            acc.practicalCourse.pass += row.practicalCourse.pass;
            acc.practicalCourse.fail += row.practicalCourse.fail;
            acc.onRoad.total += row.onRoad.total;
            acc.onRoad.pass += row.onRoad.pass;
            acc.onRoad.fail += row.onRoad.fail;
            acc.finalPass += row.finalPass;
            return acc;
        }, {
            class: 'a+b',
            totalApplications: 0,
            totalParticipants: 0,
            theory: { total: 0, pass: 0, fail: 0 },
            simulation: { total: 0, pass: 0, fail: 0 },
            practicalCourse: { total: 0, pass: 0, fail: 0 },
            onRoad: { total: 0, pass: 0, fail: 0 },
            finalPass: 0,
        });
    }, [appData]);

    const handleClearData = () => {
        setAppData(null);
        setStudentRecords(null);
        setError(null);
        // trainingUnits are global config, do not clear them when clearing session data
    };

    const handleSaveSession = async (name: string, reportDate: Date) => {
        if (!appData || !grandTotal || !studentRecords) return;
        setIsLoading(true);

        try {
            const newSession: SavedSession = {
                id: Date.now().toString(),
                name: name,
                createdAt: Date.now(),
                reportDate: reportDate.toISOString(),
                studentRecords: studentRecords,
                appData: appData,
                grandTotal: grandTotal,
                reportMetadata: reportMetadata,
                trainingUnits: trainingUnits // Save units
            };

            await storageService.saveSession(newSession);
            await loadData(); // Refresh sessions

            // Reset and go to dashboard
            handleClearData();
            setCurrentView('dashboard');
            showToast('Đã lưu kỳ sát hạch thành công!', 'success');
        } catch (err) {
            showToast('Lỗi khi lưu dữ liệu!', 'error');
            console.error(err);
        } finally {
            setIsLoading(false);
        }
    };

    const handleUpdateSession = async (name: string, reportDate: Date, metadata: ReportMetadata) => {
        if (!selectedSession) return;
        setIsLoading(true);

        try {
            const updatedSession: SavedSession = {
                ...selectedSession,
                name: name,
                reportDate: reportDate.toISOString(),
                reportMetadata: metadata,
                // trainingUnits usually don't change in this edit mode, 
                // but if we added unit editing in view mode, we would update it here.
                // For now, keep existing.
                trainingUnits: selectedSession.trainingUnits || []
            };

            await storageService.saveSession(updatedSession);
            await loadData();

            // Update local selected session state so the view refreshes immediately
            setSelectedSession(updatedSession);
            setReportMetadata(metadata);

            showToast('Đã cập nhật kỳ sát hạch!', 'success');
        } catch (err) {
            showToast('Lỗi khi cập nhật dữ liệu!', 'error');
            console.error(err);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDeleteSession = async (id: string) => {
        try {
            await storageService.deleteSession(id);
            await loadData();
            if (selectedSession?.id === id) {
                setSelectedSession(null);
                setCurrentView('dashboard');
            }
            showToast('Đã xóa kỳ sát hạch.', 'info');
        } catch (err) {
            showToast('Lỗi khi xóa dữ liệu!', 'error');
        }
    };

    const handleSelectSession = async (session: SavedSession) => {
        setIsLoading(true);

        // In local mode, session usually has full data, but getSessionById ensures it
        let fullSession = session;
        if (!session.appData || !session.studentRecords) {
             const loaded = await storageService.getSessionById(session.id);
             if (loaded) fullSession = loaded;
        }

        setSelectedSession(fullSession);
        setAppData(fullSession.appData);
        setStudentRecords(fullSession.studentRecords);
        setReportMetadata(fullSession.reportMetadata);
        setTrainingUnits(fullSession.trainingUnits || []); // Load units
        setCurrentView('detail');
        setIsLoading(false);
    };

    const handleNavChange = (view: AppView) => {
        if (view === 'create') {
            handleClearData();
            setSelectedSession(null);
        }
        if (view === 'dashboard') {
            loadData();
        }
        setCurrentView(view);
    };

    const renderMainContent = () => {
        if (isLoading && !appData && currentView === 'dashboard') {
             return <div className="flex h-full items-center justify-center"><i className="fa-solid fa-spinner animate-spin text-4xl text-blue-500"></i></div>;
        }

        // 1. Dashboard View
        if (currentView === 'dashboard') {
            return (
                <SessionList 
                    sessions={savedSessions} 
                    onSelectSession={handleSelectSession} 
                    onDeleteSession={handleDeleteSession}
                    onCreateNew={() => handleNavChange('create')}
                    onRefresh={async () => { await loadData(); }}
                />
            );
        }

        // 2. Training Units Management
        if (currentView === 'training-units') {
            return (
                <TrainingUnitManager 
                    trainingUnits={trainingUnits}
                    onUnitsImport={(units) => {
                        setTrainingUnits(units);
                        showToast(`Cập nhật thành công ${units.length} đơn vị đào tạo!`, 'success');
                    }}
                />
            );
        }

        // 3. Create View (Input -> Preview)
        if (currentView === 'create') {
            // If we have calculated data, show Preview Report
            if (appData) {
                 return (
                    <div className="h-full bg-gray-200">
                         {/* Header helper for "Back to input" */}
                         <div className="bg-white border-b px-4 py-2 flex justify-between items-center print:hidden">
                            <h2 className="font-bold text-gray-700">Tạo kỳ sát hạch mới - Xem trước</h2>
                            <button 
                                onClick={handleClearData} 
                                className="text-sm text-red-600 hover:text-red-800"
                            >
                                <i className="fa-solid fa-arrow-left"></i> Quay lại nhập liệu
                            </button>
                         </div>
                         <div className="h-[calc(100%-45px)] overflow-hidden">
                            <ReportDashboardPage 
                                summaryData={appData} 
                                studentRecords={studentRecords}
                                grandTotal={grandTotal} 
                                reportMetadata={reportMetadata}
                                mode="preview"
                                onSaveSession={handleSaveSession}
                                trainingUnits={trainingUnits} // Pass units from global state
                            />
                         </div>
                    </div>
                );
            }

            // Else show Input Form
            return (
                <div className="h-full bg-gray-50 flex justify-center overflow-y-auto">
                    <div className="w-full max-w-5xl bg-white shadow-lg h-full flex flex-col">
                         <DataInputPage 
                            onExcelSubmit={handleExcelSubmit}
                            isLoading={isLoading}
                            error={error}
                            onClearData={handleClearData}
                            reportMetadata={reportMetadata}
                            onMetadataChange={setReportMetadata}
                        />
                    </div>
                </div>
            );
        }

        // 4. Detail View (View Only/Edit)
        if (currentView === 'detail' && selectedSession && appData) {
             return (
                 <div className="h-full bg-gray-200 flex flex-col">
                     <div className="bg-white border-b px-6 py-3 flex justify-between items-center print:hidden shadow-sm z-20">
                        <div className="flex items-center gap-3">
                            <button 
                                onClick={() => setCurrentView('dashboard')} 
                                className="w-8 h-8 rounded-full bg-gray-100 hover:bg-gray-200 flex items-center justify-center text-gray-600 transition-colors"
                            >
                                <i className="fa-solid fa-arrow-left"></i>
                            </button>
                            <div>
                                <h2 className="font-bold text-lg text-gray-800">Chi tiết Kỳ Sát Hạch</h2>
                                <p className="text-xs text-gray-500">Đã lưu: {new Date(selectedSession.createdAt).toLocaleString('vi-VN')}</p>
                            </div>
                        </div>
                     </div>
                     <div className="flex-1 overflow-hidden relative z-0">
                         {isLoading ? (
                             <div className="flex h-full items-center justify-center">Loading full details...</div>
                         ) : (
                            <ReportDashboardPage 
                                summaryData={appData} 
                                studentRecords={studentRecords}
                                grandTotal={grandTotal} 
                                reportMetadata={reportMetadata}
                                mode="view"
                                initialReportDate={selectedSession.reportDate}
                                sessionName={selectedSession.name}
                                onUpdateSession={handleUpdateSession}
                                trainingUnits={trainingUnits} // Pass units
                            />
                         )}
                     </div>
                </div>
            );
        }

        // 5. Settings View
        if (currentView === 'settings') {
            return <SettingsPage />;
        }

        return null;
    };

    return (
         <div className="flex h-screen bg-gray-100 text-gray-800 font-sans overflow-hidden">
            {/* Sidebar Navigation */}
            <AdminSidebar currentView={currentView === 'detail' ? 'dashboard' : currentView} onChangeView={handleNavChange} />

            {/* Main Content Area */}
            <main className="flex-1 h-full relative flex flex-col min-w-0">
                {renderMainContent()}
            </main>

            {/* Global Toast */}
            {toast && (
                <Toast 
                    message={toast.message} 
                    type={toast.type} 
                    onClose={() => setToast(null)} 
                />
            )}
        </div>
    );
};

