                        <th className={tableHeaderStyle}>Lý thuyết</th>
                        <th className={tableHeaderStyle}>Mô phỏng</th>
                        <th className={tableHeaderStyle}>Sa hình</th>
                        <th className={tableHeaderStyle}>Đường trường</th>
