    merges.push({ s: { r: R, c: 0 }, e: { r: R, c: 15 } });
    R++;

    // --- 2. MEETING MINUTES ---
    R += 2;
    const formattedDateForMeeting = `Ngày ${reportDate.getDate()} tháng ${reportDate.getMonth() + 1} năm ${reportDate.getFullYear()}`;
