        ws[`A${R + 1}`] = { v: `${index + 1}. ${attendee.name}`, s: s.attendee };
        ws[`E${R + 1}`] = { v: `- ${attendee.role}`, s: s.attendee };
        merges.push({ s: { r: R, c: 0 }, e: { r: R, c: 3 } });
        merges.push({ s: { r: R, c: 4 }, e: { r: R, c: 15 } });
        R++;
