            merges.push({ s: { r: R, c: 1 }, e: { r: R, c: 4 } });
        } else if(row[0] && row[0].v === 'Bằng Chữ:') {
            merges.push({ s: { r: R, c: 1 }, e: { r: R, c: 5 } });
        } else {
             merges.push({ s: { r: R, c: 1 }, e: { r: R, c: 2 } });
        }
        R++;
