// Function to export the main summary report
export const exportGeneralReportToExcel = (
    summaryData: AppData,
    grandTotal: LicenseClassData | null,
    reportDate: Date,
    reportMetadata: ReportMetadata
) => {
    if (!grandTotal) return;

    const wb = XLSX.utils.book_new();
