    let R = 0; // current row tracker

    const merges: any[] = [];

    // --- 1. HEADER ---
    ws['A1'] = { v: 'CÔNG AN TỈNH BẮC NINH', s: s.header };
    ws['J1'] = { v: 'CỘNG HÒA XÃ HỘI CHỦ NGHĨA VIỆT NAM', s: s.header };
