    const headers = ['STT', 'SBD', 'Họ và tên', 'Ngày sinh', 'Hạng', 'Đơn vị đào tạo', 'Lý thuyết', 'Mô phỏng', 'Sa hình', 'Đường trường', 'Kết quả chung'];
    headers.forEach((h, C) => { ws[XLSX.utils.encode_cell({ r: R, c: C })] = { v: h, s: s.tableHeader } });
