            { id: '1', name: 'Đồng chí: Trung tá Dương Kim Giang', role: 'Chức vụ: Phó Trưởng phòng, Chủ tịch Hội đồng' },
            { id: '2', name: 'Đồng chí: Trung tá Trần Duy Giang', role: 'Chức vụ: Đội trưởng, Phó Chủ tịch Hội đồng' },
            { id: '3', name: 'Ông: Vũ Tiến Tuế', role: 'Chức vụ: Giám đốc Trung tâm sát hạch, Ủy viên' },
            { id: '4', name: 'Đồng chí: Vương Mai Phương', role: 'Thư ký' },
        ],
        technicalErrorSBD: '02,153,369',
    });

    // Load sessions & units on mount
    const loadData = async () => {
        const sessions = await storageService.getAllSessions();
        const units = await storageService.getAllTrainingUnits();
        setSavedSessions(sessions);
        setTrainingUnits(units);
    };

    useEffect(() => {
        const init = async () => {
             // 1. Check Server Connection
             try {
                const res = await fetch('/api/server-status');
                if (res.ok) {
                    const data = await res.json();
                    if (data.dbConnected) {
                        showToast('Đã kết nối Cloud SQL thành công!', 'success');
                    } else {
                        showToast('Không thể kết nối Cloud SQL. Đang dùng chế độ Offline.', 'info');
                    }
                }
             } catch (e) {
                 showToast('Mất kết nối Server. Đang dùng chế độ Offline.', 'info');
             }

             // 2. Load Data
             await loadData();
        };
        init();
    }, []);

    const showToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
        setToast({ message, type });
    };

    const handleExcelSubmit = (records: StudentRecord[]) => {
        setIsLoading(true);
        setError(null);
        try {
            const processedData = processExcelData(records);
            setStudentRecords(records);
            setAppData(processedData);
            showToast('Xử lý dữ liệu thành công! Vui lòng kiểm tra và lưu báo cáo.', 'info');
        } catch (e) {
             setError(`Lỗi xử lý file Excel: ${(e as Error).message}`);
             showToast('Lỗi xử lý file Excel', 'error');
        } finally {
            setIsLoading(false);
        }
    };

    // Calculated Grand Total for the currently active data
    const grandTotal = useMemo<LicenseClassData | null>(() => {
        if (!appData) return null;

        const allRows = [...appData.firstTime.rows, ...appData.retake.rows];
        if (allRows.length === 0) return null;

        return allRows.reduce((acc, row) => {
            acc.totalApplications += row.totalApplications;
            acc.totalParticipants += row.totalParticipants;
            acc.theory.total += row.theory.total;
            acc.theory.pass += row.theory.pass;
            acc.theory.fail += row.theory.fail;
            acc.simulation.total += row.simulation.total;
            acc.simulation.pass += row.simulation.pass;
            acc.simulation.fail += row.simulation.fail;
            acc.practicalCourse.total += row.practicalCourse.total;
            acc.practicalCourse.pass += row.practicalCourse.pass;
            acc.practicalCourse.fail += row.practicalCourse.fail;
            acc.onRoad.total += row.onRoad.total;
            acc.onRoad.pass += row.onRoad.pass;
            acc.onRoad.fail += row.onRoad.fail;
            acc.finalPass += row.finalPass;
            return acc;
        }, {
            class: 'a+b',
            totalApplications: 0,
            totalParticipants: 0,
            theory: { total: 0, pass: 0, fail: 0 },
            simulation: { total: 0, pass: 0, fail: 0 },
            practicalCourse: { total: 0, pass: 0, fail: 0 },
            onRoad: { total: 0, pass: 0, fail: 0 },
            finalPass: 0,
        });
    }, [appData]);

    const handleClearData = () => {
        setAppData(null);
        setStudentRecords(null);
        setError(null);
        // trainingUnits are global config, do not clear them when clearing session data
    };

    const handleSaveSession = async (name: string, reportDate: Date) => {
        if (!appData || !grandTotal || !studentRecords) return;
        setIsLoading(true);

        try {
            const newSession: SavedSession = {
                id: Date.now().toString(),
                name: name,
                createdAt: Date.now(),
                reportDate: reportDate.toISOString(),
                studentRecords: studentRecords,
                appData: appData,
                grandTotal: grandTotal,
                reportMetadata: reportMetadata,
                trainingUnits: trainingUnits // Save units
            };

            await storageService.saveSession(newSession);
            await loadData(); // Refresh sessions

            // Reset and go to dashboard
            handleClearData();
            setCurrentView('dashboard');
            showToast('Đã lưu kỳ sát hạch thành công!', 'success');
        } catch (err) {
            showToast('Lỗi khi lưu dữ liệu!', 'error');
            console.error(err);
        } finally {
            setIsLoading(false);
        }
    };

    const handleUpdateSession = async (name: string, reportDate: Date, metadata: ReportMetadata) => {
        if (!selectedSession) return;
        setIsLoading(true);

        try {
            const updatedSession: SavedSession = {
                ...selectedSession,
                name: name,
                reportDate: reportDate.toISOString(),
                reportMetadata: metadata,
                // trainingUnits usually don't change in this edit mode, 
                // but if we added unit editing in view mode, we would update it here.
                // For now, keep existing.
                trainingUnits: selectedSession.trainingUnits || []
            };

            await storageService.saveSession(updatedSession);
            await loadData();

            // Update local selected session state so the view refreshes immediately
            setSelectedSession(updatedSession);
            setReportMetadata(metadata);

            showToast('Đã cập nhật kỳ sát hạch!', 'success');
        } catch (err) {
            showToast('Lỗi khi cập nhật dữ liệu!', 'error');
            console.error(err);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDeleteSession = async (id: string) => {
        try {
            await storageService.deleteSession(id);
            await loadData();
            if (selectedSession?.id === id) {
                setSelectedSession(null);
                setCurrentView('dashboard');
            }
            showToast('Đã xóa kỳ sát hạch.', 'info');
        } catch (err) {
            showToast('Lỗi khi xóa dữ liệu!', 'error');
        }
    };

    const handleSelectSession = async (session: SavedSession) => {
        setIsLoading(true);

        // In local mode, session usually has full data, but getSessionById ensures it
        let fullSession = session;
        if (!session.appData || !session.studentRecords) {
             const loaded = await storageService.getSessionById(session.id);
             if (loaded) fullSession = loaded;
        }

        setSelectedSession(fullSession);
        setAppData(fullSession.appData);
        setStudentRecords(fullSession.studentRecords);
        setReportMetadata(fullSession.reportMetadata);
        setTrainingUnits(fullSession.trainingUnits || []); // Load units
        setCurrentView('detail');
        setIsLoading(false);
    };

    const handleNavChange = (view: AppView) => {
        if (view === 'create') {
            handleClearData();
            setSelectedSession(null);
        }
        if (view === 'dashboard') {
            loadData();
        }
        setCurrentView(view);
    };

    const renderMainContent = () => {
        if (isLoading && !appData && currentView === 'dashboard') {
             return <div className="flex h-full items-center justify-center"><i className="fa-solid fa-spinner animate-spin text-4xl text-blue-500"></i></div>;
        }

        // 1. Dashboard View
        if (currentView === 'dashboard') {
            return (
                <SessionList 
                    sessions={savedSessions} 
                    onSelectSession={handleSelectSession} 
                    onDeleteSession={handleDeleteSession}
                    onCreateNew={() => handleNavChange('create')}
                    onRefresh={async () => { await loadData(); }}
                />
            );
        }

        // 2. Aggregate Report (NEW)
        if (currentView === 'aggregate-report') {
            return <AggregateReportPage />;
        }

        // 3. Student Lookup (NEW PHASE 3)
        if (currentView === 'student-lookup') {
            return <StudentLookupPage />;
        }

        // 4. Training Units Management
        if (currentView === 'training-units') {
            return (
                <TrainingUnitManager 
                    trainingUnits={trainingUnits}
                    onUnitsImport={(units) => {
                        setTrainingUnits(units);
                        showToast(`Cập nhật thành công ${units.length} đơn vị đào tạo!`, 'success');
                    }}
                />
            );
        }

        // 5. Create View (Input -> Preview)
        if (currentView === 'create') {
            // If we have calculated data, show Preview Report
            if (appData) {
                 return (
                    <div className="h-full bg-gray-200">
                         {/* Header helper for "Back to input" */}
                         <div className="bg-white border-b px-4 py-2 flex justify-between items-center print:hidden">
                            <h2 className="font-bold text-gray-700">Tạo kỳ sát hạch mới - Xem trước</h2>
                            <button 
                                onClick={handleClearData} 
                                className="text-sm text-red-600 hover:text-red-800"
                            >
                                <i className="fa-solid fa-arrow-left"></i> Quay lại nhập liệu
                            </button>
                         </div>
                         <div className="h-[calc(100%-45px)] overflow-hidden">
                            <ReportDashboardPage 
                                summaryData={appData} 
                                studentRecords={studentRecords}
                                grandTotal={grandTotal} 
                                reportMetadata={reportMetadata}
                                mode="preview"
                                onSaveSession={handleSaveSession}
                                trainingUnits={trainingUnits} // Pass units from global state
                            />
                         </div>
                    </div>
                );
            }

            // Else show Input Form
            return (
                <div className="h-full bg-gray-50 flex justify-center overflow-y-auto">
                    <div className="w-full max-w-5xl bg-white shadow-lg h-full flex flex-col">
                         <DataInputPage 
                            onExcelSubmit={handleExcelSubmit}
                            isLoading={isLoading}
                            error={error}
                            onClearData={handleClearData}
                            reportMetadata={reportMetadata}
                            onMetadataChange={setReportMetadata}
                        />
                    </div>
                </div>
            );
        }

        // 6. Detail View (View Only/Edit)
        if (currentView === 'detail' && selectedSession && appData) {
             return (
                 <div className="h-full bg-gray-200 flex flex-col">
                     <div className="bg-white border-b px-6 py-3 flex justify-between items-center print:hidden shadow-sm z-20">
                        <div className="flex items-center gap-3">
                            <button 
                                onClick={() => setCurrentView('dashboard')} 
                                className="w-8 h-8 rounded-full bg-gray-100 hover:bg-gray-200 flex items-center justify-center text-gray-600 transition-colors"
                            >
                                <i className="fa-solid fa-arrow-left"></i>
                            </button>
                            <div>
                                <h2 className="font-bold text-lg text-gray-800">Chi tiết Kỳ Sát Hạch</h2>
                                <p className="text-xs text-gray-500">Đã lưu: {new Date(selectedSession.createdAt).toLocaleString('vi-VN')}</p>
                            </div>
                        </div>
                     </div>
                     <div className="flex-1 overflow-hidden relative z-0">
                         {isLoading ? (
                             <div className="flex h-full items-center justify-center">Loading full details...</div>
                         ) : (
                            <ReportDashboardPage 
                                summaryData={appData} 
                                studentRecords={studentRecords}
                                grandTotal={grandTotal} 
                                reportMetadata={reportMetadata}
                                mode="view"
                                initialReportDate={selectedSession.reportDate}
                                sessionName={selectedSession.name}
                                onUpdateSession={handleUpdateSession}
                                trainingUnits={trainingUnits} // Pass units
                            />
                         )}
                     </div>
                </div>
            );
        }

        // 7. Settings View
        if (currentView === 'settings') {
            return <SettingsPage />;
        }

        return null;
    };

    return (
         <div className="flex h-screen bg-gray-100 text-gray-800 font-sans overflow-hidden">
            {/* Sidebar Navigation */}
            <AdminSidebar currentView={currentView === 'detail' ? 'dashboard' : currentView} onChangeView={handleNavChange} />

            {/* Main Content Area */}
            <main className="flex-1 h-full relative flex flex-col min-w-0">
                {renderMainContent()}
            </main>

            {/* Global Toast */}
            {toast && (
                <Toast 
                    message={toast.message} 
                    type={toast.type} 
                    onClose={() => setToast(null)} 
                />
            )}
        </div>
    );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { storageService } from '../../services/storageService';
import type { SavedSession } from '../../types';
import { exportAggregateReportToExcel } from '../../services/excelGenerator';
import { 
    BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
    PieChart, Pie, Cell
} from 'recharts';

type TimeFilter = 'month' | 'quarter' | 'year' | 'custom';

export const AggregateReportPage: React.FC = () => {
    const [sessions, setSessions] = useState<SavedSession[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    // Filter States
    const [filterType, setFilterType] = useState<TimeFilter>('month');
    const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());
    const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth() + 1);
    const [selectedQuarter, setSelectedQuarter] = useState(Math.ceil((new Date().getMonth() + 1) / 3));
    const [customStartDate, setCustomStartDate] = useState('');
    const [customEndDate, setCustomEndDate] = useState('');

    useEffect(() => {
        const loadData = async () => {
            setIsLoading(true);
            try {
                const data = await storageService.getAllSessions();
                setSessions(data);
            } catch (error) {
                console.error("Failed to load sessions", error);
            } finally {
                setIsLoading(false);
            }
        };
        loadData();
    }, []);

    const filteredData = useMemo(() => {
        let start: Date, end: Date;

        if (filterType === 'month') {
            start = new Date(selectedYear, selectedMonth - 1, 1);
            end = new Date(selectedYear, selectedMonth, 0, 23, 59, 59);
        } else if (filterType === 'quarter') {
            const startMonth = (selectedQuarter - 1) * 3;
            start = new Date(selectedYear, startMonth, 1);
            end = new Date(selectedYear, startMonth + 3, 0, 23, 59, 59);
        } else if (filterType === 'year') {
            start = new Date(selectedYear, 0, 1);
            end = new Date(selectedYear, 11, 31, 23, 59, 59);
        } else { // custom
            if (!customStartDate || !customEndDate) return [];
            start = new Date(customStartDate);
            start.setHours(0,0,0,0);
            end = new Date(customEndDate);
            end.setHours(23,59,59,999);
        }

        const filteredSessions = sessions.filter(s => {
            const sDate = new Date(s.reportDate);
            return sDate >= start && sDate <= end;
        });

        // Sort by date ascending
        return filteredSessions.sort((a, b) => new Date(a.reportDate).getTime() - new Date(b.reportDate).getTime());

    }, [sessions, filterType, selectedYear, selectedMonth, selectedQuarter, customStartDate, customEndDate]);

    const stats = useMemo(() => {
        return filteredData.reduce((acc, session) => {
            // Theory
            acc.theory.total += session.grandTotal.theory.total;
            acc.theory.pass += session.grandTotal.theory.pass;
            acc.theory.fail += session.grandTotal.theory.fail;

            // Simulation
            acc.simulation.total += session.grandTotal.simulation.total;
            acc.simulation.pass += session.grandTotal.simulation.pass;
            acc.simulation.fail += session.grandTotal.simulation.fail;

            // Practical
            acc.practical.total += session.grandTotal.practicalCourse.total;
            acc.practical.pass += session.grandTotal.practicalCourse.pass;
            acc.practical.fail += session.grandTotal.practicalCourse.fail;

            // Road
            acc.road.total += session.grandTotal.onRoad.total;
            acc.road.pass += session.grandTotal.onRoad.pass;
            acc.road.fail += session.grandTotal.onRoad.fail;

            // General
            acc.applications += session.grandTotal.totalApplications;
            acc.participants += session.grandTotal.totalParticipants;
            acc.finalPass += session.grandTotal.finalPass;

            return acc;
        }, { 
            theory: { total: 0, pass: 0, fail: 0 }, 
            simulation: { total: 0, pass: 0, fail: 0 }, 
            practical: { total: 0, pass: 0, fail: 0 }, 
            road: { total: 0, pass: 0, fail: 0 }, 
            applications: 0, 
            participants: 0,
            finalPass: 0 
        });
    }, [filteredData]);

    const chartData = useMemo(() => [
        { name: 'Lý Thuyết', pass: stats.theory.pass, fail: stats.theory.fail },
        { name: 'Mô Phỏng', pass: stats.simulation.pass, fail: stats.simulation.fail },
        { name: 'Sa Hình', pass: stats.practical.pass, fail: stats.practical.fail },
        { name: 'Đường Trường', pass: stats.road.pass, fail: stats.road.fail },
    ], [stats]);

    const pieData = useMemo(() => [
        { name: 'Đạt', value: stats.finalPass },
        { name: 'Trượt/Vắng', value: stats.applications - stats.finalPass },
    ], [stats]);

    const COLORS = ['#16a34a', '#dc2626']; // Green, Red

    const handleExport = () => {
        if (filteredData.length === 0) {
            alert('Không có dữ liệu để xuất!');
            return;
        }

        let title = '';
        if (filterType === 'month') title = `Tháng ${selectedMonth}/${selectedYear}`;
        else if (filterType === 'quarter') title = `Quý ${selectedQuarter}/${selectedYear}`;
        else if (filterType === 'year') title = `Năm ${selectedYear}`;
        else title = `Từ ${new Date(customStartDate).toLocaleDateString('vi-VN')} đến ${new Date(customEndDate).toLocaleDateString('vi-VN')}`;

        // Transform stats to simple totals structure for existing export function
        const simpleTotals = {
            theory: stats.theory.total,
            simulation: stats.simulation.total,
            practical: stats.practical.total,
            road: stats.road.total
        };

        exportAggregateReportToExcel(filteredData, simpleTotals, title);
    };

    return (
        <div className="p-6 md:p-10 h-full overflow-y-auto bg-gray-100">
            <div className="mb-8">
                <h2 className="text-2xl font-bold text-gray-800">Báo cáo Tổng hợp & Thống kê</h2>
                <p className="text-gray-500 mt-1">Phân tích dữ liệu sát hạch theo thời gian thực.</p>
            </div>

            {/* Filter Controls */}
            <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 mb-6">
                <div className="flex flex-col md:flex-row gap-6 items-end">

                    {/* Filter Type */}
                    <div>
                        <label className="block text-sm font-semibold text-gray-700 mb-2">Loại báo cáo</label>
                        <select 
                            value={filterType} 
                            onChange={(e) => setFilterType(e.target.value as TimeFilter)}
                            className="px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none w-40"
                        >
                            <option value="month">Theo Tháng</option>
                            <option value="quarter">Theo Quý</option>
                            <option value="year">Theo Năm</option>
                            <option value="custom">Tùy chỉnh</option>
                        </select>
                    </div>

                    {/* Dynamic Inputs */}
                    {filterType === 'month' && (
                        <>
                            <div>
                                <label className="block text-sm font-semibold text-gray-700 mb-2">Tháng</label>
                                <select value={selectedMonth} onChange={(e) => setSelectedMonth(Number(e.target.value))} className="px-3 py-2 border border-gray-300 rounded-lg w-24">
                                    {Array.from({length: 12}, (_, i) => i + 1).map(m => <option key={m} value={m}>{m}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className="block text-sm font-semibold text-gray-700 mb-2">Năm</label>
                                <input type="number" value={selectedYear} onChange={(e) => setSelectedYear(Number(e.target.value))} className="px-3 py-2 border border-gray-300 rounded-lg w-28" />
                            </div>
                        </>
                    )}

                    {filterType === 'quarter' && (
                        <>
                            <div>
                                <label className="block text-sm font-semibold text-gray-700 mb-2">Quý</label>
                                <select value={selectedQuarter} onChange={(e) => setSelectedQuarter(Number(e.target.value))} className="px-3 py-2 border border-gray-300 rounded-lg w-32">
                                    <option value={1}>Quý I</option>
                                    <option value={2}>Quý II</option>
                                    <option value={3}>Quý III</option>
                                    <option value={4}>Quý IV</option>
                                </select>
                            </div>
                            <div>
                                <label className="block text-sm font-semibold text-gray-700 mb-2">Năm</label>
                                <input type="number" value={selectedYear} onChange={(e) => setSelectedYear(Number(e.target.value))} className="px-3 py-2 border border-gray-300 rounded-lg w-28" />
                            </div>
                        </>
                    )}

                    {filterType === 'year' && (
                        <div>
                            <label className="block text-sm font-semibold text-gray-700 mb-2">Năm báo cáo</label>
                            <input type="number" value={selectedYear} onChange={(e) => setSelectedYear(Number(e.target.value))} className="px-3 py-2 border border-gray-300 rounded-lg w-32" />
                        </div>
                    )}

                    {filterType === 'custom' && (
                        <>
                            <div>
                                <label className="block text-sm font-semibold text-gray-700 mb-2">Từ ngày</label>
                                <input type="date" value={customStartDate} onChange={(e) => setCustomStartDate(e.target.value)} className="px-3 py-2 border border-gray-300 rounded-lg" />
                            </div>
                            <div>
                                <label className="block text-sm font-semibold text-gray-700 mb-2">Đến ngày</label>
                                <input type="date" value={customEndDate} onChange={(e) => setCustomEndDate(e.target.value)} className="px-3 py-2 border border-gray-300 rounded-lg" />
                            </div>
                        </>
                    )}

                    <div className="flex-1 text-right">
                        <button 
                            onClick={handleExport}
                            disabled={filteredData.length === 0}
                            className="px-5 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 shadow-sm font-medium flex items-center gap-2 ml-auto disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            <i className="fa-solid fa-file-excel"></i> Xuất Excel
                        </button>
                    </div>
                </div>
            </div>

            {/* CHARTS & STATS */}
            {filteredData.length > 0 && (
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-6">
                    {/* General Stats Cards (Column 1) */}
                    <div className="lg:col-span-3 grid grid-cols-2 md:grid-cols-5 gap-4">
                        <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm">
                            <div className="text-gray-500 text-xs font-bold uppercase tracking-wide">Số hồ sơ</div>
                            <div className="text-2xl font-bold text-gray-800 mt-1">{stats.applications.toLocaleString()}</div>
                        </div>
                        <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm border-l-4 border-l-blue-500">
                            <div className="text-gray-500 text-xs font-bold uppercase tracking-wide">Lượt Lý Thuyết</div>
                            <div className="text-2xl font-bold text-blue-600 mt-1">{stats.theory.total.toLocaleString()}</div>
                        </div>
                        <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm border-l-4 border-l-purple-500">
                            <div className="text-gray-500 text-xs font-bold uppercase tracking-wide">Lượt Mô Phỏng</div>
                            <div className="text-2xl font-bold text-purple-600 mt-1">{stats.simulation.total.toLocaleString()}</div>
                        </div>
                        <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm border-l-4 border-l-orange-500">
                            <div className="text-gray-500 text-xs font-bold uppercase tracking-wide">Lượt Sa Hình</div>
                            <div className="text-2xl font-bold text-orange-600 mt-1">{stats.practical.total.toLocaleString()}</div>
                        </div>
