                                    <input
                                        type="text"
                                        name="instanceConnectionName"
                                        value={dbConfig.instanceConnectionName}
                                        onChange={handleChange}
                                        className="w-full rounded-md border-gray-300 shadow-sm border p-3 focus:ring-blue-500 focus:border-blue-500 bg-blue-50/30"
                                        placeholder="project:region:instance"
