import React, { useState, useEffect } from 'react';
import { ExcelUploadSection } from './ExcelUploadSection';
import { StudentDataPreviewTable } from './StudentDataPreviewTable';
import type { StudentRecord, ReportMetadata, SavedSession } from '../types';
import { ReportMetadataModal } from './ReportMetadataModal';
import { storageService } from '../services/storageService';

interface DataInputPageProps {
    onExcelSubmit: (studentRecords: StudentRecord[]) => void;
    onClearData: () => void;
    isLoading: boolean;
    error: string | null;
    reportMetadata: ReportMetadata;
    onMetadataChange: (metadata: ReportMetadata) => void;
}

export const DataInputPage: React.FC<DataInputPageProps> = ({ 
    onExcelSubmit, 
    onClearData,
    isLoading: parentIsLoading, 
    error,
    reportMetadata,
    onMetadataChange
}) => {
    const [isMetadataModalOpen, setIsMetadataModalOpen] = useState(false);
    const [previewData, setPreviewData] = useState<StudentRecord[] | null>(null);
    const [isValidating, setIsValidating] = useState(false);

    // Core validation function
    const validateWithHistory = async (newRecords: StudentRecord[]) => {
        setIsValidating(true);
        try {
            // 1. Fetch all past sessions for history
            const pastSessions = await storageService.getAllSessions();

            // 2. Build a Map of passed subjects per student ID
            // Map<StudentId, Map<SubjectChar, {date: string, session: string}>>
            const passMap = new Map<string, Map<string, { date: string, session: string }>>();

            pastSessions.forEach(session => {
                const dateStr = new Date(session.reportDate).toLocaleDateString('vi-VN');
                session.studentRecords.forEach(record => {
                    const studentId = String(record['MÃ HỌC VIÊN']).trim();
                    if (!studentId) return;

                    if (!passMap.has(studentId)) {
                        passMap.set(studentId, new Map());
                    }
                    const studentPasses = passMap.get(studentId)!;

                    if (record['LÝ THUYẾT']?.toUpperCase().trim() === 'ĐẠT') studentPasses.set('L', { date: dateStr, session: session.name });
                    if (record['MÔ PHỎNG']?.toUpperCase().trim() === 'ĐẠT') studentPasses.set('M', { date: dateStr, session: session.name });
                    if (record['SA HÌNH']?.toUpperCase().trim() === 'ĐẠT') studentPasses.set('H', { date: dateStr, session: session.name });
                    if (record['ĐƯỜNG TRƯỜNG']?.toUpperCase().trim() === 'ĐẠT') studentPasses.set('D', { date: dateStr, session: session.name });
                });
            });

            // 3. Enrich new records with warnings
            const enrichedRecords = newRecords.map(record => {
                const studentId = String(record['MÃ HỌC VIÊN']).trim();
                const content = (record['NỘI DUNG THI'] || '').toUpperCase().replace(/Đ/g, 'D');
                const warnings: string[] = [];

                if (passMap.has(studentId)) {
                    const history = passMap.get(studentId)!;

                    if (content.includes('L') && history.has('L')) {
                        const h = history.get('L')!;
                        warnings.push(`Đã đạt Lý thuyết (${h.date})`);
                    }
                    if (content.includes('M') && history.has('M')) {
                        const h = history.get('M')!;
                        warnings.push(`Đã đạt Mô phỏng (${h.date})`);
                    }
                    if (content.includes('H') && history.has('H')) {
                        const h = history.get('H')!;
                        warnings.push(`Đã đạt Sa hình (${h.date})`);
                    }
                    if (content.includes('D') && history.has('D')) {
                        const h = history.get('D')!;
                        warnings.push(`Đã đạt Đường trường (${h.date})`);
                    }
                }

                return { ...record, _historyWarnings: warnings.length > 0 ? warnings : undefined };
            });

            setPreviewData(enrichedRecords);
        } catch (err) {
            console.error("Validation error:", err);
            setPreviewData(newRecords); // Fallback to raw if validation fails
        } finally {
            setIsValidating(false);
        }
    };

    const handleUpload = (data: StudentRecord[]) => {
        validateWithHistory(data);
    };

    const handleConfirm = () => {
        if (previewData) {
            onExcelSubmit(previewData);
            setPreviewData(null);
        }
    };

    const handleCancelPreview = () => {
        setPreviewData(null);
        onClearData();
    };

    return (
        <div className="flex flex-col h-full bg-white dark:bg-gray-800">
            <header className="p-4 border-b dark:border-gray-700 space-y-3">
                 <div className="flex justify-between items-start">
                    <div>
                         <h1 className="text-xl font-bold text-gray-800 dark:text-white">
                             {previewData ? 'Xác nhận Dữ liệu' : 'Bảng Điều Khiển'}
                         </h1>
                         <p className="mt-1 text-sm text-gray-600 dark:text-gray-400">
                             {previewData 
                                ? (isValidating ? 'Đang đối chiếu lịch sử sát hạch...' : 'Vui lòng kiểm tra kỹ nội dung thi và cảnh báo lịch sử.') 
                                : 'Nhập dữ liệu Excel học viên để tạo báo cáo.'}
                         </p>
                    </div>
                    <div className="flex items-center gap-2 flex-shrink-0">
                        <button
                            onClick={() => setIsMetadataModalOpen(true)}
                            className="px-4 py-2 bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-200 rounded-md hover:bg-gray-300 dark:hover:bg-gray-600 transition-colors flex items-center gap-2 font-semibold text-sm"
                        >
                            <i className="fa-solid fa-file-invoice"></i> Biên bản
                        </button>
                        {!previewData && (
                            <button
                                onClick={onClearData}
                                className="px-4 py-2 bg-green-600 text-white rounded-md hover:bg-green-700 transition-colors flex items-center gap-2 font-semibold text-sm"
                            >
                                <i className="fa-solid fa-rotate"></i> Làm mới
                            </button>
                        )}
                    </div>
                 </div>
            </header>
            <main className="flex-1 overflow-y-auto bg-gray-50 dark:bg-gray-900 p-6 space-y-6">

                {!previewData ? (
                    <div className="bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700 animate-fade-in">
                         <ExcelUploadSection onSubmit={handleUpload} isLoading={parentIsLoading || isValidating} error={error} />
                    </div>
                ) : (
                    <div className="relative">
                        {isValidating && (
                            <div className="absolute inset-0 bg-white/50 dark:bg-gray-900/50 z-30 flex items-center justify-center backdrop-blur-sm rounded-lg">
                                <div className="flex flex-col items-center gap-2">
                                    <i className="fa-solid fa-spinner animate-spin text-3xl text-blue-600"></i>
                                    <span className="font-bold text-gray-700 dark:text-gray-200">Đang đối soát lịch sử...</span>
                                </div>
                            </div>
                        )}
                        <StudentDataPreviewTable 
                            data={previewData} 
                            onConfirm={handleConfirm} 
                            onCancel={handleCancelPreview} 
                        />
                    </div>
                )}

            </main>
            {isMetadataModalOpen && (
                <ReportMetadataModal
                    initialMetadata={reportMetadata}
                    onSave={onMetadataChange}
                    onClose={() => setIsMetadataModalOpen(false)}
                />
            )}
        </div>
    );
};

import React, { useMemo } from 'react';
import type { StudentRecord } from '../types';
import { isStudentPassed, isStudentAbsent } from '../services/reportUtils';

interface StudentDataPreviewTableProps {
    data: StudentRecord[];
    onConfirm: () => void;
    onCancel: () => void;
}

export const StudentDataPreviewTable: React.FC<StudentDataPreviewTableProps> = ({ data, onConfirm, onCancel }) => {

    // Total warnings count
    const warningCount = useMemo(() => {
        return data.reduce((count, s) => count + (s._historyWarnings ? 1 : 0), 0);
    }, [data]);

    // Quick stats for preview
    const stats = useMemo(() => {
        let passed = 0;
        let failed = 0;
        let absent = 0;

        data.forEach(s => {
            if (isStudentAbsent(s)) absent++;
            else if (isStudentPassed(s)) passed++;
            else failed++;
        });

        return { total: data.length, passed, failed, absent };
    }, [data]);

    const getScoreClass = (score: string | undefined) => {
        const s = (score || '').toUpperCase().trim();
        if (s === 'ĐẠT') return 'text-green-600 font-bold bg-green-50';
        if (s === 'KHÔNG ĐẠT' || s === 'TRƯỢT') return 'text-red-600 font-bold bg-red-50';
        if (s === '' || s === 'VẮNG') return 'text-gray-400 bg-gray-50';
        return 'text-gray-700';
    };

    return (
        <div className="space-y-4 animate-fade-in-up">
            {/* Header / Stats */}
            <div className="bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700 p-4">
                <div className="flex flex-col md:flex-row justify-between items-center gap-4">
                    <div className="flex items-center gap-4">
                        <div>
                            <h2 className="text-lg font-bold text-gray-800 dark:text-white flex items-center gap-2">
                                <i className="fa-solid fa-table-list text-blue-600"></i>
                                Xem trước dữ liệu
                            </h2>
                            <p className="text-sm text-gray-500 dark:text-gray-400">Kiểm tra lại dữ liệu và các cảnh báo nội dung thi.</p>
                        </div>
                        {warningCount > 0 && (
                            <div className="bg-red-100 text-red-700 px-3 py-1.5 rounded-full border border-red-200 flex items-center gap-2 animate-bounce">
                                <i className="fa-solid fa-triangle-exclamation"></i>
                                <span className="font-bold text-sm">Phát hiện {warningCount} học viên sai nội dung thi!</span>
                            </div>
                        )}
                    </div>
                    <div className="flex gap-3 text-sm">
                        <div className="px-3 py-1 bg-blue-50 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 rounded-md border border-blue-100 dark:border-blue-800">
                            <strong>Tổng:</strong> {stats.total}
                        </div>
                        <div className="px-3 py-1 bg-green-50 dark:bg-green-900/30 text-green-700 dark:text-green-300 rounded-md border border-green-100 dark:border-green-800">
                            <strong>Đạt:</strong> {stats.passed}
                        </div>
                        <div className="px-3 py-1 bg-red-50 dark:bg-red-900/30 text-red-700 dark:text-red-300 rounded-md border border-red-100 dark:border-red-800">
                            <strong>Trượt:</strong> {stats.failed}
                        </div>
                    </div>
                </div>
            </div>

            {/* Scrollable Table */}
            <div className="bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700 overflow-hidden flex flex-col max-h-[600px]">
                <div className="overflow-auto flex-1">
                    <table className="w-full text-sm text-left text-gray-600 dark:text-gray-300 relative">
                        <thead className="text-xs text-gray-700 dark:text-gray-200 uppercase bg-gray-50 dark:bg-gray-700 sticky top-0 z-10 shadow-sm">
                            <tr>
                                <th className="px-4 py-3 text-center w-12">STT</th>
                                <th className="px-4 py-3">Mã Học Viên</th>
                                <th className="px-4 py-3">Họ và Tên</th>
                                <th className="px-4 py-3">Nội dung đăng ký</th>
                                <th className="px-4 py-3 text-center">Kết quả</th>
                                <th className="px-4 py-3">Cảnh báo / Lịch sử</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                            {data.map((row, index) => {
                                let status = 'TRƯỢT';
                                let statusClass = 'text-red-600 bg-red-50 dark:bg-red-900/20';
                                if (isStudentAbsent(row)) {
                                    status = 'VẮNG';
                                    statusClass = 'text-gray-500 bg-gray-100 dark:bg-gray-700/50';
                                } else if (isStudentPassed(row)) {
                                    status = 'ĐẠT';
                                    statusClass = 'text-green-700 bg-green-50 dark:bg-green-900/20';
                                }

                                const hasWarning = !!row._historyWarnings;

                                return (
                                    <tr key={index} className={`hover:bg-blue-50 dark:hover:bg-gray-700/50 transition-colors ${hasWarning ? 'bg-red-50/30 dark:bg-red-900/10' : ''}`}>
                                        <td className="px-4 py-3 text-center text-gray-400">{index + 1}</td>
                                        <td className="px-4 py-3 font-mono text-xs">{row['MÃ HỌC VIÊN']}</td>
                                        <td className="px-4 py-3">
                                            <div className="font-bold text-gray-800 dark:text-gray-100">{row['HỌ VÀ TÊN']}</div>
                                            <div className="text-[10px] text-gray-400">SBD: {row['SỐ BÁO DANH']} | Hạng: {row['HẠNG GPLX']}</div>
                                        </td>
                                        <td className="px-4 py-3">
                                            <span className="px-2 py-0.5 bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300 rounded font-bold text-xs border border-blue-200 dark:border-blue-800">
                                                {row['NỘI DUNG THI']}
                                            </span>
                                        </td>

                                        <td className="px-4 py-3 text-center">
                                            <span className={`px-2 py-1 rounded text-xs font-bold border ${statusClass} border-opacity-20`}>
                                                {status}
                                            </span>
                                        </td>

                                        <td className="px-4 py-3">
                                            {hasWarning ? (
                                                <div className="space-y-1">
                                                    {row._historyWarnings!.map((w, idx) => (
                                                        <div key={idx} className="flex items-center gap-1.5 text-red-600 dark:text-red-400 text-xs font-semibold">
                                                            <i className="fa-solid fa-circle-exclamation"></i>
                                                            <span>{w}</span>
                                                        </div>
                                                    ))}
                                                </div>
                                            ) : (
                                                <span className="text-green-500 text-xs flex items-center gap-1">
                                                    <i className="fa-solid fa-check"></i> Hợp lệ
                                                </span>
                                            )}
                                        </td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>

                {/* Actions Footer */}
                <div className="p-4 bg-gray-50 dark:bg-gray-900 border-t dark:border-gray-700 flex justify-between items-center sticky bottom-0 z-20">
                    <div className="text-sm">
                        {warningCount > 0 ? (
                            <span className="text-red-600 dark:text-red-400 font-bold">
                                <i className="fa-solid fa-triangle-exclamation mr-1"></i>
                                Lưu ý: Phát hiện trùng lặp lịch sử cho {warningCount} học viên. 
                            </span>
                        ) : (
                            <span className="text-green-600 dark:text-green-400 font-bold">
                                <i className="fa-solid fa-circle-check mr-1"></i>
                                Tất cả dữ liệu hợp lệ với lịch sử.
                            </span>
                        )}
                    </div>
                    <div className="flex gap-3">
                        <button 
                            onClick={onCancel}
                            className="px-5 py-2.5 bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-300 border border-gray-300 dark:border-gray-600 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 font-medium transition-colors shadow-sm"
                        >
                            <i className="fa-solid fa-arrow-rotate-left mr-2"></i> Nhập lại file
                        </button>
                        <button 
                            onClick={onConfirm}
                            className="px-6 py-2.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700 font-bold shadow-md transition-all hover:scale-105"
                        >
                            <i className="fa-solid fa-check mr-2"></i> Tiếp tục tạo Báo cáo
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { ExcelUploadSection } from './ExcelUploadSection';
import { StudentDataPreviewTable } from './StudentDataPreviewTable';
import type { StudentRecord, ReportMetadata, SavedSession } from '../types';
import { ReportMetadataModal } from './ReportMetadataModal';
import { storageService } from '../services/storageService';

interface PassDetail {
    date: string;
    session: string;
    isImplicit: boolean; // True if assumed passed because it was missing in first registration
}

interface DataInputPageProps {
    onExcelSubmit: (studentRecords: StudentRecord[]) => void;
    onClearData: () => void;
    isLoading: boolean;
    error: string | null;
    reportMetadata: ReportMetadata;
    onMetadataChange: (metadata: ReportMetadata) => void;
}

export const DataInputPage: React.FC<DataInputPageProps> = ({ 
    onExcelSubmit, 
    onClearData,
    isLoading: parentIsLoading, 
    error,
    reportMetadata,
    onMetadataChange
}) => {
    const [isMetadataModalOpen, setIsMetadataModalOpen] = useState(false);
    const [previewData, setPreviewData] = useState<StudentRecord[] | null>(null);
    const [isValidating, setIsValidating] = useState(false);

    const validateWithHistory = async (newRecords: StudentRecord[]) => {
        setIsValidating(true);
        try {
            const pastSessions = await storageService.getAllSessions();

            // Map<StudentId, Map<SubjectCode, PassDetail>>
            const passMap = new Map<string, Map<string, PassDetail>>();

            // 1. Group records by student and sort sessions by date to find the "First Appearance"
            const studentHistory = new Map<string, { record: StudentRecord, sessionName: string, date: Date }[]>();

            pastSessions.forEach(session => {
                const date = new Date(session.reportDate);
                session.studentRecords.forEach(record => {
                    const studentId = String(record['MÃ HỌC VIÊN']).trim();
                    if (!studentId) return;
                    if (!studentHistory.has(studentId)) studentHistory.set(studentId, []);
                    studentHistory.get(studentId)!.push({ record, sessionName: session.name, date });
                });
            });

            // 2. Process each student's history chronologically
            studentHistory.forEach((history, studentId) => {
                // Sort by date ascending
                history.sort((a, b) => a.date.getTime() - b.date.getTime());

                const studentPasses = new Map<string, PassDetail>();
                const firstEntry = history[0];
                const firstContent = (firstEntry.record['NỘI DUNG THI'] || '').toUpperCase().replace(/Đ/g, 'D');
                const firstDateStr = firstEntry.date.toLocaleDateString('vi-VN');

                // A. Implicit Pass Logic: 
                // In the first appearance, any subject NOT in NỘI DUNG THI is assumed "Already Passed"
                const allSubjectCodes = ['L', 'M', 'H', 'D'];
                allSubjectCodes.forEach(code => {
                    if (!firstContent.includes(code)) {
                        studentPasses.set(code, { 
                            date: firstDateStr, 
                            session: firstEntry.sessionName, 
                            isImplicit: true 
                        });
                    }
                });

                // B. Explicit Pass Logic:
                // Scan all history (including the first one) for 'ĐẠT' scores
                history.forEach(h => {
                    const dStr = h.date.toLocaleDateString('vi-VN');
                    if (h.record['LÝ THUYẾT']?.toUpperCase().trim() === 'ĐẠT') 
                        studentPasses.set('L', { date: dStr, session: h.sessionName, isImplicit: false });
                    if (h.record['MÔ PHỎNG']?.toUpperCase().trim() === 'ĐẠT') 
                        studentPasses.set('M', { date: dStr, session: h.sessionName, isImplicit: false });
                    if (h.record['SA HÌNH']?.toUpperCase().trim() === 'ĐẠT') 
                        studentPasses.set('H', { date: dStr, session: h.sessionName, isImplicit: false });
                    if (h.record['ĐƯỜNG TRƯỜNG']?.toUpperCase().trim() === 'ĐẠT') 
                        studentPasses.set('D', { date: dStr, session: h.sessionName, isImplicit: false });
                });

                passMap.set(studentId, studentPasses);
            });

            // 3. Enrich new records with warnings based on the passMap
            const subjectLabels: Record<string, string> = { 'L': 'Lý thuyết', 'M': 'Mô phỏng', 'H': 'Sa hình', 'D': 'Đường trường' };

            const enrichedRecords = newRecords.map(record => {
                const studentId = String(record['MÃ HỌC VIÊN']).trim();
                const content = (record['NỘI DUNG THI'] || '').toUpperCase().replace(/Đ/g, 'D');
                const warnings: string[] = [];

                if (passMap.has(studentId)) {
                    const history = passMap.get(studentId)!;

                    ['L', 'M', 'H', 'D'].forEach(code => {
                        if (content.includes(code) && history.has(code)) {
                            const h = history.get(code)!;
                            const label = subjectLabels[code];
                            if (h.isImplicit) {
                                warnings.push(`Sai nội dung: Mặc định đạt ${label} từ kỳ đầu (${h.date})`);
                            } else {
                                warnings.push(`Sai nội dung: Đã đạt ${label} tại kỳ (${h.session} - ${h.date})`);
                            }
                        }
                    });
                }

                return { ...record, _historyWarnings: warnings.length > 0 ? warnings : undefined };
            });

            setPreviewData(enrichedRecords);
        } catch (err) {
            console.error("Validation error:", err);
            setPreviewData(newRecords);
        } finally {
            setIsValidating(false);
        }
    };

    const handleUpload = (data: StudentRecord[]) => {
        validateWithHistory(data);
    };

    const handleConfirm = () => {
        if (previewData) {
            onExcelSubmit(previewData);
            setPreviewData(null);
        }
    };

    const handleCancelPreview = () => {
        setPreviewData(null);
        onClearData();
    };

    return (
        <div className="flex flex-col h-full bg-white dark:bg-gray-800">
            <header className="p-4 border-b dark:border-gray-700 space-y-3">
                 <div className="flex justify-between items-start">
                    <div>
                         <h1 className="text-xl font-bold text-gray-800 dark:text-white">
                             {previewData ? 'Xác nhận Dữ liệu' : 'Bảng Điều Khiển'}
                         </h1>
                         <p className="mt-1 text-sm text-gray-600 dark:text-gray-400">
                             {previewData 
                                ? (isValidating ? 'Đang đối chiếu lịch sử sát hạch...' : 'Vui lòng kiểm tra kỹ nội dung thi và cảnh báo lịch sử.') 
                                : 'Nhập dữ liệu Excel học viên để tạo báo cáo.'}
                         </p>
                    </div>
                    <div className="flex items-center gap-2 flex-shrink-0">
                        <button
                            onClick={() => setIsMetadataModalOpen(true)}
                            className="px-4 py-2 bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-200 rounded-md hover:bg-gray-300 dark:hover:bg-gray-600 transition-colors flex items-center gap-2 font-semibold text-sm"
                        >
                            <i className="fa-solid fa-file-invoice"></i> Biên bản
                        </button>
                        {!previewData && (
                            <button
                                onClick={onClearData}
                                className="px-4 py-2 bg-green-600 text-white rounded-md hover:bg-green-700 transition-colors flex items-center gap-2 font-semibold text-sm"
                            >
                                <i className="fa-solid fa-rotate"></i> Làm mới
                            </button>
                        )}
                    </div>
                 </div>
            </header>
            <main className="flex-1 overflow-y-auto bg-gray-50 dark:bg-gray-900 p-6 space-y-6">

                {!previewData ? (
                    <div className="bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700 animate-fade-in">
                         <ExcelUploadSection onSubmit={handleUpload} isLoading={parentIsLoading || isValidating} error={error} />
                    </div>
                ) : (
                    <div className="relative">
                        {isValidating && (
                            <div className="absolute inset-0 bg-white/50 dark:bg-gray-900/50 z-30 flex items-center justify-center backdrop-blur-sm rounded-lg">
                                <div className="flex flex-col items-center gap-2">
                                    <i className="fa-solid fa-spinner animate-spin text-3xl text-blue-600"></i>
                                    <span className="font-bold text-gray-700 dark:text-gray-200">Đang đối soát lịch sử...</span>
                                </div>
                            </div>
                        )}
                        <StudentDataPreviewTable 
                            data={previewData} 
                            onConfirm={handleConfirm} 
                            onCancel={handleCancelPreview} 
                        />
                    </div>
                )}

            </main>
            {isMetadataModalOpen && (
                <ReportMetadataModal
                    initialMetadata={reportMetadata}
                    onSave={onMetadataChange}
                    onClose={() => setIsMetadataModalOpen(false)}
                />
            )}
        </div>
    );
};

import React, { useState, useMemo } from 'react';
import type { StudentRecord, TrainingUnit, SavedSession } from '../../types';
import { storageService } from '../../services/storageService';
import { exportValidationResultsToExcel } from '../../services/excelGenerator';

declare const XLSX: any;

interface ValidationResult extends StudentRecord {
    _status: 'valid' | 'invalid';
    _messages: string[];
}

interface PassDetail {
    date: string;
    session: string;
    isImplicit: boolean;
}

export const ContentValidationPage: React.FC = () => {
    const [isLoading, setIsLoading] = useState(false);
    const [results, setResults] = useState<ValidationResult[]>([]);
    const [error, setError] = useState<string | null>(null);

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            setIsLoading(true);
            setError(null);
            const file = e.target.files[0];
            const reader = new FileReader();

            reader.onload = async (event) => {
                try {
                    const data = new Uint8Array(event.target!.result as ArrayBuffer);
                    const workbook = XLSX.read(data, { type: 'array' });
                    const sheetName = workbook.SheetNames[0];
                    const worksheet = workbook.Sheets[sheetName];
                    const json: any[] = XLSX.utils.sheet_to_json(worksheet);

                    if (json.length === 0) {
                        setError("File Excel không có dữ liệu.");
                        setIsLoading(false);
                        return;
                    }

                    await performValidation(json);
                } catch (err) {
                    setError("Lỗi xử lý file Excel.");
                    setIsLoading(false);
                }
            };
            reader.readAsArrayBuffer(file);
        }
    };

    const performValidation = async (incomingData: any[]) => {
        try {
            const pastSessions = await storageService.getAllSessions();

            // 1. Build Pass Map (Same logic as DataInputPage)
            const passMap = new Map<string, Map<string, PassDetail>>();
            const studentHistory = new Map<string, { record: StudentRecord, sessionName: string, date: Date }[]>();

            pastSessions.forEach(session => {
                const date = new Date(session.reportDate);
                session.studentRecords.forEach(record => {
                    const studentId = String(record['MÃ HỌC VIÊN']).trim();
                    if (!studentId) return;
                    if (!studentHistory.has(studentId)) studentHistory.set(studentId, []);
                    studentHistory.get(studentId)!.push({ record, sessionName: session.name, date });
                });
            });

            studentHistory.forEach((history, studentId) => {
                history.sort((a, b) => a.date.getTime() - b.date.getTime());
                const studentPasses = new Map<string, PassDetail>();
                const firstEntry = history[0];
                const firstContent = (firstEntry.record['NỘI DUNG THI'] || '').toUpperCase().replace(/Đ/g, 'D');
                const firstDateStr = firstEntry.date.toLocaleDateString('vi-VN');

                ['L', 'M', 'H', 'D'].forEach(code => {
                    if (!firstContent.includes(code)) {
                        studentPasses.set(code, { date: firstDateStr, session: firstEntry.sessionName, isImplicit: true });
                    }
                });

                history.forEach(h => {
                    const dStr = h.date.toLocaleDateString('vi-VN');
                    if (String(h.record['LÝ THUYẾT']).trim().toUpperCase() === 'ĐẠT') studentPasses.set('L', { date: dStr, session: h.sessionName, isImplicit: false });
                    if (String(h.record['MÔ PHỎNG']).trim().toUpperCase() === 'ĐẠT') studentPasses.set('M', { date: dStr, session: h.sessionName, isImplicit: false });
                    if (String(h.record['SA HÌNH']).trim().toUpperCase() === 'ĐẠT') studentPasses.set('H', { date: dStr, session: h.sessionName, isImplicit: false });
                    if (String(h.record['ĐƯỜNG TRƯỜNG']).trim().toUpperCase() === 'ĐẠT') studentPasses.set('D', { date: dStr, session: h.sessionName, isImplicit: false });
                });
                passMap.set(studentId, studentPasses);
            });

            // 2. Validate Incoming Data
            const subjectLabels: Record<string, string> = { 'L': 'Lý thuyết', 'M': 'Mô phỏng', 'H': 'Sa hình', 'D': 'Đường trường' };
            const validated: ValidationResult[] = incomingData.map(row => {
                const studentId = String(row['MÃ HỌC VIÊN'] || '').trim();
                const content = String(row['NỘI DUNG THI'] || '').toUpperCase().replace(/Đ/g, 'D');
                const messages: string[] = [];

                if (studentId && passMap.has(studentId)) {
                    const history = passMap.get(studentId)!;
                    ['L', 'M', 'H', 'D'].forEach(code => {
                        if (content.includes(code) && history.has(code)) {
                            const h = history.get(code)!;
                            if (h.isImplicit) {
                                messages.push(`Mặc định đạt ${subjectLabels[code]} (${h.date})`);
                            } else {
                                messages.push(`Đã đạt ${subjectLabels[code]} (${h.date})`);
                            }
                        }
                    });
                }

                return {
                    ...row,
                    _status: messages.length > 0 ? 'invalid' : 'valid',
                    _messages: messages
                };
            });

            setResults(validated);
        } catch (err) {
            console.error(err);
            setError("Lỗi khi đối soát dữ liệu.");
        } finally {
            setIsLoading(false);
        }
    };

    const handleExport = () => {
        if (results.length === 0) return;
        exportValidationResultsToExcel(results);
    };

    const handleClear = () => {
        setResults([]);
        setError(null);
    };

    return (
        <div className="p-6 md:p-8 h-full overflow-y-auto bg-gray-50 dark:bg-gray-900">
            <div className="mb-6 flex justify-between items-center">
                <div>
                    <h2 className="text-2xl font-bold text-gray-800 dark:text-white">Kiểm tra Nội dung thi</h2>
                    <p className="text-gray-500 dark:text-gray-400 mt-1 text-sm">Đối soát nội dung thi của học viên với lịch sử sát hạch.</p>
                </div>
                {results.length > 0 && (
                    <div className="flex gap-2">
                         <button 
                            onClick={handleClear}
                            className="px-4 py-2 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-600 dark:text-gray-300 rounded-lg hover:bg-gray-50 text-sm font-medium"
                        >
                            <i className="fa-solid fa-trash-can mr-2"></i> Xóa kết quả
                        </button>
                        <button 
                            onClick={handleExport}
                            className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 shadow-sm text-sm font-bold flex items-center gap-2"
                        >
                            <i className="fa-solid fa-file-excel"></i> Xuất file kết quả
                        </button>
                    </div>
                )}
            </div>

            {results.length === 0 ? (
                <div className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 p-12 text-center">
                    <div className="w-20 h-20 bg-blue-50 dark:bg-blue-900/30 rounded-full flex items-center justify-center mx-auto mb-6">
                        <i className="fa-solid fa-file-shield text-4xl text-blue-500"></i>
                    </div>
                    <h3 className="text-lg font-bold text-gray-800 dark:text-white mb-2">Tải file Excel để kiểm tra</h3>
                    <p className="text-gray-500 dark:text-gray-400 max-w-md mx-auto mb-8">
                        Cấu trúc file: SBD, MÃ HỌC VIÊN, HỌ VÀ TÊN, SỐ CHỨNG MINH, NGÀY SINH, NƠI CƯ TRÚ, HẠNG, NỘI DUNG THI.
                    </p>

                    <div className="max-w-xs mx-auto">
                        <label className={`block w-full py-4 px-6 border-2 border-dashed rounded-xl cursor-pointer transition-all ${isLoading ? 'border-gray-300 bg-gray-50 pointer-events-none' : 'border-blue-300 bg-blue-50 hover:bg-blue-100 dark:bg-blue-900/10 dark:hover:bg-blue-900/20'}`}>
                            {isLoading ? (
                                <div className="flex items-center justify-center gap-2 text-gray-500">
                                    <i className="fa-solid fa-spinner animate-spin"></i>
                                    <span className="font-bold">Đang đối soát...</span>
                                </div>
                            ) : (
                                <div className="flex flex-col items-center gap-1">
                                    <i className="fa-solid fa-upload text-blue-600 mb-1"></i>
                                    <span className="text-blue-700 dark:text-blue-400 font-bold">Chọn file Excel</span>
                                    <input type="file" accept=".xlsx, .xls" className="hidden" onChange={handleFileUpload} />
                                </div>
                            )}
                        </label>
                    </div>
                    {error && <p className="mt-4 text-red-500 text-sm font-medium">{error}</p>}
                </div>
            ) : (
                <div className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 overflow-hidden">
                    <div className="p-4 bg-gray-50 dark:bg-gray-750 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center">
                         <span className="text-sm font-bold text-gray-700 dark:text-gray-200">
                             Kết quả: {results.length} học viên ({results.filter(r => r._status === 'invalid').length} cảnh báo)
