                                            ) : (
                                                <span className="text-green-600 dark:text-green-400 text-xs flex items-center gap-1 font-medium">
                                                    <i className="fa-solid fa-circle-check"></i> Hợp lệ
                                                </span>
                                            )}
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}
        </div>
    );
};

