import React, { useState, useMemo, useEffect } from 'react';
import { DataInputPage } from './components/DataInputPage';
import { ReportDashboardPage } from './components/reports/ReportDashboardPage';
import { AdminSidebar } from './components/admin/AdminSidebar';
import { SessionList } from './components/admin/SessionList';
import { SettingsPage } from './components/admin/SettingsPage';
import { TrainingUnitManager } from './components/admin/TrainingUnitManager';
import { AggregateReportPage } from './components/admin/AggregateReportPage';
import { StudentLookupPage } from './components/admin/StudentLookupPage';
import { ContentValidationPage } from './components/admin/ContentValidationPage';
import { storageService } from './services/storageService';
import type { AppData, LicenseClassData, StudentRecord, ReportMetadata, SavedSession, TrainingUnit } from './types';
import { processExcelData, normalizeData } from './services/excelProcessor';
import { Toast } from './components/ui/Toast';

type AppView = 'dashboard' | 'create' | 'detail' | 'settings' | 'training-units' | 'aggregate-report' | 'student-lookup' | 'content-validation';

const App: React.FC = () => {
    // Navigation State
    const [currentView, setCurrentView] = useState<AppView>('dashboard');

    // Data State
    const [savedSessions, setSavedSessions] = useState<SavedSession[]>([]);

    // Working State (New or Selected Session)
    const [appData, setAppData] = useState<AppData | null>(null);
    const [studentRecords, setStudentRecords] = useState<StudentRecord[] | null>(null);
    const [selectedSession, setSelectedSession] = useState<SavedSession | null>(null);
    const [trainingUnits, setTrainingUnits] = useState<TrainingUnit[]>([]);

    // UI State
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);
    const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info' } | null>(null);

    // Dark Mode State
    const [darkMode, setDarkMode] = useState<boolean>(() => {
        return localStorage.getItem('theme') === 'dark';
    });

    // Toggle Dark Mode
    useEffect(() => {
        if (darkMode) {
            document.documentElement.classList.add('dark');
            localStorage.setItem('theme', 'dark');
        } else {
            document.documentElement.classList.remove('dark');
            localStorage.setItem('theme', 'light');
        }
    }, [darkMode]);

    // Initial Metadata Template
    const [reportMetadata, setReportMetadata] = useState<ReportMetadata>({
        meetingTime: '18 giờ 00 phút',
        meetingLocation: 'Trung tâm dạy nghề và Sát hạch lái xe Đông Đô',
        organizer: 'Giám đốc Công an tỉnh',
        attendees: [
            { id: '1', name: 'Đồng chí: Trung tá Dương Kim Giang', role: 'Chức vụ: Phó Trưởng phòng, Chủ tịch Hội đồng' },
            { id: '2', name: 'Đồng chí: Trung tá Trần Duy Giang', role: 'Chức vụ: Đội trưởng, Phó Chủ tịch Hội đồng' },
            { id: '3', name: 'Ông: Vũ Tiến Tuế', role: 'Chức vụ: Giám đốc Trung tâm sát hạch, Ủy viên' },
            { id: '4', name: 'Đồng chí: Vương Mai Phương', role: 'Thư ký' },
        ],
        technicalErrorSBD: '02,153,369',
    });

    // Load sessions & units on mount
    const loadData = async () => {
        const sessions = await storageService.getAllSessions();
        const units = await storageService.getAllTrainingUnits();
        setSavedSessions(sessions);
        setTrainingUnits(units);
    };

    const showToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
        setToast({ message, type });
    };

    // --- HEARTBEAT & INIT LOGIC ---
    useEffect(() => {
        const checkServer = async () => {
             try {
                const res = await fetch('/api/server-status');
                if (res.ok) {
                    const data = await res.json();
                    return data.dbConnected;
                }
             } catch (e) {
                 return false;
             }
             return false;
        };

        const init = async () => {
             // 1. Initial Check
             const isConnected = await checkServer();
             if (isConnected) {
                 showToast('Đã kết nối Cloud SQL thành công!', 'success');
             } else {
                 showToast('Chế độ Offline (Mất kết nối Server)', 'info');
             }

             // 2. Load Data
             await loadData();
        };

        init();

        // 3. Setup Heartbeat Interval (Keep Alive)
        const intervalId = setInterval(async () => {
            const isAlive = await checkServer();
            if (!isAlive) {
                console.warn("Heartbeat missed. Trying to wake up DB...");
            }
        }, 4 * 60 * 1000); 

        return () => clearInterval(intervalId);
    }, []);

    // --- INLINE EDITING LOGIC ---
    const handleStudentUpdate = (id: string, field: string, value: any) => {
        if (!studentRecords) return;

        const updatedRecords = studentRecords.map(record => {
            if (String(record['SỐ BÁO DANH']) === id || String(record['MÃ HỌC VIÊN']) === id) {
                // Determine if we need to update "NỘI DUNG THI" based on scores
                const updatedRecord = { ...record, [field]: value };

                // Recalculate derived logic if scores change? 
                // For now, simpler is better. Just update value.
                // We re-process excel data to update stats.
                return updatedRecord;
            }
            return record;
        });

        // Re-process stats
        try {
            const processedData = processExcelData(updatedRecords);
            setStudentRecords(updatedRecords);
            setAppData(processedData);
            showToast('Đã cập nhật dữ liệu học viên', 'info');
        } catch (e) {
            showToast('Lỗi cập nhật dữ liệu: ' + (e as Error).message, 'error');
        }
    };

    const handleExcelSubmit = (rawRecords: StudentRecord[]) => {
        setIsLoading(true);
        setError(null);
        try {
            // Normalize data FIRST to ensure consistent keys and auto-generated fields
            const cleanRecords = normalizeData(rawRecords);
            const processedData = processExcelData(cleanRecords);

            setStudentRecords(cleanRecords); // Store CLEAN data
            setAppData(processedData);

            showToast('Xử lý dữ liệu thành công! Vui lòng kiểm tra và lưu báo cáo.', 'info');
        } catch (e) {
             setError(`Lỗi xử lý file Excel: ${(e as Error).message}`);
             showToast('Lỗi xử lý file Excel', 'error');
        } finally {
            setIsLoading(false);
        }
    };

    // Calculated Grand Total for the currently active data
    const grandTotal = useMemo<LicenseClassData | null>(() => {
        if (!appData) return null;

        const allRows = [...appData.firstTime.rows, ...appData.retake.rows];
        if (allRows.length === 0) return null;

        return allRows.reduce((acc, row) => {
            acc.totalApplications += row.totalApplications;
            acc.totalParticipants += row.totalParticipants;
            acc.theory.total += row.theory.total;
            acc.theory.pass += row.theory.pass;
            acc.theory.fail += row.theory.fail;
            acc.simulation.total += row.simulation.total;
            acc.simulation.pass += row.simulation.pass;
            acc.simulation.fail += row.simulation.fail;
            acc.practicalCourse.total += row.practicalCourse.total;
            acc.practicalCourse.pass += row.practicalCourse.pass;
            acc.practicalCourse.fail += row.practicalCourse.fail;
            acc.onRoad.total += row.onRoad.total;
            acc.onRoad.pass += row.onRoad.pass;
            acc.onRoad.fail += row.onRoad.fail;
            acc.finalPass += row.finalPass;
            return acc;
        }, {
            class: 'a+b',
            totalApplications: 0,
            totalParticipants: 0,
            theory: { total: 0, pass: 0, fail: 0 },
            simulation: { total: 0, pass: 0, fail: 0 },
            practicalCourse: { total: 0, pass: 0, fail: 0 },
            onRoad: { total: 0, pass: 0, fail: 0 },
            finalPass: 0,
        });
    }, [appData]);

    const handleClearData = () => {
        setAppData(null);
        setStudentRecords(null);
        setError(null);
        // trainingUnits are global config, do not clear them when clearing session data
    };

    const handleSaveSession = async (name: string, reportDate: Date) => {
        if (!appData || !grandTotal || !studentRecords) return;
        setIsLoading(true);

        try {
            const newSession: SavedSession = {
                id: Date.now().toString(),
                name: name,
                createdAt: Date.now(),
                reportDate: reportDate.toISOString(),
                studentRecords: studentRecords,
                appData: appData,
                grandTotal: grandTotal,
                reportMetadata: reportMetadata,
                trainingUnits: trainingUnits // Save units
            };

            await storageService.saveSession(newSession);
            await loadData(); // Refresh sessions

            // Reset and go to dashboard
            handleClearData();
            setCurrentView('dashboard');
            showToast('Đã lưu kỳ sát hạch thành công!', 'success');
        } catch (err) {
            showToast('Lỗi khi lưu dữ liệu!', 'error');
            console.error(err);
        } finally {
            setIsLoading(false);
        }
    };

    const handleUpdateSession = async (name: string, reportDate: Date, metadata: ReportMetadata) => {
        if (!selectedSession) return;
        setIsLoading(true);

        try {
            const updatedSession: SavedSession = {
                ...selectedSession,
                name: name,
                reportDate: reportDate.toISOString(),
                reportMetadata: metadata,
                // Include updated student records (stats are re-calculated in memory but saved here)
                studentRecords: studentRecords || selectedSession.studentRecords,
                appData: appData || selectedSession.appData,
                trainingUnits: selectedSession.trainingUnits || []
            };

            await storageService.saveSession(updatedSession);
            await loadData();

            // Update local selected session state so the view refreshes immediately
            setSelectedSession(updatedSession);
            setReportMetadata(metadata);

            showToast('Đã cập nhật kỳ sát hạch!', 'success');
        } catch (err) {
            showToast('Lỗi khi cập nhật dữ liệu!', 'error');
            console.error(err);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDeleteSession = async (id: string) => {
        try {
            await storageService.deleteSession(id);
            await loadData();
            if (selectedSession?.id === id) {
                setSelectedSession(null);
                setCurrentView('dashboard');
            }
            showToast('Đã xóa kỳ sát hạch.', 'info');
        } catch (err) {
            showToast('Lỗi khi xóa dữ liệu!', 'error');
        }
    };

    const handleSelectSession = async (session: SavedSession) => {
        setIsLoading(true);

        // In local mode, session usually has full data, but getSessionById ensures it
        let fullSession = session;
        if (!session.appData || !session.studentRecords) {
             const loaded = await storageService.getSessionById(session.id);
             if (loaded) fullSession = loaded;
        }

        setSelectedSession(fullSession);
        setAppData(fullSession.appData);
        setStudentRecords(fullSession.studentRecords);
        setReportMetadata(fullSession.reportMetadata);
        setTrainingUnits(fullSession.trainingUnits || []); // Load units
        setCurrentView('detail');
        setIsLoading(false);
    };

    const handleNavChange = (view: AppView) => {
        if (view === 'create') {
            handleClearData();
            setSelectedSession(null);
        }
        if (view === 'dashboard') {
            loadData();
        }
        setCurrentView(view);
    };

    const renderMainContent = () => {
        if (isLoading && !appData && currentView === 'dashboard') {
             return <div className="flex h-full items-center justify-center dark:bg-gray-900"><i className="fa-solid fa-spinner animate-spin text-4xl text-blue-500"></i></div>;
        }

        // 1. Dashboard View
        if (currentView === 'dashboard') {
            return (
                <SessionList 
                    sessions={savedSessions} 
                    onSelectSession={handleSelectSession} 
                    onDeleteSession={handleDeleteSession}
                    onCreateNew={() => handleNavChange('create')}
                    onRefresh={async () => { await loadData(); }}
                />
            );
        }

        // 2. Aggregate Report
        if (currentView === 'aggregate-report') {
            return <AggregateReportPage />;
        }

        // 3. Student Lookup
        if (currentView === 'student-lookup') {
            return <StudentLookupPage />;
        }

        // 4. Content Validation (New Tool)
        if (currentView === 'content-validation') {
            return <ContentValidationPage />;
        }

        // 5. Training Units Management
        if (currentView === 'training-units') {
            return (
                <TrainingUnitManager 
                    trainingUnits={trainingUnits}
                    onUnitsImport={(units) => {
                        setTrainingUnits(units);
                        showToast(`Cập nhật thành công ${units.length} đơn vị đào tạo!`, 'success');
                    }}
                />
            );
        }

        // 6. Create View (Input -> Preview)
        if (currentView === 'create') {
            // If we have calculated data, show Preview Report
            if (appData) {
                 return (
                    <div className="h-full bg-gray-200 dark:bg-gray-800">
                         {/* Header helper for "Back to input" */}
                         <div className="bg-white dark:bg-gray-900 border-b dark:border-gray-700 px-4 py-2 flex justify-between items-center print:hidden">
                            <h2 className="font-bold text-gray-700 dark:text-gray-200">Tạo kỳ sát hạch mới - Xem trước</h2>
                            <button 
                                onClick={handleClearData} 
                                className="text-sm text-red-600 dark:text-red-400 hover:text-red-800 dark:hover:text-red-300"
                            >
                                <i className="fa-solid fa-arrow-left"></i> Quay lại nhập liệu
                            </button>
                         </div>
                         <div className="h-[calc(100%-45px)] overflow-hidden">
                            <ReportDashboardPage 
                                summaryData={appData} 
                                studentRecords={studentRecords}
                                grandTotal={grandTotal} 
                                reportMetadata={reportMetadata}
                                mode="preview"
                                onSaveSession={handleSaveSession}
                                trainingUnits={trainingUnits}
                                onStudentUpdate={handleStudentUpdate}
                            />
                         </div>
                    </div>
                );
            }

            // Else show Input Form
            return (
                <div className="h-full bg-gray-50 dark:bg-gray-900 flex justify-center overflow-y-auto">
                    <div className="w-full max-w-5xl bg-white dark:bg-gray-800 shadow-lg h-full flex flex-col">
                         <DataInputPage 
                            onExcelSubmit={handleExcelSubmit}
                            isLoading={isLoading}
                            error={error}
                            onClearData={handleClearData}
                            reportMetadata={reportMetadata}
                            onMetadataChange={setReportMetadata}
                        />
                    </div>
                </div>
            );
        }

        // 7. Detail View (View Only/Edit)
        if (currentView === 'detail' && selectedSession && appData) {
             return (
                 <div className="h-full bg-gray-200 dark:bg-gray-800 flex flex-col">
                     <div className="bg-white dark:bg-gray-900 border-b dark:border-gray-700 px-6 py-3 flex justify-between items-center print:hidden shadow-sm z-20">
                        <div className="flex items-center gap-3">
                            <button 
                                onClick={() => setCurrentView('dashboard')} 
                                className="w-8 h-8 rounded-full bg-gray-100 dark:bg-gray-700 hover:bg-gray-200 dark:hover:bg-gray-600 flex items-center justify-center text-gray-600 dark:text-gray-300 transition-colors"
                            >
                                <i className="fa-solid fa-arrow-left"></i>
                            </button>
                            <div>
                                <h2 className="font-bold text-lg text-gray-800 dark:text-white">Chi tiết Kỳ Sát Hạch</h2>
                                <p className="text-xs text-gray-500 dark:text-gray-400">Đã lưu: {new Date(selectedSession.createdAt).toLocaleString('vi-VN')}</p>
                            </div>
                        </div>
                     </div>
                     <div className="flex-1 overflow-hidden relative z-0">
                         {isLoading ? (
                             <div className="flex h-full items-center justify-center dark:text-white">Loading full details...</div>
                         ) : (
                            <ReportDashboardPage 
                                summaryData={appData} 
                                studentRecords={studentRecords}
                                grandTotal={grandTotal} 
                                reportMetadata={reportMetadata}
                                mode="view"
                                initialReportDate={selectedSession.reportDate}
                                sessionName={selectedSession.name}
                                onUpdateSession={handleUpdateSession}
                                trainingUnits={trainingUnits}
                                onStudentUpdate={handleStudentUpdate}
                            />
                         )}
                     </div>
                </div>
            );
        }

        // 8. Settings View
        if (currentView === 'settings') {
            return <SettingsPage />;
        }

        return null;
    };

    return (
         <div className={`flex h-screen bg-gray-100 dark:bg-gray-900 text-gray-800 dark:text-gray-200 font-sans overflow-hidden ${darkMode ? 'dark' : ''}`}>
            {/* Sidebar Navigation */}
            <AdminSidebar 
                currentView={currentView === 'detail' ? 'dashboard' : currentView} 
                onChangeView={handleNavChange} 
                darkMode={darkMode}
                onToggleDarkMode={() => setDarkMode(!darkMode)}
            />

            {/* Main Content Area */}
            <main className="flex-1 h-full relative flex flex-col min-w-0">
                {renderMainContent()}
            </main>

            {/* Global Toast */}
            {toast && (
                <Toast 
                    message={toast.message} 
                    type={toast.type} 
                    onClose={() => setToast(null)} 
                />
            )}
        </div>
    );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import type { SavedSession, StudentRecord } from '../../types';
import { storageService } from '../../services/storageService';
import { isStudentPassed, isStudentAbsent } from '../../services/reportUtils';

interface StudentHistoryItem {
    sessionName: string;
    reportDate: string;
    studentData: StudentRecord;
    normalizedName: string;
    normalizedId: string;
    normalizedSbd: string;
    normalizedCccd: string;
    timestamp: number;
}

export const StudentLookupPage: React.FC = () => {
    const [sessions, setSessions] = useState<SavedSession[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const scrollContainerRef = useRef<HTMLDivElement>(null);

    // Filter States
    const [searchTerm, setSearchTerm] = useState('');
    const [debouncedSearchTerm, setDebouncedSearchTerm] = useState('');
    const [dateFrom, setDateFrom] = useState('');
    const [dateTo, setDateTo] = useState('');
    const [selectedClass, setSelectedClass] = useState('all');
    const [selectedStatus, setSelectedStatus] = useState<'all' | 'passed' | 'failed' | 'absent'>('all');

    // Pagination State
    const [currentPage, setCurrentPage] = useState(1);
    const [itemsPerPage, setItemsPerPage] = useState(20);

    // Load data once
    useEffect(() => {
        const loadData = async () => {
            setIsLoading(true);
            try {
                const data = await storageService.getAllSessions();
                setSessions(data);
            } catch (error) {
                console.error("Failed to load sessions", error);
            } finally {
                setIsLoading(false);
            }
        };
        loadData();
    }, []);

    // Debounce Logic
    useEffect(() => {
        const handler = setTimeout(() => setDebouncedSearchTerm(searchTerm), 300);
        return () => clearTimeout(handler);
    }, [searchTerm]);

    // Reset pagination when filters or page size change
    useEffect(() => {
        setCurrentPage(1);
    }, [debouncedSearchTerm, dateFrom, dateTo, selectedClass, selectedStatus, itemsPerPage]);

    // Scroll to top on page change
    useEffect(() => {
        if (scrollContainerRef.current) {
            scrollContainerRef.current.scrollTo({ top: 0, behavior: 'smooth' });
        }
    }, [currentPage]);

    // Flatten and normalize data
    const allStudentItems = useMemo(() => {
        if (sessions.length === 0) return [];
        const flattened: StudentHistoryItem[] = [];
        sessions.forEach(session => {
            if (!session.studentRecords) return;
            const sessionTime = new Date(session.reportDate).getTime();
            session.studentRecords.forEach(student => {
                flattened.push({
                    sessionName: session.name,
                    reportDate: session.reportDate,
                    studentData: student,
                    timestamp: sessionTime,
                    normalizedName: (student['HỌ VÀ TÊN'] || '').toLowerCase(),
                    normalizedId: (student['MÃ HỌC VIÊN'] || '').toString().toLowerCase(),
                    normalizedSbd: (student['SỐ BÁO DANH'] || '').toString().toLowerCase(),
                    normalizedCccd: (student['SỐ CHỨNG MINH'] || '').toString().toLowerCase(),
                });
            });
        });
        return flattened.sort((a, b) => b.timestamp - a.timestamp);
    }, [sessions]);

    const uniqueClasses = useMemo(() => {
        const classes = new Set<string>();
        allStudentItems.forEach(item => {
            if (item.studentData['HẠNG GPLX']) classes.add(item.studentData['HẠNG GPLX'].toString().trim());
        });
        return Array.from(classes).sort();
    }, [allStudentItems]);

    // Filtering
    const filteredResults = useMemo(() => {
        const term = debouncedSearchTerm.toLowerCase().trim();
        const fromDate = dateFrom ? new Date(dateFrom).getTime() : 0;
        const toDate = dateTo ? new Date(dateTo).getTime() + (86400000 - 1) : Infinity;

        return allStudentItems.filter(item => {
            if (item.timestamp < fromDate || item.timestamp > toDate) return false;
            if (selectedClass !== 'all' && item.studentData['HẠNG GPLX'] !== selectedClass) return false;
            if (selectedStatus !== 'all') {
                const isAbsent = isStudentAbsent(item.studentData);
                const isPass = isStudentPassed(item.studentData);
                if (selectedStatus === 'passed' && !isPass) return false;
                if (selectedStatus === 'absent' && !isAbsent) return false;
                if (selectedStatus === 'failed' && (isPass || isAbsent)) return false; 
            }
            if (term) {
                if (!item.normalizedName.includes(term) && !item.normalizedId.includes(term) && 
                    !item.normalizedCccd.includes(term) && item.normalizedSbd !== term) {
                    return false;
                }
            }
            return true;
        });
    }, [allStudentItems, debouncedSearchTerm, dateFrom, dateTo, selectedClass, selectedStatus]);

    // Pagination Calcs
    const totalPages = Math.ceil(filteredResults.length / itemsPerPage);
    const paginatedData = useMemo(() => {
        const startIndex = (currentPage - 1) * itemsPerPage;
        return filteredResults.slice(startIndex, startIndex + itemsPerPage);
    }, [filteredResults, currentPage, itemsPerPage]);

    const stats = useMemo(() => {
        let pass = 0, fail = 0, absent = 0;
        filteredResults.forEach(item => {
            if (isStudentAbsent(item.studentData)) absent++;
            else if (isStudentPassed(item.studentData)) pass++;
            else fail++;
        });
        return { total: filteredResults.length, pass, fail, absent };
    }, [filteredResults]);

    // Page number generation logic
    const getPageNumbers = () => {
        const pages: (number | string)[] = [];
        const maxVisible = 5;
        if (totalPages <= maxVisible + 2) {
            for (let i = 1; i <= totalPages; i++) pages.push(i);
        } else {
            if (currentPage <= 3) {
                pages.push(1, 2, 3, 4, '...', totalPages);
            } else if (currentPage >= totalPages - 2) {
                pages.push(1, '...', totalPages - 3, totalPages - 2, totalPages - 1, totalPages);
            } else {
                pages.push(1, '...', currentPage - 1, currentPage, currentPage + 1, '...', totalPages);
            }
        }
        return pages;
    };

    const handleResetFilters = () => {
        setSearchTerm('');
        setDateFrom('');
        setDateTo('');
        setSelectedClass('all');
        setSelectedStatus('all');
    };

    const getStatusBadge = (pass: boolean, absent: boolean) => {
        if (absent) return <span className="px-2.5 py-0.5 bg-gray-100 text-gray-600 text-xs font-bold rounded-full border border-gray-200 uppercase tracking-wider">Vắng</span>;
        return pass 
            ? <span className="px-2.5 py-0.5 bg-green-100 text-green-700 text-xs font-bold rounded-full border border-green-200 uppercase tracking-wider">Đạt</span>
            : <span className="px-2.5 py-0.5 bg-red-100 text-red-700 text-xs font-bold rounded-full border border-red-200 uppercase tracking-wider">Trượt</span>;
    };

    const getScoreColor = (score: string | undefined) => {
        if (!score) return 'text-gray-300';
        const s = score.trim().toUpperCase();
        if (s === 'ĐẠT') return 'text-green-600 font-bold';
        if (s === 'KHÔNG ĐẠT' || s === 'TRƯỢT') return 'text-red-600 font-bold';
        return 'text-gray-800 dark:text-gray-200 font-medium';
    };

    return (
        <div ref={scrollContainerRef} className="p-4 md:p-8 h-full overflow-y-auto bg-gray-50/50 dark:bg-gray-900/50 transition-colors">
            <div className="mb-6">
                <h2 className="text-2xl font-bold text-gray-800 dark:text-white">Tra cứu Hồ sơ Thí sinh</h2>
                <p className="text-gray-500 dark:text-gray-400 mt-1 text-sm">Tìm kiếm và lọc kết quả thi sát hạch từ cơ sở dữ liệu.</p>
            </div>

            {/* Filter Panel */}
            <div className="bg-white dark:bg-gray-800 p-5 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 mb-6 space-y-4 transition-colors">
                <div className="flex flex-col md:flex-row gap-4">
                    <div className="flex-1 relative">
                        <i className="fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
                        <input 
                            type="text" 
                            className="w-full pl-11 pr-4 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all shadow-sm dark:bg-gray-700 dark:text-white"
                            placeholder="Tìm tên, mã học viên, SBD hoặc CCCD..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                        {searchTerm !== debouncedSearchTerm && (
                            <i className="fa-solid fa-spinner animate-spin absolute right-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
                        )}
                    </div>
                    {(searchTerm || dateFrom || dateTo || selectedClass !== 'all' || selectedStatus !== 'all') && (
                        <button 
                            onClick={handleResetFilters}
                            className="px-4 py-2 text-red-600 dark:text-red-400 bg-red-50 dark:bg-red-900/20 hover:bg-red-100 dark:hover:bg-red-900/40 rounded-lg text-sm font-medium transition-colors flex items-center justify-center gap-2 whitespace-nowrap"
                        >
                            <i className="fa-solid fa-filter-circle-xmark"></i> Xóa bộ lọc
                        </button>
                    )}
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                    <div className="flex items-center gap-2 bg-gray-50 dark:bg-gray-700 p-1 rounded-lg border border-gray-200 dark:border-gray-600">
                        <input type="date" className="w-full bg-transparent border-none text-xs focus:ring-0 p-2 text-gray-600 dark:text-gray-200" value={dateFrom} onChange={(e) => setDateFrom(e.target.value)} title="Từ ngày" />
                        <span className="text-gray-400 text-xs"><i className="fa-solid fa-arrow-right"></i></span>
                        <input type="date" className="w-full bg-transparent border-none text-xs focus:ring-0 p-2 text-gray-600 dark:text-gray-200" value={dateTo} onChange={(e) => setDateTo(e.target.value)} title="Đến ngày" />
                    </div>

                    <div className="relative">
                        <select className="w-full px-3 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm bg-white dark:bg-gray-700 dark:text-white appearance-none" value={selectedClass} onChange={(e) => setSelectedClass(e.target.value)}>
                            <option value="all">Tất cả Hạng GPLX</option>
                            {uniqueClasses.map(cls => <option key={cls} value={cls}>Hạng {cls}</option>)}
                        </select>
                        <i className="fa-solid fa-chevron-down absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 text-xs pointer-events-none"></i>
                    </div>

                    <div className="relative">
                        <select className="w-full px-3 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm bg-white dark:bg-gray-700 dark:text-white appearance-none" value={selectedStatus} onChange={(e) => setSelectedStatus(e.target.value as any)}>
                            <option value="all">Tất cả Trạng thái</option>
                            <option value="passed">Đạt</option>
                            <option value="failed">Trượt</option>
                            <option value="absent">Vắng thi</option>
                        </select>
                        <i className="fa-solid fa-chevron-down absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 text-xs pointer-events-none"></i>
                    </div>

                    <div className="flex items-center gap-3">
                         <span className="text-xs font-bold text-gray-500 uppercase whitespace-nowrap">Hiển thị</span>
                         <select className="px-3 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm bg-white dark:bg-gray-700 dark:text-white appearance-none w-20" value={itemsPerPage} onChange={(e) => setItemsPerPage(Number(e.target.value))}>
                            <option value={10}>10</option>
                            <option value={20}>20</option>
                            <option value={50}>50</option>
                            <option value={100}>100</option>
                        </select>
                    </div>
                </div>
            </div>

            {isLoading ? (
                <div className="text-center py-20">
                    <i className="fa-solid fa-spinner animate-spin text-3xl text-blue-500"></i>
                    <p className="mt-3 text-gray-500 dark:text-gray-400">Đang tải dữ liệu...</p>
                </div>
            ) : (
                <>
                    {filteredResults.length > 0 && (
                        <div className="flex flex-wrap items-center justify-between gap-4 mb-4 text-sm">
                            <div className="flex items-center gap-4">
                                <span className="font-bold text-gray-700 dark:text-gray-200">Kết quả: {stats.total} thí sinh</span>
                                <div className="h-4 w-px bg-gray-300 dark:bg-gray-600 hidden sm:block"></div>
                                <span className="text-green-600 dark:text-green-400"><i className="fa-solid fa-check-circle mr-1"></i>Đạt: {stats.pass}</span>
                                <span className="text-red-600 dark:text-red-400"><i className="fa-solid fa-circle-xmark mr-1"></i>Trượt: {stats.fail}</span>
                                <span className="text-gray-500 dark:text-gray-400"><i className="fa-solid fa-user-slash mr-1"></i>Vắng: {stats.absent}</span>
                            </div>
                            <div className="text-gray-500 dark:text-gray-400 italic text-xs">
                                Đang hiển thị {((currentPage-1)*itemsPerPage)+1} đến {Math.min(currentPage*itemsPerPage, stats.total)}
                            </div>
                        </div>
                    )}

                    {filteredResults.length > 0 ? (
                        <>
                        <div className="space-y-4">
                            {paginatedData.map((item, index) => {
                                const s = item.studentData;
                                const isPass = isStudentPassed(s);
                                const isAbsent = isStudentAbsent(s);
                                const uniqueKey = `${s['SỐ BÁO DANH']}_${item.reportDate}_${index}`;

                                return (
                                    <div key={uniqueKey} className="bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700 overflow-hidden hover:shadow-md transition-all duration-200">
                                        <div className="flex flex-col md:flex-row">
                                            <div className="p-4 md:w-1/3 border-b md:border-b-0 md:border-r border-gray-100 dark:border-gray-700 bg-gray-50/30 dark:bg-gray-700/30">
                                                <div className="flex justify-between items-start mb-2">
                                                    <span className="text-xs font-bold text-gray-400 uppercase tracking-wider">Họ và tên</span>
                                                    {getStatusBadge(isPass, isAbsent)}
                                                </div>
                                                <h3 className="text-lg font-bold text-gray-800 dark:text-gray-100 mb-1">{s['HỌ VÀ TÊN']}</h3>
                                                <div className="space-y-1 text-sm text-gray-600 dark:text-gray-400">
                                                    <div className="flex items-center gap-2"><i className="fa-solid fa-cake-candles w-4 text-center text-gray-400"></i><span>{s['NGÀY SINH']}</span></div>
                                                    <div className="flex items-center gap-2"><i className="fa-regular fa-id-card w-4 text-center text-gray-400"></i><span className="font-mono">{s['SỐ CHỨNG MINH'] || '---'}</span></div>
                                                    <div className="flex items-center gap-2"><i className="fa-solid fa-fingerprint w-4 text-center text-gray-400"></i><span className="font-mono">{s['MÃ HỌC VIÊN']}</span></div>
                                                </div>
                                            </div>

                                            <div className="p-4 md:w-1/2 grid grid-cols-2 sm:grid-cols-4 gap-4 items-center">
                                                {[
                                                    { label: 'Lý Thuyết', score: s['LÝ THUYẾT'] },
                                                    { label: 'Mô Phỏng', score: s['MÔ PHỎNG'] },
                                                    { label: 'Sa Hình', score: s['SA HÌNH'] },
                                                    { label: 'Đ.Trường', score: s['ĐƯỜNG TRƯỜNG'] }
                                                ].map((exam, i) => (
                                                    <div key={i} className="text-center">
                                                        <div className="text-[10px] uppercase text-gray-400 font-bold mb-1">{exam.label}</div>
                                                        <div className={getScoreColor(exam.score)}>{exam.score || '-'}</div>
                                                    </div>
                                                ))}
                                                <div className="col-span-2 sm:col-span-4 mt-2 pt-2 border-t border-gray-100 dark:border-gray-700 flex gap-4 text-xs text-gray-500 dark:text-gray-400">
                                                     <div className="flex flex-col"><span className="uppercase text-[10px] font-bold text-gray-400">Hạng</span><span className="font-bold text-gray-700 dark:text-gray-200">{s['HẠNG GPLX']}</span></div>
                                                     <div className="flex flex-col"><span className="uppercase text-[10px] font-bold text-gray-400">Nội dung thi</span><span className="font-bold text-blue-600 dark:text-blue-400">{s['NỘI DUNG THI'] || '-'}</span></div>
                                                     <div className="flex flex-col"><span className="uppercase text-[10px] font-bold text-gray-400">SBD</span><span className="font-bold text-gray-700 dark:text-gray-200">{s['SỐ BÁO DANH']}</span></div>
                                                </div>
                                            </div>

                                            <div className="p-4 md:w-1/6 bg-blue-50/30 dark:bg-blue-900/10 border-t md:border-t-0 md:border-l border-gray-100 dark:border-gray-700 flex flex-col justify-center text-right">
                                                <div className="text-[10px] uppercase text-gray-400 font-bold mb-1">Kỳ Sát Hạch</div>
                                                <div className="text-sm font-semibold text-blue-700 dark:text-blue-300 line-clamp-2">{item.sessionName}</div>
                                                <div className="text-xs text-gray-500 dark:text-gray-400 mt-1">{new Date(item.reportDate).toLocaleDateString('vi-VN')}</div>
                                            </div>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>

                        {/* Advanced Pagination Navigation */}
                        {totalPages > 1 && (
                            <div className="mt-10 mb-20 flex flex-wrap justify-center items-center gap-2">
                                <button onClick={() => setCurrentPage(1)} disabled={currentPage === 1} className="px-3 py-2 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 rounded-md text-gray-600 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700 disabled:opacity-30 disabled:cursor-not-allowed transition-colors" title="Trang đầu">
                                    <i className="fa-solid fa-angles-left"></i>
                                </button>
                                <button onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))} disabled={currentPage === 1} className="px-3 py-2 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 rounded-md text-gray-600 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700 disabled:opacity-30 disabled:cursor-not-allowed transition-colors">
                                    <i className="fa-solid fa-chevron-left"></i>
                                </button>

                                {getPageNumbers().map((p, i) => (
                                    typeof p === 'number' ? (
                                        <button key={i} onClick={() => setCurrentPage(p)} className={`w-10 h-10 flex items-center justify-center rounded-md font-bold text-sm transition-all ${currentPage === p ? 'bg-blue-600 text-white shadow-md scale-110' : 'bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-600 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700'}`}>
                                            {p}
                                        </button>
                                    ) : (
                                        <span key={i} className="px-2 text-gray-400 font-bold">...</span>
                                    )
                                ))}

                                <button onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))} disabled={currentPage === totalPages} className="px-3 py-2 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 rounded-md text-gray-600 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700 disabled:opacity-30 disabled:cursor-not-allowed transition-colors">
                                    <i className="fa-solid fa-chevron-right"></i>
                                </button>
                                <button onClick={() => setCurrentPage(totalPages)} disabled={currentPage === totalPages} className="px-3 py-2 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 rounded-md text-gray-600 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700 disabled:opacity-30 disabled:cursor-not-allowed transition-colors" title="Trang cuối">
                                    <i className="fa-solid fa-angles-right"></i>
                                </button>
                            </div>
                        )}
                        </>
                    ) : (
                        <div className="text-center py-16 bg-white dark:bg-gray-800 rounded-xl border border-dashed border-gray-300 dark:border-gray-600 transition-colors">
                            <div className="w-16 h-16 bg-gray-100 dark:bg-gray-700 rounded-full flex items-center justify-center mx-auto mb-4 text-gray-400">
                                <i className="fa-solid fa-filter"></i>
                            </div>
                            <h3 className="text-gray-600 dark:text-gray-300 font-medium">Không tìm thấy kết quả</h3>
                            <p className="text-gray-400 dark:text-gray-500 text-sm mt-1">Vui lòng thử thay đổi từ khóa hoặc điều chỉnh bộ lọc.</p>
                            <button onClick={handleResetFilters} className="mt-4 px-4 py-2 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-lg text-sm font-medium hover:bg-blue-100 dark:hover:bg-blue-900/50 transition-colors">
                                Xóa bộ lọc
                            </button>
                        </div>
                    )}
                </>
            )}
        </div>
    );
};

import React, { useState, useMemo } from 'react';
import type { StudentRecord, TrainingUnit, SavedSession } from '../../types';
import { storageService } from '../../services/storageService';
import { exportValidationResultsToExcel } from '../../services/excelGenerator';

declare const XLSX: any;

interface ValidationResult extends StudentRecord {
    _status: 'valid' | 'invalid';
    _messages: string[];
}

interface PassDetail {
    date: string;
    session: string;
    isImplicit: boolean;
}

export const ContentValidationPage: React.FC = () => {
    const [isLoading, setIsLoading] = useState(false);
    const [results, setResults] = useState<ValidationResult[]>([]);
    const [error, setError] = useState<string | null>(null);

    // Filter States
    const [searchTerm, setSearchTerm] = useState('');
    const [statusFilter, setStatusFilter] = useState<'all' | 'valid' | 'invalid'>('all');
    const [classFilter, setClassFilter] = useState('all');
    const [contentFilter, setContentFilter] = useState('all');

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            setIsLoading(true);
            setError(null);
            const file = e.target.files[0];
            const reader = new FileReader();

            reader.onload = async (event) => {
                try {
                    const data = new Uint8Array(event.target!.result as ArrayBuffer);
                    const workbook = XLSX.read(data, { type: 'array' });
                    const sheetName = workbook.SheetNames[0];
                    const worksheet = workbook.Sheets[sheetName];
                    const json: any[] = XLSX.utils.sheet_to_json(worksheet);

                    if (json.length === 0) {
                        setError("File Excel không có dữ liệu.");
                        setIsLoading(false);
                        return;
                    }

                    await performValidation(json);
                } catch (err) {
                    setError("Lỗi xử lý file Excel.");
                    setIsLoading(false);
                }
            };
            reader.readAsArrayBuffer(file);
        }
    };

    const performValidation = async (incomingData: any[]) => {
        try {
            const pastSessions = await storageService.getAllSessions();

            // 1. Build Pass Map
            const passMap = new Map<string, Map<string, PassDetail>>();
            const studentHistory = new Map<string, { record: StudentRecord, sessionName: string, date: Date }[]>();

            pastSessions.forEach(session => {
                const date = new Date(session.reportDate);
                session.studentRecords.forEach(record => {
                    const studentId = String(record['MÃ HỌC VIÊN']).trim();
                    if (!studentId) return;
                    if (!studentHistory.has(studentId)) studentHistory.set(studentId, []);
                    studentHistory.get(studentId)!.push({ record, sessionName: session.name, date });
                });
            });

            studentHistory.forEach((history, studentId) => {
                history.sort((a, b) => a.date.getTime() - b.date.getTime());
                const studentPasses = new Map<string, PassDetail>();
                const firstEntry = history[0];
                const firstContent = (firstEntry.record['NỘI DUNG THI'] || '').toUpperCase().replace(/Đ/g, 'D');
                const firstDateStr = firstEntry.date.toLocaleDateString('vi-VN');

                ['L', 'M', 'H', 'D'].forEach(code => {
                    if (!firstContent.includes(code)) {
                        studentPasses.set(code, { date: firstDateStr, session: firstEntry.sessionName, isImplicit: true });
                    }
                });

                history.forEach(h => {
                    const dStr = h.date.toLocaleDateString('vi-VN');
                    if (String(h.record['LÝ THUYẾT']).trim().toUpperCase() === 'ĐẠT') studentPasses.set('L', { date: dStr, session: h.sessionName, isImplicit: false });
                    if (String(h.record['MÔ PHỎNG']).trim().toUpperCase() === 'ĐẠT') studentPasses.set('M', { date: dStr, session: h.sessionName, isImplicit: false });
                    if (String(h.record['SA HÌNH']).trim().toUpperCase() === 'ĐẠT') studentPasses.set('H', { date: dStr, session: h.sessionName, isImplicit: false });
                    if (String(h.record['ĐƯỜNG TRƯỜNG']).trim().toUpperCase() === 'ĐẠT') studentPasses.set('D', { date: dStr, session: h.sessionName, isImplicit: false });
                });
                passMap.set(studentId, studentPasses);
            });

            // 2. Validate Incoming Data (normalize keys)
            const subjectLabels: Record<string, string> = { 'L': 'Lý thuyết', 'M': 'Mô phỏng', 'H': 'Sa hình', 'D': 'Đường trường' };
            const validated: ValidationResult[] = incomingData.map(row => {
                // Handle different possible column names for Mã học viên and Nội dung thi
                const studentId = String(row['MÃ HỌC VIÊN'] || row['MA HOC VIEN'] || row['MAHV'] || '').trim();
                const rawContent = String(row['NỘI DUNG THI'] || row['NOI DUNG THI'] || row['ND THI'] || '').toUpperCase();
                const content = rawContent.replace(/Đ/g, 'D');

                const messages: string[] = [];

                if (studentId && passMap.has(studentId)) {
                    const history = passMap.get(studentId)!;
                    ['L', 'M', 'H', 'D'].forEach(code => {
                        if (content.includes(code) && history.has(code)) {
                            const h = history.get(code)!;
                            if (h.isImplicit) {
                                messages.push(`Mặc định đạt ${subjectLabels[code]} (${h.date})`);
                            } else {
                                messages.push(`Đã đạt ${subjectLabels[code]} (${h.date})`);
                            }
                        }
                    });
                }

                return {
                    ...row,
                    // Ensure standard keys exist for filtering/display
                    'MÃ HỌC VIÊN': studentId,
                    'NỘI DUNG THI': rawContent,
                    'HỌ VÀ TÊN': row['HỌ VÀ TÊN'] || row['HO VA TEN'] || row['HỌ TÊN'] || '',
                    'HẠNG': row['HẠNG'] || row['HANG'] || row['HẠNG GPLX'] || '',
                    _status: messages.length > 0 ? 'invalid' : 'valid',
                    _messages: messages
                };
            });

            setResults(validated);
        } catch (err) {
            console.error(err);
            setError("Lỗi khi đối soát dữ liệu.");
        } finally {
            setIsLoading(false);
        }
    };

    // Derived Filter Data
    const uniqueClasses = useMemo(() => {
        const classes = new Set<string>();
        results.forEach(r => { if (r['HẠNG']) classes.add(String(r['HẠNG']).trim()); });
        return Array.from(classes).sort();
    }, [results]);

    const uniqueContents = useMemo(() => {
        const contents = new Set<string>();
        results.forEach(r => { if (r['NỘI DUNG THI']) contents.add(String(r['NỘI DUNG THI']).trim()); });
        return Array.from(contents).sort();
    }, [results]);

    const filteredResults = useMemo(() => {
        return results.filter(r => {
            const matchesSearch = searchTerm === '' || 
                String(r['HỌ VÀ TÊN']).toLowerCase().includes(searchTerm.toLowerCase()) ||
                String(r['MÃ HỌC VIÊN']).toLowerCase().includes(searchTerm.toLowerCase()) ||
                String(r['SỐ BÁO DANH'] || r['SBD']).toLowerCase().includes(searchTerm.toLowerCase());

            const matchesStatus = statusFilter === 'all' || r._status === statusFilter;
            const matchesClass = classFilter === 'all' || String(r['HẠNG']) === classFilter;
            const matchesContent = contentFilter === 'all' || String(r['NỘI DUNG THI']) === contentFilter;

            return matchesSearch && matchesStatus && matchesClass && matchesContent;
        });
    }, [results, searchTerm, statusFilter, classFilter, contentFilter]);

    const handleExport = () => {
        if (filteredResults.length === 0) return;
        exportValidationResultsToExcel(filteredResults);
    };

    const handleClear = () => {
        if (window.confirm('Xóa kết quả hiện tại?')) {
            setResults([]);
            setError(null);
            setSearchTerm('');
            setStatusFilter('all');
            setClassFilter('all');
            setContentFilter('all');
        }
    };

    const handleResetFilters = () => {
        setSearchTerm('');
        setStatusFilter('all');
        setClassFilter('all');
        setContentFilter('all');
    };

    return (
        <div className="p-6 md:p-8 h-full overflow-y-auto bg-gray-50 dark:bg-gray-900">
            <div className="mb-6 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
