                                            </td>
                                            <td className={`px-4 py-4 text-center font-medium ${String(item.record['SA HÌNH']).toUpperCase() === 'ĐẠT' ? 'text-green-600' : 'text-red-400'}`}>
                                                {item.record['SA HÌNH'] || '-'}
