import type { AppData, LicenseClassData, StudentRecord } from '../types';
import { getResultStatus, isStudentAbsent, isStudentPassed } from './reportUtils';

/**
 * Standardizes strings for robust header matching.
 * Handles Vietnamese Unicode normalization (NFC/NFD) and removes special chars.
 */
const simplifyHeader = (str: string): string => {
    return (str || '')
        .toString()
        .trim()
        .normalize('NFC') // Crucial for Vietnamese character matching
        .toUpperCase()
        .replace(/\s+/g, ' ');
};

export const normalizeRecord = (record: any): StudentRecord => {
    const normalized: any = {};

    // Primary Field Mappings (Simplified Keys -> Standard Keys)
    const keyMap: {[key: string]: string} = {
        'HỌ VÀ TÊN': 'HỌ VÀ TÊN', 'HO VA TEN': 'HỌ VÀ TÊN', 'HỌ TÊN': 'HỌ VÀ TÊN', 'HOTEN': 'HỌ VÀ TÊN', 'TÊN HỌC VIÊN': 'HỌ VÀ TÊN',
        'SỐ BÁO DANH': 'SỐ BÁO DANH', 'SBD': 'SỐ BÁO DANH', 'SO BAO DANH': 'SỐ BÁO DANH',
        'MÃ HỌC VIÊN': 'MÃ HỌC VIÊN', 'MÃ HV': 'MÃ HỌC VIÊN', 'MA HOC VIEN': 'MÃ HỌC VIÊN', 'MAHV': 'MÃ HỌC VIÊN', 'MÃ DK': 'MÃ HỌC VIÊN',
        'HẠNG GPLX': 'HẠNG GPLX', 'HẠNG': 'HẠNG GPLX', 'HANG': 'HẠNG GPLX', 'HANG GPLX': 'HẠNG GPLX', 'HẠNG XE': 'HẠNG GPLX',
        'NỘI DUNG THI': 'NỘI DUNG THI', 'NOI DUNG THI': 'NỘI DUNG THI', 'ND THI': 'NỘI DUNG THI', 'MÔN THI': 'NỘI DUNG THI', 'NDSH': 'NỘI DUNG THI', 'NỘI DUNG SH': 'NỘI DUNG THI',

        'LÝ THUYẾT': 'LÝ THUYẾT', 'LY THUYET': 'LÝ THUYẾT', 'LT': 'LÝ THUYẾT', 'KQ LT': 'LÝ THUYẾT',
        'MÔ PHỎNG': 'MÔ PHỎNG', 'MO PHONG': 'MÔ PHỎNG', 'MP': 'MÔ PHỎNG', 'KQ MP': 'MÔ PHỎNG',
        'SA HÌNH': 'SA HÌNH', 'KQ SH': 'SA HÌNH', 'TH TRONG HÌNH': 'SA HÌNH', 'TRONG HÌNH': 'SA HÌNH',
        'ĐƯỜNG TRƯỜNG': 'ĐƯỜNG TRƯỜNG', 'KQ ĐT': 'ĐƯỜNG TRƯỜNG', 'TH ĐƯỜNG TRƯỜNG': 'ĐƯỜNG TRƯỜNG', 'ĐƯỜNG TRƯỜN': 'ĐƯỜNG TRƯỜNG',

        'NGÀY SINH': 'NGÀY SINH', 'NGAY SINH': 'NGÀY SINH',
        'SỐ CHỨNG MINH': 'SỐ CHỨNG MINH', 'SO CHUNG MINH': 'SỐ CHỨNG MINH', 'CCCD': 'SỐ CHỨNG MINH', 'CMND': 'SỐ CHỨNG MINH', 'CHỨNG MINH': 'SỐ CHỨNG MINH',
        'NƠI CƯ TRÚ': 'NƠI CƯ TRÚ', 'NOI CU TRU': 'NƠI CƯ TRÚ', 'ĐỊA CHỈ': 'NƠI CƯ TRÚ'
    };

    Object.keys(record).forEach(key => {
        const cleanKey = simplifyHeader(key);
        let mappedKey = keyMap[cleanKey];

        // Secondary fuzzy matching if direct mapping fails
        if (!mappedKey) {
            if (cleanKey.includes('LY THUYET') || cleanKey.includes('LÝ THUYẾT')) mappedKey = 'LÝ THUYẾT';
            else if (cleanKey.includes('MO PHONG') || cleanKey.includes('MÔ PHỎNG')) mappedKey = 'MÔ PHỎNG';
            else if (cleanKey.includes('SA HINH') || cleanKey.includes('SA HÌNH')) mappedKey = 'SA HÌNH';
            else if (cleanKey.includes('DUONG TRUONG') || cleanKey.includes('ĐƯỜNG TRƯỜNG')) mappedKey = 'ĐƯỜNG TRƯỜNG';
            else if (cleanKey.includes('CHUNG MINH') || cleanKey.includes('CĂN CƯỚC')) mappedKey = 'SỐ CHỨNG MINH';
            else if (cleanKey.includes('NGAY SINH')) mappedKey = 'NGÀY SINH';
            else if (cleanKey.includes('HO TEN') || cleanKey.includes('HỌ TÊN')) mappedKey = 'HỌ VÀ TÊN';
            else mappedKey = cleanKey;
        }

        normalized[mappedKey] = record[key];
    });

    // CRITICAL: Fallback for missing Student ID using ID Card number (Số chứng minh)
    if (!normalized['MÃ HỌC VIÊN'] && normalized['SỐ CHỨNG MINH']) {
        normalized['MÃ HỌC VIÊN'] = normalized['SỐ CHỨNG MINH'];
    }

    return normalized as StudentRecord;
};

const createNewClassData = (className: string): LicenseClassData => ({
    class: className,
    totalApplications: 0,
    totalParticipants: 0,
    theory: { total: 0, pass: 0, fail: 0 },
    simulation: { total: 0, pass: 0, fail: 0 },
    practicalCourse: { total: 0, pass: 0, fail: 0 },
    onRoad: { total: 0, pass: 0, fail: 0 },
    finalPass: 0,
});

export const normalizeData = (rawRecords: any[]): StudentRecord[] => {
    return rawRecords.map(raw => {
        const record = normalizeRecord(raw);

        // Standardize result values to uppercase string
        ['LÝ THUYẾT', 'MÔ PHỎNG', 'SA HÌNH', 'ĐƯỜNG TRƯỜNG'].forEach(field => {
             if (record[field as keyof StudentRecord] !== undefined) {
                 (record as any)[field] = String(record[field as keyof StudentRecord] || '').trim().toUpperCase();
             }
        });

        // Ensure "NỘI DUNG THI" is extracted and standardized
        let content = String(record['NỘI DUNG THI'] || '').trim().toUpperCase();
        content = content.replace(/Đ/g, 'D'); // Normalize 'Đ' to 'D' for logic processing
        record['NỘI DUNG THI'] = content;

        // Auto-generate 'NỘI DUNG THI' if missing based on result values in Excel
        if (!record['NỘI DUNG THI']) {
             const parts: string[] = [];
             if (record['LÝ THUYẾT'] && record['LÝ THUYẾT'] !== 'VẮNG') parts.push('L');
             if (record['MÔ PHỎNG'] && record['MÔ PHỎNG'] !== 'VẮNG') parts.push('M');
             if (record['SA HÌNH'] && record['SA HÌNH'] !== 'VẮNG') parts.push('H');
             if (record['ĐƯỜNG TRƯỜNG'] && record['ĐƯỜNG TRƯỜNG'] !== 'VẮNG') parts.push('D');

             if (parts.length > 0) {
                 record['NỘI DUNG THI'] = parts.join('');
             }
        }
        return record;
    });
};

export const processExcelData = (rawRecords: StudentRecord[]): AppData => {
    const records = normalizeData(rawRecords);
    const firstTimeData: { [className: string]: LicenseClassData } = {};
    const retakeData: { [className: string]: LicenseClassData } = {};

    for (const record of records) {
        const className = String(record['HẠNG GPLX'] || '').trim();
        if (!className) continue;

        const maHocVien = String(record['MÃ HỌC VIÊN'] || '').trim();
        const isRetake = maHocVien.startsWith('2721') || maHocVien.startsWith('2722');

        const targetData = isRetake ? retakeData : firstTimeData;

        if (!targetData[className]) {
            targetData[className] = createNewClassData(className);
        }
        const classData = targetData[className];

        classData.totalApplications += 1;

        if (!isStudentAbsent(record)) {
            classData.totalParticipants += 1;
        }

        const theoryRes = getResultStatus(record['LÝ THUYẾT']);
        if (theoryRes.participated) {
            classData.theory.total += 1;
            if (theoryRes.passed) classData.theory.pass += 1;
        }

        const simRes = getResultStatus(record['MÔ PHỎNG']);
        if (simRes.participated) {
            classData.simulation.total += 1;
            if (simRes.passed) classData.simulation.pass += 1;
        }

        const practicalRes = getResultStatus(record['SA HÌNH']);
        if (practicalRes.participated) {
            classData.practicalCourse.total += 1;
            if (practicalRes.passed) classData.practicalCourse.pass += 1;
        }

        const onRoadRes = getResultStatus(record['ĐƯỜNG TRƯỜNG']);
        if (onRoadRes.participated) {
            classData.onRoad.total += 1;
            if (onRoadRes.passed) classData.onRoad.pass += 1;
        }

        if (isStudentPassed(record)) {
            classData.finalPass += 1;
        }
    }

    const finalizeData = (data: { [className: string]: LicenseClassData }): LicenseClassData[] => {
        const classDataArray = Object.values(data);
        for (const classData of classDataArray) {
            classData.theory.fail = Math.max(0, classData.theory.total - classData.theory.pass);
            classData.simulation.fail = Math.max(0, classData.simulation.total - classData.simulation.pass);
            classData.practicalCourse.fail = Math.max(0, classData.practicalCourse.total - classData.practicalCourse.pass);
            classData.onRoad.fail = Math.max(0, classData.onRoad.total - classData.onRoad.pass);
        }
        return classDataArray.sort((a, b) => a.class.localeCompare(b.class));
    };

    const firstTimeRows = finalizeData(firstTimeData);
    const retakeRows = finalizeData(retakeData);

    if (firstTimeRows.length === 0 && retakeRows.length === 0) {
        throw new Error("Không tìm thấy dữ liệu học viên hợp lệ (Vui lòng kiểm tra tiêu đề các cột).");
    }

    return {
        firstTime: { title: 'a) Học viên dự thi lần đầu:', rows: firstTimeRows },
        retake: { title: 'b) Thí sinh thuộc đối tượng cấp lại giấy phép lái xe và thí sinh tự do:', rows: retakeRows }
    };
};

import type { StudentRecord, TrainingUnit } from '../types';

// Helper to check result status, handles empty/null/different formats.
export const getResultStatus = (result: any): { participated: boolean, passed: boolean } => {
    const val = String(result || '').trim().toUpperCase();
    if (val === '' || val === 'VẮNG' || val === 'V') return { participated: false, passed: false };

    // Handles 'ĐẠT', 'DẠT', 'DAT', 'D'
    const isPass = val.startsWith('Đ') || val.startsWith('D') || val === 'DAT' || val === 'PASSED';
    return { participated: true, passed: isPass };
};

// Check if a student is considered absent (took no tests).
export const isStudentAbsent = (record: StudentRecord): boolean => {
    const theory = getResultStatus(record['LÝ THUYẾT']);
    const simulation = getResultStatus(record['MÔ PHỎNG']);
    const practical = getResultStatus(record['SA HÌNH']);
    const onRoad = getResultStatus(record['ĐƯỜNG TRƯỜNG']);
    return !theory.participated && !simulation.participated && !practical.participated && !onRoad.participated;
};

// Check if a student passed, based on their required tests.
export const isStudentPassed = (record: StudentRecord): boolean => {
    if (isStudentAbsent(record)) return false;

    // Standardize 'NỘI DUNG THI' (e.g., 'LMHD' or 'L+M+H+D')
    let noiDungThi = String(record['NỘI DUNG THI'] || '').trim().toUpperCase();
    noiDungThi = noiDungThi.replace(/Đ/g, 'D');

    // If content is still empty, we can't determine pass status, default to false
    if (!noiDungThi) return false;

    const subjects = {
        L: getResultStatus(record['LÝ THUYẾT']).passed,
        M: getResultStatus(record['MÔ PHỎNG']).passed,
        H: getResultStatus(record['SA HÌNH']).passed,
        D: getResultStatus(record['ĐƯỜNG TRƯỜNG']).passed
    };

    // Logical check: If the code is in registration, it MUST be passed.
    const checks = [
        !noiDungThi.includes('L') || subjects.L,
        !noiDungThi.includes('M') || subjects.M,
        !noiDungThi.includes('H') || subjects.H,
        !noiDungThi.includes('D') || subjects.D
    ];

    return checks.every(result => result === true);
};

// Generate the summary string (Total: X, Class B: Y, ...)
export const generateClassSummaryString = (students: StudentRecord[]): string => {
    if (!students || students.length === 0) return "Tổng số: 0";

    const classCounts: { [key: string]: number } = {};
    for (const student of students) {
        const className = String(student['HẠNG GPLX'] || 'Khác').trim();
        classCounts[className] = (classCounts[className] || 0) + 1;
    }

    const parts = Object.keys(classCounts).sort().map(cls => `Hạng ${cls}: ${classCounts[cls]}`);
    return `Tổng số: ${students.length}\u00A0\u00A0\u00A0\u00A0${parts.join('; ')}`;
};

export const generateGhiChu = (record: StudentRecord): string => {
    const maHocVien = String(record['MÃ HỌC VIÊN'] || '').trim();
    const isRetake = maHocVien.startsWith('2721') || maHocVien.startsWith('2722');
    let content = String(record['NỘI DUNG THI'] || '').trim().toUpperCase().replace(/D/g, 'Đ');

    if (isRetake) return `Thi lại nội dung: ${content}`;
    return `Thi lần đầu`;
};

export const identifyTrainingUnit = (studentId: any, units: TrainingUnit[] = []): string => {
    if (!studentId || !units.length) return '';
    const sId = String(studentId).trim();
    const sortedUnits = [...units].sort((a, b) => b.code.length - a.code.length);
    const matchedUnit = sortedUnits.find(u => sId.startsWith(u.code));
    return matchedUnit ? matchedUnit.name : '';
};

