/**
 * Standardizes strings for robust header matching.
 * Handles Vietnamese Unicode normalization (NFC/NFD) and removes special chars.
 */
const simplifyHeader = (str: string): string => {
    return (str || '')
        .toString()
        .trim()
        .normalize('NFC') // Crucial for Vietnamese character matching
        .toUpperCase()
        .replace(/\s+/g, ' ');
};

export const normalizeRecord = (record: any): StudentRecord => {
    const normalized: any = {};

    // Primary Field Mappings based on the user's Excel image
    const keyMap: {[key: string]: string} = {
        'HỌ VÀ TÊN': 'HỌ VÀ TÊN', 'HO VA TEN': 'HỌ VÀ TÊN', 'HỌ TÊN': 'HỌ VÀ TÊN',
        'SỐ BÁO DANH': 'SỐ BÁO DANH', 'SBD': 'SỐ BÁO DANH',
        'MÃ HỌC VIÊN': 'MÃ HỌC VIÊN', 'MA HOC VIEN': 'MÃ HỌC VIÊN', 'MAHV': 'MÃ HỌC VIÊN',
        'HẠNG GPLX': 'HẠNG GPLX', 'HANG GPLX': 'HẠNG GPLX', 'HẠNG': 'HẠNG GPLX',
        'NỘI DUNG': 'NỘI DUNG THI', 'NỘI DUNG THI': 'NỘI DUNG THI', 'NỘI DUNG SH': 'NỘI DUNG THI', 'ND': 'NỘI DUNG THI',
        'LÝ THUYẾT': 'LÝ THUYẾT', 'LT': 'LÝ THUYẾT',
        'MÔ PHỎNG': 'MÔ PHỎNG', 'MP': 'MÔ PHỎNG',
        'SA HÌNH': 'SA HÌNH', 'SH': 'SA HÌNH',
        'ĐƯỜNG TRƯỜNG': 'ĐƯỜNG TRƯỜNG', 'DT': 'ĐƯỜNG TRƯỜNG', 'ĐT': 'ĐƯỜNG TRƯỜNG',
        'SỐ CHỨNG MINH': 'SỐ CHỨNG MINH', 'SO CHUNG MINH': 'SỐ CHỨNG MINH', 'CCCD': 'SỐ CHỨNG MINH',
        'NGÀY SINH': 'NGÀY SINH', 'NGAY SINH': 'NGÀY SINH',
        'NƠI CƯ TRÚ': 'NƠI CƯ TRÚ', 'DIA CHI': 'NƠI CƯ TRÚ'
    };

    Object.keys(record).forEach(key => {
        const cleanKey = simplifyHeader(key);
        let mappedKey = keyMap[cleanKey];

        // Secondary fuzzy matching
        if (!mappedKey) {
            if (cleanKey === 'NOI DUNG') mappedKey = 'NỘI DUNG THI';
            else if (cleanKey.includes('LY THUYET')) mappedKey = 'LÝ THUYẾT';
            else if (cleanKey.includes('MO PHONG')) mappedKey = 'MÔ PHỎNG';
            else if (cleanKey.includes('SA HINH')) mappedKey = 'SA HÌNH';
            else if (cleanKey.includes('DUONG TRUONG')) mappedKey = 'ĐƯỜNG TRƯỜNG';
            else if (cleanKey.includes('CHUNG MINH')) mappedKey = 'SỐ CHỨNG MINH';
            else mappedKey = cleanKey;
        }

        normalized[mappedKey] = record[key];
    });

    // Handle student ID which might be numeric or contain dashes
    if (normalized['MÃ HỌC VIÊN'] !== undefined) {
        normalized['MÃ HỌC VIÊN'] = String(normalized['MÃ HỌC VIÊN']).trim();
    } else if (normalized['SỐ CHỨNG MINH']) {
        normalized['MÃ HỌC VIÊN'] = String(normalized['SỐ CHỨNG MINH']).trim();
    }

    return normalized as StudentRecord;
};

