/**
 * Standardizes strings for robust header matching.
 * Handles Vietnamese Unicode normalization (NFC/NFD), removes non-printable chars, and excessive whitespace.
 */
const simplifyHeader = (str: string): string => {
    return (str || '')
        .toString()
        .normalize('NFC') 
        .replace(/[\u200B-\u200D\uFEFF]/g, '') // Remove zero-width characters
        .trim()
        .toUpperCase()
        .replace(/\s+/g, ' ');
};

/**
 * Removes accents from Vietnamese characters for fallback matching.
 */
const removeAccents = (str: string): string => {
    return str.normalize('NFD')
        .replace(/[\u0300-\u036f]/g, '')
        .replace(/đ/g, 'd')
        .replace(/Đ/g, 'D');
};

export const normalizeRecord = (record: any): StudentRecord => {
    const normalized: any = {};

    // Primary Field Mappings - Expanded with every possible variation
    const keyMap: {[key: string]: string} = {
        'HỌ VÀ TÊN': 'HỌ VÀ TÊN', 'HO VA TEN': 'HỌ VÀ TÊN', 'HỌ TÊN': 'HỌ VÀ TÊN', 'HOTEN': 'HỌ VÀ TÊN',
        'SỐ BÁO DANH': 'SỐ BÁO DANH', 'SBD': 'SỐ BÁO DANH', 'SO BAO DANH': 'SỐ BÁO DANH',
        'MÃ HỌC VIÊN': 'MÃ HỌC VIÊN', 'MA HOC VIEN': 'MÃ HỌC VIÊN', 'MAHV': 'MÃ HỌC VIÊN', 'MÃ HV': 'MÃ HỌC VIÊN',
        'HẠNG GPLX': 'HẠNG GPLX', 'HANG GPLX': 'HẠNG GPLX', 'HẠNG': 'HẠNG GPLX', 'HANG': 'HẠNG GPLX',
        'NỘI DUNG SH': 'NỘI DUNG THI', 'NOI DUNG SH': 'NỘI DUNG THI', 'NDSH': 'NỘI DUNG THI',
        'NỘI DUNG': 'NỘI DUNG THI', 'NOI DUNG': 'NỘI DUNG THI', 'NỘI DUNG THI': 'NỘI DUNG THI', 'ND THI': 'NỘI DUNG THI',
        'LÝ THUYẾT': 'LÝ THUYẾT', 'LT': 'LÝ THUYẾT', 'LY THUYET': 'LÝ THUYẾT',
        'MÔ PHỎNG': 'MÔ PHỎNG', 'MP': 'MÔ PHỎNG', 'MO PHONG': 'MÔ PHỎNG',
        'SA HÌNH': 'SA HÌNH', 'SH': 'SA HÌNH', 'SA HINH': 'SA HÌNH',
        'ĐƯỜNG TRƯỜNG': 'ĐƯỜNG TRƯỜNG', 'DT': 'ĐƯỜNG TRƯỜNG', 'ĐT': 'ĐƯỜNG TRƯỜNG', 'DUONG TRUONG': 'ĐƯỜNG TRƯỜNG',
        'SỐ CHỨNG MINH': 'SỐ CHỨNG MINH', 'SO CHUNG MINH': 'SỐ CHỨNG MINH', 'CCCD': 'SỐ CHỨNG MINH', 'CMND': 'SỐ CHỨNG MINH',
        'NGÀY SINH': 'NGÀY SINH', 'NGAY SINH': 'NGÀY SINH',
        'NƠI CƯ TRÚ': 'NƠI CƯ TRÚ', 'DIA CHI': 'NƠI CƯ TRÚ', 'NOI CU TRU': 'NƠI CƯ TRÚ'
    };

    const rawKeys = Object.keys(record);

    // First pass: Exact mapping after simplification
    rawKeys.forEach(key => {
        const cleanKey = simplifyHeader(key);
        const mappedKey = keyMap[cleanKey];
        if (mappedKey) {
            normalized[mappedKey] = record[key];
        }
    });

    // Second pass: Fuzzy search for missing critical fields
    if (!normalized['NỘI DUNG THI']) {
        const ndKey = rawKeys.find(k => {
            const ck = removeAccents(simplifyHeader(k));
            return ck.includes('NOI DUNG') || ck.includes('NDSH') || ck === 'ND';
        });
        if (ndKey) normalized['NỘI DUNG THI'] = record[ndKey];
    }

    if (!normalized['HỌ VÀ TÊN']) {
        const nameKey = rawKeys.find(k => removeAccents(simplifyHeader(k)).includes('HO TEN'));
        if (nameKey) normalized['HỌ VÀ TÊN'] = record[nameKey];
    }

    if (!normalized['MÃ HỌC VIÊN']) {
        if (normalized['SỐ CHỨNG MINH']) {
            normalized['MÃ HỌC VIÊN'] = normalized['SỐ CHỨNG MINH'];
        } else {
             const idKey = rawKeys.find(k => removeAccents(simplifyHeader(k)).includes('MA HOC VIEN') || removeAccents(simplifyHeader(k)) === 'MAHV');
             if (idKey) normalized['MÃ HỌC VIÊN'] = record[idKey];
        }
    }

    return normalized as StudentRecord;
};

