export const identifyTrainingUnit = (studentId: any, units: TrainingUnit[] = []): string => {
    if (!studentId || !units.length) return '';
    const sId = String(studentId).trim();
    const sortedUnits = [...units].sort((a, b) => b.code.length - a.code.length);
    const matchedUnit = sortedUnits.find(u => sId.includes(u.code));
    return matchedUnit ? matchedUnit.name : '';
};

