 * Loại bỏ dấu, chuyển thành chữ thường, loại bỏ khoảng trắng và ký tự đặc biệt.
 */
const normalizeKeyForMatching = (str: string): string => {
    return (str || '')
        .toString()
        .toLowerCase()
        .normalize('NFD')
        .replace(/[\u0300-\u036f]/g, '') // Loại bỏ dấu
        .replace(/đ/g, 'd')
        .trim()
        .replace(/[^a-z0-9]/g, ''); // Chỉ giữ lại chữ cái và số
};

/**
 * Danh sách từ khóa nhận diện cho từng cột dữ liệu
 */
const COLUMN_KEYWORDS: { [key: string]: string[] } = {
    'SỐ BÁO DANH': ['sbd', 'sobaodanh', 'baodanh'],
    'MÃ HỌC VIÊN': ['mahocvien', 'mahv', 'madk', 'madangky', 'makysh'],
    'HỌ VÀ TÊN': ['hovaten', 'hoten', 'tenhocvien'],
    'SỐ CHỨNG MINH': ['sochungminh', 'cccd', 'cmnd', 'cancuoc', 'chungminh'],
    'NGÀY SINH': ['ngaysinh', 'ns'],
    'NƠI CƯ TRÚ': ['noicutru', 'diachi', 'hktt', 'hokhau'],
    'HẠNG GPLX': ['hanggplx', 'hangxe', 'hang'],
    'NỘI DUNG THI': ['noidung', 'noidungsh', 'ndsh', 'noidungthi', 'nd'],
    'LÝ THUYẾT': ['lythuyet', 'lt', 'kqlt', 'monlt'],
    'MÔ PHỎNG': ['mophong', 'mp', 'kqmp', 'monmp'],
    'SA HÌNH': ['sahinh', 'sh', 'kqsh', 'thtronghinh', 'tronghinh'],
    'ĐƯỜNG TRƯỜNG': ['duongtruong', 'dt', 'kqdt', 'thduongtruong']
};

export const normalizeRecord = (record: any): StudentRecord => {
    const normalized: any = {};
    const rawKeys = Object.keys(record);

    // Quét từng cột trong file Excel
    rawKeys.forEach(rawKey => {
        const normalizedRawKey = normalizeKeyForMatching(rawKey);

        // Tìm xem tiêu đề này khớp với cột chuẩn nào dựa trên từ khóa
        for (const [standardKey, keywords] of Object.entries(COLUMN_KEYWORDS)) {
            // Nếu khớp chính xác từ khóa hoặc tiêu đề chứa từ khóa (như "Nội dung SH" chứa "noidung")
            if (keywords.some(kw => normalizedRawKey === kw || normalizedRawKey.includes(kw))) {
                // Ưu tiên không ghi đè nếu đã tìm thấy cột khớp tốt hơn trước đó
                if (!normalized[standardKey]) {
                    normalized[standardKey] = record[rawKey];
                }
                break;
            }
        }
    });

    // Fallback: Nếu không có mã học viên nhưng có CCCD
    if (!normalized['MÃ HỌC VIÊN'] && normalized['SỐ CHỨNG MINH']) {
        normalized['MÃ HỌC VIÊN'] = normalized['SỐ CHỨNG MINH'];
    }

    return normalized as StudentRecord;
};

