                // Chỉ cập nhật nếu tìm thấy cột khớp tốt hơn hoặc chưa có dữ liệu
                if (!matchScores[standardKey] || score > matchScores[standardKey]) {
                    normalized[standardKey] = record[rawKey];
                    matchScores[standardKey] = score;
                }
            }
        }
    });

    // Fallback logic cho Mã Học Viên (Nếu vẫn trống thì dùng CCCD)
    if (!normalized['MÃ HỌC VIÊN'] && normalized['SỐ CHỨNG MINH']) {
        normalized['MÃ HỌC VIÊN'] = normalized['SỐ CHỨNG MINH'];
    }

