    const retakeData: { [className: string]: LicenseClassData } = {};

    for (const record of records) {
        const className = String(record['HẠNG GPLX'] || '').trim();
        if (!className) continue;

        const maHocVien = String(record['MÃ HỌC VIÊN'] || '').trim();
        const isRetake = maHocVien.includes('2721') || maHocVien.includes('2722');

        const targetData = isRetake ? retakeData : firstTimeData;

        if (!targetData[className]) {
            targetData[className] = createNewClassData(className);
        }
        const classData = targetData[className];
        classData.totalApplications += 1;

        if (!isStudentAbsent(record)) {
            classData.totalParticipants += 1;
        }

        const theoryRes = getResultStatus(record['LÝ THUYẾT']);
        if (theoryRes.participated) {
            classData.theory.total += 1;
            if (theoryRes.passed) classData.theory.pass += 1;
        }

        const simRes = getResultStatus(record['MÔ PHỎNG']);
        if (simRes.participated) {
            classData.simulation.total += 1;
            if (simRes.passed) classData.simulation.pass += 1;
        }

        const practicalRes = getResultStatus(record['SA HÌNH']);
        if (practicalRes.participated) {
            classData.practicalCourse.total += 1;
            if (practicalRes.passed) classData.practicalCourse.pass += 1;
        }

        const onRoadRes = getResultStatus(record['ĐƯỜNG TRƯỜNG']);
        if (onRoadRes.participated) {
            classData.onRoad.total += 1;
            if (onRoadRes.passed) classData.onRoad.pass += 1;
        }

        if (isStudentPassed(record)) {
            classData.finalPass += 1;
        }
    }

    const finalizeData = (data: { [className: string]: LicenseClassData }): LicenseClassData[] => {
        const classDataArray = Object.values(data);
        for (const classData of classDataArray) {
            classData.theory.fail = Math.max(0, classData.theory.total - classData.theory.pass);
            classData.simulation.fail = Math.max(0, classData.simulation.total - classData.simulation.pass);
            classData.practicalCourse.fail = Math.max(0, classData.practicalCourse.total - classData.practicalCourse.pass);
            classData.onRoad.fail = Math.max(0, classData.onRoad.total - classRoad.onRoad.pass);
        }
        return classDataArray.sort((a, b) => a.class.localeCompare(b.class));
    };

    return {
        firstTime: { title: 'a) Học viên dự thi lần đầu:', rows: finalizeData(firstTimeData) },
        retake: { title: 'b) Thí sinh thuộc đối tượng cấp lại giấy phép lái xe và thí sinh tự do:', rows: finalizeData(retakeData) }
    };
};

import React, { useState, useEffect } from 'react';
import { ExcelUploadSection } from './ExcelUploadSection';
import { StudentDataPreviewTable } from './StudentDataPreviewTable';
import type { StudentRecord, ReportMetadata, SavedSession } from '../types';
import { ReportMetadataModal } from './ReportMetadataModal';
import { storageService } from '../services/storageService';
import { normalizeData } from '../services/excelProcessor';

interface PassDetail {
    date: string;
    session: string;
    isImplicit: boolean; // True if assumed passed because it was missing in first registration
}

interface DataInputPageProps {
    onExcelSubmit: (studentRecords: StudentRecord[]) => void;
    onClearData: () => void;
    isLoading: boolean;
    error: string | null;
    reportMetadata: ReportMetadata;
    onMetadataChange: (metadata: ReportMetadata) => void;
}

export const DataInputPage: React.FC<DataInputPageProps> = ({ 
    onExcelSubmit, 
    onClearData,
    isLoading: parentIsLoading, 
    error,
    reportMetadata,
    onMetadataChange
}) => {
    const [isMetadataModalOpen, setIsMetadataModalOpen] = useState(false);
    const [previewData, setPreviewData] = useState<StudentRecord[] | null>(null);
    const [isValidating, setIsValidating] = useState(false);

    const validateWithHistory = async (rawRecords: any[]) => {
        setIsValidating(true);
        try {
            // Bước quan trọng: Chuẩn hóa dữ liệu ngay khi vừa nạp từ Excel
            const normalizedRecords = normalizeData(rawRecords);

            const pastSessions = await storageService.getAllSessions();

            // Map<StudentId, Map<SubjectCode, PassDetail>>
            const passMap = new Map<string, Map<string, PassDetail>>();

            // 1. Group records by student and sort sessions by date to find the "First Appearance"
            const studentHistory = new Map<string, { record: StudentRecord, sessionName: string, date: Date }[]>();

            pastSessions.forEach(session => {
                const date = new Date(session.reportDate);
                session.studentRecords.forEach(record => {
                    const studentId = String(record['MÃ HỌC VIÊN']).trim();
                    if (!studentId) return;
                    if (!studentHistory.has(studentId)) studentHistory.set(studentId, []);
                    studentHistory.get(studentId)!.push({ record, sessionName: session.name, date });
                });
            });

            // 2. Process each student's history chronologically
            studentHistory.forEach((history, studentId) => {
                // Sort by date ascending
                history.sort((a, b) => a.date.getTime() - b.date.getTime());

                const studentPasses = new Map<string, PassDetail>();
                const firstEntry = history[0];
                const firstContent = (firstEntry.record['NỘI DUNG THI'] || '').toUpperCase().replace(/Đ/g, 'D');
                const firstDateStr = firstEntry.date.toLocaleDateString('vi-VN');

                // A. Implicit Pass Logic: 
                // In the first appearance, any subject NOT in NỘI DUNG THI is assumed "Already Passed"
                const allSubjectCodes = ['L', 'M', 'H', 'D'];
                allSubjectCodes.forEach(code => {
                    if (!firstContent.includes(code)) {
                        studentPasses.set(code, { 
                            date: firstDateStr, 
                            session: firstEntry.sessionName, 
                            isImplicit: true 
                        });
                    }
                });

                // B. Explicit Pass Logic:
                // Scan all history (including the first one) for 'ĐẠT' scores
                history.forEach(h => {
                    const dStr = h.date.toLocaleDateString('vi-VN');
                    if (String(h.record['LÝ THUYẾT'] || '').toUpperCase().trim() === 'ĐẠT') 
                        studentPasses.set('L', { date: dStr, session: h.sessionName, isImplicit: false });
                    if (String(h.record['MÔ PHỎNG'] || '').toUpperCase().trim() === 'ĐẠT') 
                        studentPasses.set('M', { date: dStr, session: h.sessionName, isImplicit: false });
                    if (String(h.record['SA HÌNH'] || '').toUpperCase().trim() === 'ĐẠT') 
                        studentPasses.set('H', { date: dStr, session: h.sessionName, isImplicit: false });
                    if (String(h.record['ĐƯỜNG TRƯỜNG'] || '').toUpperCase().trim() === 'ĐẠT') 
                        studentPasses.set('D', { date: dStr, session: h.sessionName, isImplicit: false });
                });

                passMap.set(studentId, studentPasses);
            });

            // 3. Enrich new records with warnings based on the passMap
            const subjectLabels: Record<string, string> = { 'L': 'Lý thuyết', 'M': 'Mô phỏng', 'H': 'Sa hình', 'D': 'Đường trường' };

            const enrichedRecords = normalizedRecords.map(record => {
                const studentId = String(record['MÃ HỌC VIÊN']).trim();
                const content = (record['NỘI DUNG THI'] || '').toUpperCase().replace(/Đ/g, 'D');
                const warnings: string[] = [];

                if (passMap.has(studentId)) {
                    const history = passMap.get(studentId)!;

                    ['L', 'M', 'H', 'D'].forEach(code => {
                        if (content.includes(code) && history.has(code)) {
                            const h = history.get(code)!;
                            const label = subjectLabels[code];
                            if (h.isImplicit) {
                                warnings.push(`Sai nội dung: Mặc định đạt ${label} từ kỳ đầu (${h.date})`);
                            } else {
                                warnings.push(`Sai nội dung: Đã đạt ${label} tại kỳ (${h.session} - ${h.date})`);
                            }
                        }
                    });
                }

                return { ...record, _historyWarnings: warnings.length > 0 ? warnings : undefined };
            });

            setPreviewData(enrichedRecords);
        } catch (err) {
            console.error("Validation error:", err);
            setPreviewData(rawRecords);
        } finally {
            setIsValidating(false);
        }
    };

    const handleUpload = (data: any[]) => {
        validateWithHistory(data);
    };

    const handleConfirm = () => {
        if (previewData) {
            onExcelSubmit(previewData);
            setPreviewData(null);
        }
    };

    const handleCancelPreview = () => {
        setPreviewData(null);
        onClearData();
    };

    return (
        <div className="flex flex-col h-full bg-white dark:bg-gray-800">
            <header className="p-4 border-b dark:border-gray-700 space-y-3">
                 <div className="flex justify-between items-start">
                    <div>
                         <h1 className="text-xl font-bold text-gray-800 dark:text-white">
                             {previewData ? 'Xác nhận Dữ liệu' : 'Bảng Điều Khiển'}
                         </h1>
                         <p className="mt-1 text-sm text-gray-600 dark:text-gray-400">
                             {previewData 
                                ? (isValidating ? 'Đang đối chiếu lịch sử sát hạch...' : 'Vui lòng kiểm tra kỹ nội dung thi và cảnh báo lịch sử.') 
                                : 'Nhập dữ liệu Excel học viên để tạo báo cáo.'}
                         </p>
                    </div>
                    <div className="flex items-center gap-2 flex-shrink-0">
                        <button
                            onClick={() => setIsMetadataModalOpen(true)}
                            className="px-4 py-2 bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-200 rounded-md hover:bg-gray-300 dark:hover:bg-gray-600 transition-colors flex items-center gap-2 font-semibold text-sm"
                        >
                            <i className="fa-solid fa-file-invoice"></i> Biên bản
                        </button>
                        {!previewData && (
                            <button
                                onClick={onClearData}
                                className="px-4 py-2 bg-green-600 text-white rounded-md hover:bg-green-700 transition-colors flex items-center gap-2 font-semibold text-sm"
                            >
                                <i className="fa-solid fa-rotate"></i> Làm mới
                            </button>
                        )}
                    </div>
                 </div>
            </header>
            <main className="flex-1 overflow-y-auto bg-gray-50 dark:bg-gray-900 p-6 space-y-6">

                {!previewData ? (
                    <div className="bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700 animate-fade-in">
                         <ExcelUploadSection onSubmit={handleUpload} isLoading={parentIsLoading || isValidating} error={error} />
                    </div>
                ) : (
                    <div className="relative">
                        {isValidating && (
                            <div className="absolute inset-0 bg-white/50 dark:bg-gray-900/50 z-30 flex items-center justify-center backdrop-blur-sm rounded-lg">
                                <div className="flex flex-col items-center gap-2">
                                    <i className="fa-solid fa-spinner animate-spin text-3xl text-blue-600"></i>
                                    <span className="font-bold text-gray-700 dark:text-gray-200">Đang đối soát lịch sử...</span>
                                </div>
                            </div>
                        )}
                        <StudentDataPreviewTable 
                            data={previewData} 
                            onConfirm={handleConfirm} 
                            onCancel={handleCancelPreview} 
                        />
                    </div>
                )}

            </main>
            {isMetadataModalOpen && (
                <ReportMetadataModal
                    initialMetadata={reportMetadata}
                    onSave={onMetadataChange}
                    onClose={() => setIsMetadataModalOpen(false)}
                />
            )}
        </div>
    );
};

import type { AppData, LicenseClassData, StudentRecord } from '../types';
import { getResultStatus, isStudentAbsent, isStudentPassed } from './reportUtils';

/**
 * Chuẩn hóa chuỗi tiêu đề để so khớp: 
 * Loại bỏ dấu, chuyển thành chữ thường, loại bỏ khoảng trắng và ký tự đặc biệt.
 */
const normalizeKeyForMatching = (str: string): string => {
    return (str || '')
        .toString()
        .toLowerCase()
        .normalize('NFD')
        .replace(/[\u0300-\u036f]/g, '') // Loại bỏ dấu
        .replace(/đ/g, 'd')
        .trim()
        .replace(/[^a-z0-9]/g, ''); // Chỉ giữ lại chữ cái và số
};

/**
 * Danh sách từ khóa nhận diện cho từng cột dữ liệu.
 * Các từ khóa được sắp xếp theo thứ tự ưu tiên.
 */
const COLUMN_KEYWORDS: { [key: string]: string[] } = {
    'SỐ BÁO DANH': ['sbd', 'sobaodanh', 'baodanh'],
    'MÃ HỌC VIÊN': ['mahocvien', 'mahv', 'madk', 'madangky', 'makysh'],
    'HỌ VÀ TÊN': ['hovaten', 'hoten', 'tenhocvien'],
    'SỐ CHỨNG MINH': ['sochungminh', 'cccd', 'cmnd', 'cancuoc', 'chungminh'],
    'NGÀY SINH': ['ngaysinh', 'ns'],
    'NƠI CƯ TRÚ': ['noicutru', 'diachi', 'hktt', 'hokhau'],
    'HẠNG GPLX': ['hanggplx', 'hangxe', 'hang'],
    'NỘI DUNG THI': ['noidung', 'noidungsh', 'ndsh', 'noidungthi', 'nd'],
    'LÝ THUYẾT': ['lythuyet', 'lt', 'kqlt', 'monlt'],
    'MÔ PHỎNG': ['mophong', 'mp', 'kqmp', 'monmp'],
    'SA HÌNH': ['sahinh', 'sh', 'kqsh', 'thtronghinh', 'tronghinh'],
    'ĐƯỜNG TRƯỜNG': ['duongtruong', 'dt', 'kqdt', 'thduongtruong']
};

export const normalizeRecord = (record: any): StudentRecord => {
    const normalized: any = {};
    const rawKeys = Object.keys(record);

    // Tạo bản đồ để lưu mức độ khớp tốt nhất cho từng standardKey
    // 0: Không khớp, 1: Khớp một phần (includes), 2: Khớp chính xác (exact)
    const matchScores: { [key: string]: number } = {};

    rawKeys.forEach(rawKey => {
        const normalizedRawKey = normalizeKeyForMatching(rawKey);

        for (const [standardKey, keywords] of Object.entries(COLUMN_KEYWORDS)) {
            let score = 0;
            if (keywords.some(kw => normalizedRawKey === kw)) {
                score = 2; // Khớp chính xác
            } else if (keywords.some(kw => normalizedRawKey.includes(kw))) {
                score = 1; // Khớp một phần
            }

            if (score > 0) {
                // Chỉ cập nhật nếu tìm thấy cột khớp tốt hơn hoặc chưa có dữ liệu
                if (!matchScores[standardKey] || score > matchScores[standardKey]) {
                    normalized[standardKey] = record[rawKey];
                    matchScores[standardKey] = score;
                }
            }
        }
    });

    // Fallback logic cho Mã Học Viên (Nếu vẫn trống thì dùng CCCD)
    if (!normalized['MÃ HỌC VIÊN'] && normalized['SỐ CHỨNG MINH']) {
        normalized['MÃ HỌC VIÊN'] = normalized['SỐ CHỨNG MINH'];
    }

    return normalized as StudentRecord;
};

const createNewClassData = (className: string): LicenseClassData => ({
    class: className,
    totalApplications: 0,
    totalParticipants: 0,
    theory: { total: 0, pass: 0, fail: 0 },
    simulation: { total: 0, pass: 0, fail: 0 },
    practicalCourse: { total: 0, pass: 0, fail: 0 },
    onRoad: { total: 0, pass: 0, fail: 0 },
    finalPass: 0,
});

export const normalizeData = (rawRecords: any[]): StudentRecord[] => {
    return rawRecords.map(raw => {
        const record = normalizeRecord(raw);

        // Chuẩn hóa nội dung thi (L, M, H, D)
        let content = String(record['NỘI DUNG THI'] || '').trim().toUpperCase();
        content = content.replace(/Đ/g, 'D'); 
        record['NỘI DUNG THI'] = content;

        // Nếu cột nội dung vẫn trống, tự động suy luận từ các cột điểm
        if (!record['NỘI DUNG THI']) {
             const parts: string[] = [];
             if (getResultStatus(record['LÝ THUYẾT']).participated) parts.push('L');
             if (getResultStatus(record['MÔ PHỎNG']).participated) parts.push('M');
             if (getResultStatus(record['SA HÌNH']).participated) parts.push('H');
             if (getResultStatus(record['ĐƯỜNG TRƯỜNG']).participated) parts.push('D');
             record['NỘI DUNG THI'] = parts.join('');
        }

        return record;
    });
};

export const processExcelData = (rawRecords: StudentRecord[]): AppData => {
    const records = normalizeData(rawRecords);
    const firstTimeData: { [className: string]: LicenseClassData } = {};
    const retakeData: { [className: string]: LicenseClassData } = {};

    for (const record of records) {
        const className = String(record['HẠNG GPLX'] || '').trim();
        if (!className) continue;

        const maHocVien = String(record['MÃ HỌC VIÊN'] || '').trim();
        const isRetake = maHocVien.includes('2721') || maHocVien.includes('2722');

        const targetData = isRetake ? retakeData : firstTimeData;

        if (!targetData[className]) {
            targetData[className] = createNewClassData(className);
        }
        const classData = targetData[className];
        classData.totalApplications += 1;

        if (!isStudentAbsent(record)) {
            classData.totalParticipants += 1;
        }

        const theoryRes = getResultStatus(record['LÝ THUYẾT']);
        if (theoryRes.participated) {
            classData.theory.total += 1;
            if (theoryRes.passed) classData.theory.pass += 1;
        }

        const simRes = getResultStatus(record['MÔ PHỎNG']);
        if (simRes.participated) {
            classData.simulation.total += 1;
            if (simRes.passed) classData.simulation.pass += 1;
        }

        const practicalRes = getResultStatus(record['SA HÌNH']);
        if (practicalRes.participated) {
            classData.practicalCourse.total += 1;
            if (practicalRes.passed) classData.practicalCourse.pass += 1;
        }

        const onRoadRes = getResultStatus(record['ĐƯỜNG TRƯỜNG']);
        if (onRoadRes.participated) {
            classData.onRoad.total += 1;
            if (onRoadRes.passed) classData.onRoad.pass += 1;
        }

        if (isStudentPassed(record)) {
            classData.finalPass += 1;
        }
    }

    const finalizeData = (data: { [className: string]: LicenseClassData }): LicenseClassData[] => {
        const classDataArray = Object.values(data);
        for (const classData of classDataArray) {
            classData.theory.fail = Math.max(0, classData.theory.total - classData.theory.pass);
            classData.simulation.fail = Math.max(0, classData.simulation.total - classData.simulation.pass);
            classData.practicalCourse.fail = Math.max(0, classData.practicalCourse.total - classData.practicalCourse.pass);
            // Fix typo here: classRoad was used instead of classData
            classData.onRoad.fail = Math.max(0, classData.onRoad.total - classData.onRoad.pass);
        }
        return classDataArray.sort((a, b) => a.class.localeCompare(b.class));
    };

    return {
        firstTime: { title: 'a) Học viên dự thi lần đầu:', rows: finalizeData(firstTimeData) },
        retake: { title: 'b) Thí sinh thuộc đối tượng cấp lại giấy phép lái xe và thí sinh tự do:', rows: finalizeData(retakeData) }
    };
};

