                { key: 'LÝ THUYẾT', code: 'L' },
                { key: 'MÔ PHỎNG', code: 'M' },
                { key: 'SA HÌNH', code: 'H' },
                { key: 'ĐƯỜNG TRƯỜNG', code: 'D' }
             ];

             scoreColumns.forEach(col => {
                const val = String(record[col.key] || '').trim().toUpperCase();
                // Nếu ô điểm không trống (có thể là Đạt, Trượt, Vắng, hoặc điểm số)
                if (val !== '' && val !== 'UNDEFINED' && val !== 'NULL') {
                    parts.push(col.code);
                }
             });

             record['NỘI DUNG THI'] = parts.join('');
        }

        return record;
    });
};

export const processExcelData = (rawRecords: StudentRecord[]): AppData => {
    const records = normalizeData(rawRecords);
    const firstTimeData: { [className: string]: LicenseClassData } = {};
    const retakeData: { [className: string]: LicenseClassData } = {};

    for (const record of records) {
        const className = String(record['HẠNG GPLX'] || '').trim();
        if (!className) continue;

        const maHocVien = String(record['MÃ HỌC VIÊN'] || '').trim();
        const isRetake = maHocVien.includes('2721') || maHocVien.includes('2722');

        const targetData = isRetake ? retakeData : firstTimeData;

        if (!targetData[className]) {
            targetData[className] = createNewClassData(className);
        }
        const classData = targetData[className];
        classData.totalApplications += 1;

        if (!isStudentAbsent(record)) {
            classData.totalParticipants += 1;
        }

        const theoryRes = getResultStatus(record['LÝ THUYẾT']);
        if (theoryRes.participated) {
            classData.theory.total += 1;
            if (theoryRes.passed) classData.theory.pass += 1;
        }

        const simRes = getResultStatus(record['MÔ PHỎNG']);
        if (simRes.participated) {
            classData.simulation.total += 1;
            if (simRes.passed) classData.simulation.pass += 1;
        }

        const practicalRes = getResultStatus(record['SA HÌNH']);
        if (practicalRes.participated) {
            classData.practicalCourse.total += 1;
            if (practicalRes.passed) classData.practicalCourse.pass += 1;
        }

        const onRoadRes = getResultStatus(record['ĐƯỜNG TRƯỜNG']);
        if (onRoadRes.participated) {
            classData.onRoad.total += 1;
            if (onRoadRes.passed) classData.onRoad.pass += 1;
        }

        if (isStudentPassed(record)) {
            classData.finalPass += 1;
        }
    }

    const finalizeData = (data: { [className: string]: LicenseClassData }): LicenseClassData[] => {
        const classDataArray = Object.values(data);
        for (const classData of classDataArray) {
            classData.theory.fail = Math.max(0, classData.theory.total - classData.theory.pass);
            classData.simulation.fail = Math.max(0, classData.simulation.total - classData.simulation.pass);
            classData.practicalCourse.fail = Math.max(0, classData.practicalCourse.total - classData.practicalCourse.pass);
            classData.onRoad.fail = Math.max(0, classData.onRoad.total - classData.onRoad.pass);
        }
        return classDataArray.sort((a, b) => a.class.localeCompare(b.class));
    };

    return {
        firstTime: { title: 'a) Học viên dự thi lần đầu:', rows: finalizeData(firstTimeData) },
        retake: { title: 'b) Thí sinh thuộc đối tượng cấp lại giấy phép lái xe và thí sinh tự do:', rows: finalizeData(retakeData) }
    };
};

import type { StudentRecord, TrainingUnit } from '../types';

// Helper to check result status, handles 'Đạt', 'Không đạt', 'Vắng'
export const getResultStatus = (result: any): { participated: boolean, passed: boolean } => {
    if (result === undefined || result === null) {
        return { participated: false, passed: false };
    }

    const val = String(result).trim().toUpperCase().normalize('NFC');

    // Nếu rỗng hoặc có chữ Vắng -> Không tham gia thi
    if (val === '' || val === 'VẮNG' || val === 'V' || val.includes('VANG')) {
        return { participated: false, passed: false };
    }

    // Kiểm tra "Đạt" (không bao gồm "Không đạt") hoặc điểm số >= 5 (tạm thời) hoặc chữ D (trong file một số phần mềm)
    const isPass = (val.includes('ĐẠT') || val === 'D' || val === 'DAT' || val === 'PASSED') && !val.includes('KHÔNG');

    return { participated: true, passed: isPass };
};

// Check if a student is considered absent (took no tests).
export const isStudentAbsent = (record: StudentRecord): boolean => {
    const theory = getResultStatus(record['LÝ THUYẾT']);
    const simulation = getResultStatus(record['MÔ PHỎNG']);
    const practical = getResultStatus(record['SA HÌNH']);
    const onRoad = getResultStatus(record['ĐƯỜNG TRƯỜNG']);
    return !theory.participated && !simulation.participated && !practical.participated && !onRoad.participated;
};

// Check if a student passed, based on their required tests.
export const isStudentPassed = (record: StudentRecord): boolean => {
    if (isStudentAbsent(record)) return false;

    let noiDungThi = String(record['NỘI DUNG THI'] || '').trim().toUpperCase();
    noiDungThi = noiDungThi.replace(/Đ/g, 'D');

    // Nếu không có nội dung thi, ta không thể xác định thí sinh có đạt hay không theo quy chuẩn
    if (!noiDungThi || noiDungThi === '') return false;

    const subjects = {
        L: getResultStatus(record['LÝ THUYẾT']).passed,
        M: getResultStatus(record['MÔ PHỎNG']).passed,
        H: getResultStatus(record['SA HÌNH']).passed,
        D: getResultStatus(record['ĐƯỜNG TRƯỜNG']).passed
    };

    // Kiểm tra logic: Những môn có trong mã nội dung thi thì phải đạt
    const requiredTests: boolean[] = [];
    if (noiDungThi.includes('L')) requiredTests.push(subjects.L);
    if (noiDungThi.includes('M')) requiredTests.push(subjects.M);
    if (noiDungThi.includes('H')) requiredTests.push(subjects.H);
    if (noiDungThi.includes('D')) requiredTests.push(subjects.D);

    if (requiredTests.length === 0) return false;

    return requiredTests.every(result => result === true);
};

export const generateClassSummaryString = (students: StudentRecord[]): string => {
    if (!students || students.length === 0) return "Tổng số: 0";

    const classCounts: { [key: string]: number } = {};
    for (const student of students) {
        const className = String(student['HẠNG GPLX'] || 'Khác').trim();
        classCounts[className] = (classCounts[className] || 0) + 1;
    }

    const parts = Object.keys(classCounts).sort().map(cls => `Hạng ${cls}: ${classCounts[cls]}`);
    return `Tổng số: ${students.length}\u00A0\u00A0\u00A0\u00A0${parts.join('; ')}`;
};

export const generateGhiChu = (record: StudentRecord): string => {
    const maHocVien = String(record['MÃ HỌC VIÊN'] || '').trim();
    const isRetake = maHocVien.includes('2721') || maHocVien.includes('2722');
    let content = String(record['NỘI DUNG THI'] || '').trim().toUpperCase().replace(/D/g, 'Đ');

    if (isRetake) return `Thi lại nội dung: ${content}`;
    return `Thi lần đầu`;
};

export const identifyTrainingUnit = (studentId: any, units: TrainingUnit[] = []): string => {
    if (!studentId || !units.length) return '';
    const sId = String(studentId).trim();
    const sortedUnits = [...units].sort((a, b) => b.code.length - a.code.length);
    const matchedUnit = sortedUnits.find(u => sId.includes(u.code));
    return matchedUnit ? matchedUnit.name : '';
};

