import React, { useState, useEffect } from 'react';
import type { TrainingUnit } from '../../types';
import { storageService } from '../../services/storageService';
import { normalizeKeyForMatching } from '../../services/excelProcessor';

declare const XLSX: any;

interface TrainingUnitManagerProps {
    trainingUnits: TrainingUnit[];
    onUnitsImport: (units: TrainingUnit[]) => void;
}

export const TrainingUnitManager: React.FC<TrainingUnitManagerProps> = ({ trainingUnits, onUnitsImport }) => {
    const [unitUploadError, setUnitUploadError] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState(false);

    // Modal State
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingUnit, setEditingUnit] = useState<TrainingUnit | null>(null);
    const [formData, setFormData] = useState({ code: '', name: '' });

    // Refresh data on mount to ensure we have the latest from DB
    useEffect(() => {
        const loadUnits = async () => {
            try {
                const units = await storageService.getAllTrainingUnits();
                onUnitsImport(units);
            } catch (error) {
                console.error("Failed to load units on mount", error);
            }
        };
        loadUnits();
    }, []);

    const handleUnitFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        setUnitUploadError(null);
        if (e.target.files && e.target.files[0]) {
            setIsLoading(true);
            const file = e.target.files[0];
            const reader = new FileReader();
            reader.onload = async (event) => {
                try {
                    const data = new Uint8Array(event.target!.result as ArrayBuffer);
                    const workbook = XLSX.read(data, { type: 'array' });
                    const sheetName = workbook.SheetNames[0];
                    const worksheet = workbook.Sheets[sheetName];
                    const json: any[] = XLSX.utils.sheet_to_json(worksheet);

                    const newUnits: TrainingUnit[] = [];

                    // Danh sách từ khóa nhận diện
                    const CODE_KEYWORDS = ['madv', 'code', 'madonvi', 'ma'];
                    const NAME_KEYWORDS = ['tendv', 'name', 'tendonvi', 'ten'];

                    json.forEach((row, index) => {
                        const rowKeys = Object.keys(row);
                        let unitCode: string | null = null;
                        let unitName: string | null = null;

                        // Duyệt qua từng key của row để tìm cột khớp nhất
                        rowKeys.forEach(key => {
                            const normalizedKey = normalizeKeyForMatching(key);

                            if (!unitCode && CODE_KEYWORDS.some(kw => normalizedKey.includes(kw))) {
                                unitCode = String(row[key]).trim();
                            }
                            if (!unitName && NAME_KEYWORDS.some(kw => normalizedKey.includes(kw))) {
                                unitName = String(row[key]).trim();
                            }
                        });

                        if (unitCode && unitName) {
                            const stableId = `unit-${unitCode}`; 
                            newUnits.push({
                                id: stableId,
                                code: unitCode,
                                name: unitName
                            });
                        }
                    });

                    if (newUnits.length === 0) {
                        setUnitUploadError("Không tìm thấy dữ liệu hợp lệ (Cần cột có tên 'MaDv' và 'TenDV')");
                    } else {
                        // Persist to Storage
                        await storageService.importTrainingUnits(newUnits);
                        // Refresh parent
                        const refreshedUnits = await storageService.getAllTrainingUnits();
                        onUnitsImport(refreshedUnits);
                        alert(`Đã nhận diện và cập nhật thành công ${newUnits.length} đơn vị!`);
                    }
                } catch (err) {
                    setUnitUploadError("Lỗi đọc file Excel hoặc lỗi lưu server");
                    console.error("Error processing Unit Excel:", err);
                } finally {
                    setIsLoading(false);
                    e.target.value = '';
                }
            };
            reader.readAsArrayBuffer(file);
        }
    };

    const downloadUnitSample = () => {
        const sampleData = [
            { 'MaDv': '2721', 'TenDV': 'Trung tâm Đông Đô' },
            { 'MaDv': '2722', 'TenDV': 'Trung tâm Âu Lạc' },
            { 'MaDv': '24001', 'TenDV': 'Trường Trung cấp 1' }
        ];
        const worksheet = XLSX.utils.json_to_sheet(sampleData);
        const workbook = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(workbook, worksheet, "DonViDaoTao");
        XLSX.writeFile(workbook, "Mau_Don_Vi_Dao_Tao.xlsx");
    };

    // CRUD Handlers
    const handleAddClick = () => {
        setEditingUnit(null);
        setFormData({ code: '', name: '' });
        setIsModalOpen(true);
    };

    const handleEditClick = (unit: TrainingUnit) => {
        setEditingUnit(unit);
        setFormData({ code: unit.code, name: unit.name });
        setIsModalOpen(true);
    };

    const handleDeleteClick = async (id: string) => {
        if (window.confirm('Bạn có chắc chắn muốn xóa đơn vị này không?')) {
            setIsLoading(true);
            try {
                await storageService.deleteTrainingUnit(id);
                const refreshedUnits = await storageService.getAllTrainingUnits();
                onUnitsImport(refreshedUnits);
            } catch (error) {
                alert('Có lỗi xảy ra khi xóa!');
            } finally {
                setIsLoading(false);
            }
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.code || !formData.name) return;

        setIsLoading(true);
        try {
            const unitToSave: TrainingUnit = {
                id: editingUnit ? editingUnit.id : `unit-${formData.code.trim()}`,
                code: formData.code.trim(),
                name: formData.name.trim()
            };

            await storageService.saveTrainingUnit(unitToSave);
            const refreshedUnits = await storageService.getAllTrainingUnits();
            onUnitsImport(refreshedUnits);
            setIsModalOpen(false);
        } catch (error) {
            alert('Lỗi khi lưu dữ liệu!');
            console.error(error);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="p-6 md:p-10 h-full overflow-y-auto bg-gray-100 dark:bg-gray-900 transition-colors">
            <div className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-4">
                <div>
                    <h2 className="text-2xl font-bold text-gray-800 dark:text-white">Đơn vị Đào tạo</h2>
                    <p className="text-gray-500 dark:text-gray-400 mt-1">Quản lý danh sách các đơn vị đào tạo lái xe để tự động nhận diện thí sinh.</p>
                </div>
                <div className="flex gap-2">
                    <button 
                        onClick={handleAddClick}
                        className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 shadow-sm transition-colors flex items-center gap-2 font-bold"
                    >
                        <i className="fa-solid fa-plus"></i> Thêm Mới
                    </button>
                    <button 
                        onClick={downloadUnitSample}
                        className="px-4 py-2 bg-white dark:bg-gray-800 border border-blue-200 dark:border-blue-800 text-blue-600 dark:text-blue-400 rounded-lg hover:bg-blue-50 dark:hover:bg-blue-900/30 shadow-sm transition-colors flex items-center gap-2 font-medium"
                    >
                        <i className="fa-solid fa-download"></i> Tải file mẫu
                    </button>
                </div>
            </div>

            <div className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 overflow-hidden">
                <div className="p-6 border-b border-gray-100 dark:border-gray-700 bg-gray-50 dark:bg-gray-750">
                    <label className="block text-sm font-bold text-gray-700 dark:text-gray-200 mb-2">
                        <i className="fa-solid fa-file-import mr-2"></i>Nhập nhanh từ Excel (Hỗ trợ tiêu đề MaDv, TenDV)
                    </label>
                    <div className="flex gap-4">
                        <input 
                            type="file" 
                            accept=".xlsx, .xls"
                            onChange={handleUnitFileChange}
                            disabled={isLoading}
                            className="block w-full text-sm text-gray-500 dark:text-gray-400 file:mr-4 file:py-2.5 file:px-4 file:rounded-lg file:border-0 file:text-sm file:font-semibold file:bg-teal-600 file:text-white hover:file:bg-teal-700 cursor-pointer bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-lg disabled:opacity-50" 
                        />
