            )}
        </div>
    );
};

import type { AppData, LicenseClassData, StudentRecord } from '../types';
import { getResultStatus, isStudentAbsent, isStudentPassed } from './reportUtils';

/**
 * Chuẩn hóa chuỗi tiêu đề để so khớp: 
 * Loại bỏ dấu, chuyển thành chữ thường, loại bỏ khoảng trắng và ký tự đặc biệt.
 */
export const normalizeKeyForMatching = (str: string): string => {
    return (str || '')
        .toString()
        .toLowerCase()
        .normalize('NFD')
        .replace(/[\u0300-\u036f]/g, '') // Loại bỏ dấu
        .replace(/đ/g, 'd')
        .trim()
        .replace(/[^a-z0-9]/g, ''); // Chỉ giữ lại chữ cái và số
};

/**
 * Danh sách từ khóa nhận diện cho từng cột dữ liệu.
 */
const COLUMN_KEYWORDS: { [key: string]: string[] } = {
    'SỐ BÁO DANH': ['sbd', 'sobaodanh', 'baodanh', 'sobd'],
    'MÃ HỌC VIÊN': ['mahocvien', 'mahv', 'madk', 'madangky', 'makysh'],
    'HỌ VÀ TÊN': ['hovaten', 'hoten', 'tenhocvien', 'tenhv'],
    'SỐ CHỨNG MINH': ['sochungminh', 'cccd', 'cmnd', 'cancuoc', 'chungminh', 'socmnd'],
    'NGÀY SINH': ['ngaysinh', 'ns', 'ngays'],
    'NƠI CƯ TRÚ': ['noicutru', 'diachi', 'hktt', 'hokhau', 'noio'],
    'HẠNG GPLX': ['hanggplx', 'hangxe', 'hang', 'hangdk'],
    'NỘI DUNG THI': ['noidung', 'noidungsh', 'ndsh', 'noidungthi', 'nd', 'noidungdk'],
    'LÝ THUYẾT': ['lythuyet', 'lt', 'kqlt', 'monlt'],
    'MÔ PHỎNG': ['mophong', 'mp', 'kqmp', 'monmp'],
    'SA HÌNH': ['sahinh', 'sh', 'kqsh', 'thtronghinh', 'tronghinh'],
    'ĐƯỜNG TRƯỜNG': ['duongtruong', 'dt', 'kqdt', 'thduongtruong']
};

export const normalizeRecord = (record: any): StudentRecord => {
    const normalized: any = {};
    const rawKeys = Object.keys(record);

    const matchScores: { [key: string]: number } = {};

    rawKeys.forEach(rawKey => {
        const normalizedRawKey = normalizeKeyForMatching(rawKey);

        for (const [standardKey, keywords] of Object.entries(COLUMN_KEYWORDS)) {
            let score = 0;
            if (keywords.some(kw => normalizedRawKey === kw)) {
                score = 2; // Khớp chính xác hoàn toàn
            } else if (keywords.some(kw => normalizedRawKey.includes(kw))) {
                score = 1; // Khớp một phần
            }

            if (score > 0) {
                if (!matchScores[standardKey] || score > matchScores[standardKey]) {
                    normalized[standardKey] = record[rawKey];
                    matchScores[standardKey] = score;
                }
            }
        }
    });

    if (!normalized['MÃ HỌC VIÊN'] && normalized['SỐ CHỨNG MINH']) {
        normalized['MÃ HỌC VIÊN'] = normalized['SỐ CHỨNG MINH'];
    }

    return normalized as StudentRecord;
};

const createNewClassData = (className: string): LicenseClassData => ({
    class: className,
    totalApplications: 0,
    totalParticipants: 0,
    theory: { total: 0, pass: 0, fail: 0 },
    simulation: { total: 0, pass: 0, fail: 0 },
    practicalCourse: { total: 0, pass: 0, fail: 0 },
    onRoad: { total: 0, pass: 0, fail: 0 },
    finalPass: 0,
});

export const normalizeData = (rawRecords: any[]): StudentRecord[] => {
    return rawRecords.map(raw => {
        const record = normalizeRecord(raw);

        // Chuẩn hóa nội dung thi hiện có
        let content = String(record['NỘI DUNG THI'] || '').trim().toUpperCase();
        content = content.replace(/Đ/g, 'D'); 
        record['NỘI DUNG THI'] = content;

        // NGƯỜI DÙNG YÊU CẦU: Không tự động suy luận nội dung thi. 
        // Nếu trống sẽ để trống và cảnh báo ở bước sau.

        return record;
    });
};

export const processExcelData = (rawRecords: StudentRecord[]): AppData => {
    const records = normalizeData(rawRecords);
    const firstTimeData: { [className: string]: LicenseClassData } = {};
    const retakeData: { [className: string]: LicenseClassData } = {};

    for (const record of records) {
        const className = String(record['HẠNG GPLX'] || '').trim();
        if (!className) continue;

        const maHocVien = String(record['MÃ HỌC VIÊN'] || '').trim();
        const isRetake = maHocVien.includes('2721') || maHocVien.includes('2722');

        const targetData = isRetake ? retakeData : firstTimeData;

        if (!targetData[className]) {
            targetData[className] = createNewClassData(className);
        }
        const classData = targetData[className];
        classData.totalApplications += 1;

        if (!isStudentAbsent(record)) {
            classData.totalParticipants += 1;
        }

        const theoryRes = getResultStatus(record['LÝ THUYẾT']);
        if (theoryRes.participated) {
            classData.theory.total += 1;
            if (theoryRes.passed) classData.theory.pass += 1;
        }

        const simRes = getResultStatus(record['MÔ PHỎNG']);
        if (simRes.participated) {
            classData.simulation.total += 1;
            if (simRes.passed) classData.simulation.pass += 1;
        }

        const practicalRes = getResultStatus(record['SA HÌNH']);
        if (practicalRes.participated) {
            classData.practicalCourse.total += 1;
            if (practicalRes.passed) classData.practicalCourse.pass += 1;
        }

        const onRoadRes = getResultStatus(record['ĐƯỜNG TRƯỜNG']);
        if (onRoadRes.participated) {
            classData.onRoad.total += 1;
            if (onRoadRes.passed) classData.onRoad.pass += 1;
        }

        if (isStudentPassed(record)) {
            classData.finalPass += 1;
        }
    }

    const finalizeData = (data: { [className: string]: LicenseClassData }): LicenseClassData[] => {
        const classDataArray = Object.values(data);
        for (const classData of classDataArray) {
            classData.theory.fail = Math.max(0, classData.theory.total - classData.theory.pass);
            classData.simulation.fail = Math.max(0, classData.simulation.total - classData.simulation.pass);
            classData.practicalCourse.fail = Math.max(0, classData.practicalCourse.total - classData.practicalCourse.pass);
            classData.onRoad.fail = Math.max(0, classData.onRoad.total - classData.onRoad.pass);
        }
        return classDataArray.sort((a, b) => a.class.localeCompare(b.class));
    };

    return {
        firstTime: { title: 'a) Học viên dự thi lần đầu:', rows: finalizeData(firstTimeData) },
        retake: { title: 'b) Thí sinh thuộc đối tượng cấp lại giấy phép lái xe và thí sinh tự do:', rows: finalizeData(retakeData) }
    };
};

import React, { useState, useEffect } from 'react';
import type { TrainingUnit } from '../../types';
import { storageService } from '../../services/storageService';
import { normalizeKeyForMatching } from '../../services/excelProcessor';

declare const XLSX: any;

interface TrainingUnitManagerProps {
    trainingUnits: TrainingUnit[];
    onUnitsImport: (units: TrainingUnit[]) => void;
}

export const TrainingUnitManager: React.FC<TrainingUnitManagerProps> = ({ trainingUnits, onUnitsImport }) => {
    const [unitUploadError, setUnitUploadError] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState(false);

    // Modal State
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingUnit, setEditingUnit] = useState<TrainingUnit | null>(null);
    const [formData, setFormData] = useState({ code: '', name: '' });

    // Refresh data on mount to ensure we have the latest from DB
    useEffect(() => {
        const loadUnits = async () => {
            try {
                const units = await storageService.getAllTrainingUnits();
                onUnitsImport(units);
            } catch (error) {
                console.error("Failed to load units on mount", error);
            }
        };
        loadUnits();
    }, []);

    const handleUnitFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        setUnitUploadError(null);
        if (e.target.files && e.target.files[0]) {
            setIsLoading(true);
            const file = e.target.files[0];
            const reader = new FileReader();

            // Đảm bảo loading được tắt nếu có lỗi đọc file ngay lập tức
            reader.onerror = () => {
                setUnitUploadError("Lỗi đọc file từ thiết bị.");
                setIsLoading(false);
            };

            reader.onload = async (event) => {
                try {
                    const data = new Uint8Array(event.target!.result as ArrayBuffer);
                    const workbook = XLSX.read(data, { type: 'array' });
                    const sheetName = workbook.SheetNames[0];
                    const worksheet = workbook.Sheets[sheetName];
                    const json: any[] = XLSX.utils.sheet_to_json(worksheet, { defval: "" });

                    const newUnits: TrainingUnit[] = [];

                    // Danh sách từ khóa nhận diện linh hoạt hơn
                    const CODE_KEYWORDS = ['madv', 'code', 'madonvi', 'ma', 'prefix'];
                    const NAME_KEYWORDS = ['tendv', 'name', 'tendonvi', 'ten', 'donvi'];

                    // Xử lý dữ liệu thô
                    for (const row of json) {
                        const rowKeys = Object.keys(row);
                        let unitCode: string | null = null;
                        let unitName: string | null = null;

                        for (const key of rowKeys) {
                            const normalizedKey = normalizeKeyForMatching(key);

                            // Chỉ gán nếu giá trị thực sự tồn tại (không rỗng)
                            const val = String(row[key] || "").trim();
                            if (!val) continue;

                            if (!unitCode && CODE_KEYWORDS.some(kw => normalizedKey === kw || normalizedKey.includes(kw))) {
                                unitCode = val;
                            }
                            if (!unitName && NAME_KEYWORDS.some(kw => normalizedKey === kw || normalizedKey.includes(kw))) {
                                unitName = val;
                            }
                        }

                        // Chỉ thêm nếu có đủ Mã và Tên
                        if (unitCode && unitName) {
                            newUnits.push({
                                id: `unit-${unitCode}`,
                                code: unitCode,
                                name: unitName
                            });
                        }
                    }

                    if (newUnits.length === 0) {
                        setUnitUploadError("Không tìm thấy dữ liệu đơn vị hợp lệ. Vui lòng kiểm tra tiêu đề MaDv và TenDV.");
                    } else {
                        // Lưu vào DB
                        await storageService.importTrainingUnits(newUnits);
                        // Cập nhật lại danh sách hiển thị
                        const refreshedUnits = await storageService.getAllTrainingUnits();
                        onUnitsImport(refreshedUnits);
                        alert(`Đã nạp thành công ${newUnits.length} đơn vị đào tạo!`);
                    }
                } catch (err) {
                    setUnitUploadError("Lỗi xử lý file Excel hoặc lỗi đồng bộ Server.");
                    console.error("Error processing Unit Excel:", err);
                } finally {
                    // Luôn luôn tắt loading
                    setIsLoading(false);
                    e.target.value = '';
                }
            };
            reader.readAsArrayBuffer(file);
        }
    };

    const downloadUnitSample = () => {
        const sampleData = [
            { 'MaDv': '2721', 'TenDV': 'Trung tâm Đông Đô' },
            { 'MaDv': '2722', 'TenDV': 'Trung tâm Âu Lạc' },
            { 'MaDv': '24001', 'TenDV': 'Trường Trung cấp 1' }
        ];
        const worksheet = XLSX.utils.json_to_sheet(sampleData);
        const workbook = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(workbook, worksheet, "DonViDaoTao");
        XLSX.writeFile(workbook, "Mau_Don_Vi_Dao_Tao.xlsx");
    };

    // CRUD Handlers
    const handleAddClick = () => {
        setEditingUnit(null);
        setFormData({ code: '', name: '' });
        setIsModalOpen(true);
    };

    const handleEditClick = (unit: TrainingUnit) => {
        setEditingUnit(unit);
        setFormData({ code: unit.code, name: unit.name });
        setIsModalOpen(true);
    };

    const handleDeleteClick = async (id: string) => {
        if (window.confirm('Bạn có chắc chắn muốn xóa đơn vị này không?')) {
            setIsLoading(true);
            try {
                await storageService.deleteTrainingUnit(id);
                const refreshedUnits = await storageService.getAllTrainingUnits();
                onUnitsImport(refreshedUnits);
            } catch (error) {
                alert('Có lỗi xảy ra khi xóa!');
            } finally {
                setIsLoading(false);
            }
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.code || !formData.name) return;

        setIsLoading(true);
        try {
            const unitToSave: TrainingUnit = {
                id: editingUnit ? editingUnit.id : `unit-${formData.code.trim()}`,
                code: formData.code.trim(),
                name: formData.name.trim()
            };

            await storageService.saveTrainingUnit(unitToSave);
            const refreshedUnits = await storageService.getAllTrainingUnits();
            onUnitsImport(refreshedUnits);
            setIsModalOpen(false);
        } catch (error) {
            alert('Lỗi khi lưu dữ liệu!');
            console.error(error);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="p-6 md:p-10 h-full overflow-y-auto bg-gray-100 dark:bg-gray-900 transition-colors">
            <div className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-4">
                <div>
                    <h2 className="text-2xl font-bold text-gray-800 dark:text-white">Đơn vị Đào tạo</h2>
                    <p className="text-gray-500 dark:text-gray-400 mt-1">Quản lý danh sách các đơn vị đào tạo lái xe để tự động nhận diện thí sinh.</p>
                </div>
                <div className="flex gap-2">
                    <button 
                        onClick={handleAddClick}
                        className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 shadow-sm transition-colors flex items-center gap-2 font-bold"
                    >
                        <i className="fa-solid fa-plus"></i> Thêm Mới
                    </button>
                    <button 
                        onClick={downloadUnitSample}
                        className="px-4 py-2 bg-white dark:bg-gray-800 border border-blue-200 dark:border-blue-800 text-blue-600 dark:text-blue-400 rounded-lg hover:bg-blue-50 dark:hover:bg-blue-900/30 shadow-sm transition-colors flex items-center gap-2 font-medium"
                    >
                        <i className="fa-solid fa-download"></i> Tải file mẫu
                    </button>
                </div>
            </div>

            <div className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 overflow-hidden">
                <div className="p-6 border-b border-gray-100 dark:border-gray-700 bg-gray-50 dark:bg-gray-750">
                    <label className="block text-sm font-bold text-gray-700 dark:text-gray-200 mb-2">
                        <i className="fa-solid fa-file-import mr-2"></i>Nhập nhanh từ Excel (Hỗ trợ tiêu đề MaDv, TenDV)
                    </label>
                    <div className="flex gap-4">
                        <input 
                            type="file" 
                            accept=".xlsx, .xls"
                            onChange={handleUnitFileChange}
                            disabled={isLoading}
                            className="block w-full text-sm text-gray-500 dark:text-gray-400 file:mr-4 file:py-2.5 file:px-4 file:rounded-lg file:border-0 file:text-sm file:font-semibold file:bg-teal-600 file:text-white hover:file:bg-teal-700 cursor-pointer bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-lg disabled:opacity-50" 
                        />
                    </div>
                    {unitUploadError && (
                        <div className="mt-3 text-sm text-red-600 dark:text-red-400 bg-red-50 dark:bg-red-900/20 p-2 rounded border border-red-100 dark:border-red-900 flex items-center gap-2">
                            <i className="fa-solid fa-circle-exclamation"></i>
                            {unitUploadError}
                        </div>
                    )}
                </div>

                {isLoading && (
                    <div className="p-12 text-center bg-gray-50 dark:bg-gray-800/50">
                        <i className="fa-solid fa-spinner animate-spin text-4xl text-blue-600 mb-3"></i>
                        <p className="text-blue-600 dark:text-blue-400 font-bold">Đang nạp dữ liệu đơn vị, vui lòng đợi...</p>
                    </div>
                )}

                {!isLoading && (
                    <div className="overflow-x-auto">
                        {trainingUnits.length === 0 ? (
                            <div className="p-12 text-center text-gray-500 dark:text-gray-400">
                                <i className="fa-solid fa-building-columns text-4xl mb-3 text-gray-300 dark:text-gray-600"></i>
                                <p className="font-medium">Chưa có dữ liệu đơn vị nào.</p>
                                <p className="text-sm mt-1">Vui lòng thêm mới hoặc tải file Excel lên.</p>
