  practicalCourse: TestResultSchema,
  onRoad: TestResultSchema,
  finalPass: z.number(),
});

export const StudentRecordSchema = z.record(z.any());

export const SavedSessionSchema = z.object({
  id: z.string(),
  name: z.string(),
  createdAt: z.number(),
  reportDate: z.string(),
  studentRecords: z.array(StudentRecordSchema),
  appData: z.any(),
