import { SavedSessionSchema, type SavedSession } from '../schemas/session.schema';
import { z } from 'zod';

const API_BASE = '/api';
const LOCAL_SESSIONS_KEY = 'driving_test_sessions_local';
const LOCAL_UNITS_KEY = 'driving_test_units_local';

export const storageService = {
  // --- SESSIONS ---
  async getAllSessions(): Promise<SavedSession[]> {
    try {
      const res = await fetch(`${API_BASE}/sessions`);
      if (!res.ok) throw new Error("Network response was not ok");
      const data = await res.json();
      return z.array(SavedSessionSchema).parse(data);
    } catch (e) {
      console.warn("[Storage] API Error, falling back to LocalStorage:", e);
      const local = localStorage.getItem(LOCAL_SESSIONS_KEY);
      if (!local) return [];
      try {
        return z.array(SavedSessionSchema).parse(JSON.parse(local));
      } catch (parseErr) {
        console.error("[Storage] Local data corrupted:", parseErr);
        return [];
      }
    }
  },

  async saveSession(session: SavedSession): Promise<void> {
    // 1. Lưu vào LocalStorage trước để đảm bảo không mất dữ liệu
    const current = await this.getAllSessions();
    const updated = [session, ...current.filter(s => s.id !== session.id)];
    localStorage.setItem(LOCAL_SESSIONS_KEY, JSON.stringify(updated));

    // 2. Thử đẩy lên Cloud
    try {
      const res = await fetch(`${API_BASE}/sessions`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(session),
      });
      if (!res.ok) throw new Error("Sync failed");
    } catch (e) {
      console.error("[Storage] Cloud sync failed, session kept in LocalStorage.");
    }
  },

  async deleteSession(id: string): Promise<void> {
    const current = await this.getAllSessions();
    const updated = current.filter(s => s.id !== id);
    localStorage.setItem(LOCAL_SESSIONS_KEY, JSON.stringify(updated));

    try {
      await fetch(`${API_BASE}/sessions/${id}`, { method: 'DELETE' });
    } catch (e) {}
  },

  // --- TRAINING UNITS ---
  async getAllTrainingUnits(): Promise<any[]> {
    try {
      const res = await fetch(`${API_BASE}/training-units`);
      return await res.json();
    } catch (e) {
      const local = localStorage.getItem(LOCAL_UNITS_KEY);
      return local ? JSON.parse(local) : [];
    }
  }
};

