require('dotenv').config();
const express = require('express');
const cors = require('cors');
const path = require('path');
const { Pool } = require('pg');

const SERVER_VERSION = '4.1.0';
const app = express();
// Cloud Run uses the PORT environment variable. Default to 8080.
const port = process.env.PORT || 8080;

// Database Configuration from Environment Variables
const isProduction = process.env.NODE_ENV === 'production';

const poolConfig = {
    user: process.env.DB_USER,
    password: process.env.DB_PASSWORD,
    database: process.env.DB_NAME,
    max: 10,
    idleTimeoutMillis: 30000,
    connectionTimeoutMillis: 5000,
};

if (process.env.INSTANCE_CONNECTION_NAME && isProduction) {
    // Unix socket connection for Cloud SQL in production
    poolConfig.host = `/cloudsql/${process.env.INSTANCE_CONNECTION_NAME}`;
} else if (process.env.DB_HOST) {
    // TCP connection for local or other environments
    poolConfig.host = process.env.DB_HOST;
    poolConfig.port = process.env.DB_PORT || 5432;
    // Common for local dev with SSL
    if (!isProduction) poolConfig.ssl = { rejectUnauthorized: false };
}

let pool;
let isDbConnected = false;

// Initialize Pool only if config is present
if (poolConfig.user && poolConfig.password && poolConfig.database) {
    pool = new Pool(poolConfig);
    pool.on('error', (err) => {
        console.error('Unexpected error on idle database client', err);
        isDbConnected = false;
    });
} else {
    console.warn("⚠️ Database credentials missing. Server will start in limited mode.");
}

const initSchema = async () => {
    if (!pool) return;
    const schema = `
        CREATE TABLE IF NOT EXISTS sessions (id VARCHAR(255) PRIMARY KEY, data JSONB NOT NULL, report_date TIMESTAMPTZ, created_at BIGINT);
        CREATE TABLE IF NOT EXISTS training_units (id VARCHAR(255) PRIMARY KEY, code VARCHAR(50) NOT NULL, name VARCHAR(255) NOT NULL, created_at BIGINT);
    `;
    try {
        await pool.query(schema);
        console.log("✅ Database Schema Verified.");
    } catch (err) {
        console.error("❌ Schema initialization failed:", err.message);
    }
};

const connectDb = async () => {
    if (!pool) return;
    try {
        const client = await pool.connect();
        const res = await client.query('SELECT NOW()');
        client.release();
        console.log(`✅ DB Connected: ${res.rows[0].now}`);
        isDbConnected = true;
        await initSchema();
    } catch (err) {
        console.error('❌ DB Connection Failed:', err.message);
        isDbConnected = false;
    }
};

// Start DB connection in background to avoid blocking the server listener
if (pool) connectDb();

// --- MIDDLEWARE ---
app.use(cors({ origin: '*' }));
app.use(express.json({ limit: '50mb' }));

// --- HEALTH CHECK (CRITICAL FOR CLOUD RUN) ---
app.get('/health', (req, res) => res.status(200).send('OK'));

// --- API ROUTES ---
app.get('/api/server-status', async (req, res) => {
    let status = isDbConnected;
    if (pool) {
        try {
            await pool.query('SELECT 1');
            status = true;
        } catch (e) {
            status = false;
        }
    }
    res.json({ success: true, version: SERVER_VERSION, dbConnected: status });
});

app.get('/api/sessions', async (req, res) => {
    if (!pool) return res.status(503).json({ error: 'DB not configured' });
    try {
        const result = await pool.query('SELECT data FROM sessions ORDER BY created_at DESC');
        res.json(result.rows.map(r => r.data));
    } catch (err) {
        res.status(500).json({ error: err.message });
    }
});

app.post('/api/sessions', async (req, res) => {
    if (!pool) return res.status(503).json({ error: 'DB not configured' });
    const s = req.body;
    try {
        await pool.query(
            'INSERT INTO sessions (id, data, report_date, created_at) VALUES ($1, $2, $3, $4) ON CONFLICT (id) DO UPDATE SET data = EXCLUDED.data, report_date = EXCLUDED.report_date',
            [s.id, JSON.stringify(s), s.reportDate, s.createdAt]
        );
        res.json({ success: true });
    } catch (err) {
        res.status(500).json({ error: err.message });
    }
});

app.get('/api/training-units', async (req, res) => {
    if (!pool) return res.status(503).json({ error: 'DB not configured' });
    try {
        const result = await pool.query('SELECT * FROM training_units ORDER BY created_at ASC');
        res.json(result.rows);
    } catch (err) {
        res.status(500).json({ error: err.message });
    }
});

app.post('/api/training-units/batch', async (req, res) => {
    if (!pool) return res.status(503).json({ error: 'DB not configured' });
    const client = await pool.connect();
    try {
        await client.query('BEGIN');
        for (const u of req.body) {
            await client.query(
                'INSERT INTO training_units (id, code, name, created_at) VALUES ($1, $2, $3, $4) ON CONFLICT (id) DO UPDATE SET code = EXCLUDED.code, name = EXCLUDED.name',
                [u.id, u.code, u.name, u.created_at || Date.now()]
            );
        }
        await client.query('COMMIT');
        res.json({ success: true });
    } catch (e) {
        await client.query('ROLLBACK');
        res.status(500).json({ error: e.message });
    } finally {
        client.release();
    }
});

// --- STATIC FILES & SPA FALLBACK ---
// We check multiple potential paths for the build output to be robust across different deploy styles
const distPaths = [
    path.join(__dirname, '../client/dist'),
    path.join(__dirname, 'dist'),
    path.join(__dirname, '../dist')
];

let actualDistPath = distPaths[0]; // default
for (const p of distPaths) {
    if (require('fs').existsSync(p)) {
        actualDistPath = p;
        break;
    }
}

console.log(`📂 Serving static files from: ${actualDistPath}`);
app.use(express.static(actualDistPath));

app.get('*', (req, res) => {
    // Only serve index.html for non-API routes
    if (!req.path.startsWith('/api')) {
        const indexPath = path.join(actualDistPath, 'index.html');
        res.sendFile(indexPath, (err) => {
            if (err) {
                // If the frontend isn't built yet, provide a clear message instead of crashing
                res.status(404).send('Frontend application not found. Please ensure "npm run build" was successful.');
            }
        });
    } else {
        res.status(404).json({ error: 'API endpoint not found' });
    }
});

