import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import * as XLSX from 'xlsx';
import { storageService } from '../services/storage.service';
import { useToast } from '../components/ui/ToastContext';
import { SavedSession } from '../schemas/session.schema';

export const DataInputPage: React.FC = () => {
  const [isLoading, setIsLoading] = useState(false);
  const [previewData, setPreviewData] = useState<any[] | null>(null);
  const [fileName, setFileName] = useState<string>('');
  const { showToast } = useToast();
  const navigate = useNavigate();

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setFileName(file.name);
    setIsLoading(true);

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws);

        // Normalize headers và dữ liệu
        const normalized = data.map((row: any) => ({
          sbd: row['SBD'] || row['Số báo danh'] || '',
          name: row['Họ và tên'] || row['Tên'] || '',
          id: String(row['Mã học viên'] || row['Mã HV'] || ''),
          class: row['Hạng'] || 'B2',
          theory: row['Lý thuyết'] || '',
          simulation: row['Mô phỏng'] || '',
          practice: row['Sa hình'] || '',
          road: row['Đường trường'] || '',
        }));

        setPreviewData(normalized);
        showToast(`Đã đọc ${normalized.length} dòng dữ liệu`, 'info');
      } catch (err) {
        showToast('Không thể đọc file Excel', 'error');
      } finally {
        setIsLoading(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  const handleSave = async () => {
    if (!previewData) return;
    setIsLoading(true);

    try {
      // Tính toán Grand Total đơn giản
      const totals = {
        class: 'B2',
        totalApplications: previewData.length,
        totalParticipants: previewData.filter(d => d.theory !== 'Vắng').length,
        theory: { total: previewData.length, pass: previewData.filter(d => d.theory === 'Đạt').length, fail: 0 },
        simulation: { total: previewData.length, pass: previewData.filter(d => d.simulation === 'Đạt').length, fail: 0 },
        practicalCourse: { total: previewData.length, pass: previewData.filter(d => d.practice === 'Đạt').length, fail: 0 },
        onRoad: { total: previewData.length, pass: previewData.filter(d => d.road === 'Đạt').length, fail: 0 },
        finalPass: previewData.filter(d => d.theory === 'Đạt' && d.road === 'Đạt').length,
      };

      const session: SavedSession = {
        id: Date.now().toString(),
        name: fileName.replace(/\.[^/.]+$/, "") || `Kỳ thi ${new Date().toLocaleDateString()}`,
        createdAt: Date.now(),
        reportDate: new Date().toISOString(),
        studentRecords: previewData,
        appData: {},
        grandTotal: totals,
        reportMetadata: { totalRows: previewData.length }
      };

      await storageService.saveSession(session);
      showToast('Đã lưu dữ liệu thành công', 'success');
      navigate('/dashboard');
    } catch (err) {
      showToast('Lỗi khi lưu dữ liệu', 'error');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="p-8 max-w-6xl mx-auto">
      <div className="mb-8 flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Tạo Kỳ Sát Hạch Mới</h1>
          <p className="text-slate-500">Tải lên file Excel kết quả 4 phần thi</p>
        </div>
        {previewData && (
          <div className="flex gap-3">
            <button onClick={() => setPreviewData(null)} className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg font-medium">Hủy</button>
            <button onClick={handleSave} disabled={isLoading} className="bg-blue-600 text-white px-6 py-2 rounded-lg font-bold shadow-lg hover:bg-blue-700 disabled:opacity-50">
              {isLoading ? 'Đang lưu...' : 'Xác nhận Lưu'}
            </button>
          </div>
        )}
      </div>

      {!previewData ? (
        <div className="border-2 border-dashed border-slate-300 rounded-2xl p-20 text-center bg-white hover:border-blue-400 transition-colors">
          <input type="file" id="excel-input" accept=".xlsx, .xls" onChange={handleFileUpload} className="hidden" />
          <label htmlFor="excel-input" className="cursor-pointer">
            <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-4">
              <i className="fa-solid fa-cloud-arrow-up text-2xl"></i>
            </div>
            <p className="text-lg font-medium text-slate-700">Nhấn để chọn file Excel kết quả</p>
            <p className="text-sm text-slate-400 mt-2">Hỗ trợ .xlsx, .xls (SBD, Họ tên, Lý thuyết, Mô phỏng...)</p>
          </label>
        </div>
      ) : (
        <div className="bg-white rounded-xl shadow-sm border overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-sm text-left">
              <thead className="bg-slate-50 border-b">
                <tr>
                  <th className="px-4 py-3 font-bold">SBD</th>
                  <th className="px-4 py-3 font-bold">Họ và Tên</th>
                  <th className="px-4 py-3 font-bold text-center">Lý Thuyết</th>
                  <th className="px-4 py-3 font-bold text-center">Mô Phỏng</th>
                  <th className="px-4 py-3 font-bold text-center">Sa Hình</th>
                  <th className="px-4 py-3 font-bold text-center">Đường Trường</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {previewData.slice(0, 50).map((row, i) => (
                  <tr key={i} className="hover:bg-slate-50">
                    <td className="px-4 py-3 font-mono">{row.sbd}</td>
                    <td className="px-4 py-3 font-medium">{row.name}</td>
                    <td className="px-4 py-3 text-center">
                      <span className={`px-2 py-1 rounded text-xs font-bold ${row.theory === 'Đạt' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>{row.theory}</span>
                    </td>
                    <td className="px-4 py-3 text-center">{row.simulation}</td>
                    <td className="px-4 py-3 text-center">{row.practice}</td>
                    <td className="px-4 py-3 text-center">{row.road}</td>
                  </tr>
                ))}
              </tbody>
            </table>
            {previewData.length > 50 && <div className="p-4 text-center text-slate-400 italic bg-slate-50">Và {previewData.length - 50} học viên khác...</div>}
          </div>
        </div>
      )}
    </div>
  );
};

