                  <td className="px-6 py-4 font-medium text-slate-700">{unit.name}</td>
                  <td className="px-6 py-4 text-right">
                    <button className="text-red-500 hover:bg-red-50 p-2 rounded-lg"><i className="fa-solid fa-trash"></i></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

const SystemSettings = () => {
  const [status, setStatus] = useState<any>(null);

  useEffect(() => {
    fetch('/api/server-status')
      .then(res => res.json())
      .then(data => setStatus(data))
      .catch(() => setStatus({ success: false }));
  }, []);

  return (
    <div className="grid gap-6 md:grid-cols-2">
      <div className="bg-white p-6 rounded-xl border shadow-sm">
        <h3 className="font-bold mb-4 flex items-center gap-2">
          <i className="fa-solid fa-server text-blue-500"></i> Trạng thái Hệ thống
        </h3>
        <div className="space-y-4 text-sm">
          <div className="flex justify-between py-2 border-b">
            <span className="text-slate-500">Phiên bản Backend</span>
            <span className="font-mono font-bold text-slate-700">{status?.version || 'Unknown'}</span>
          </div>
          <div className="flex justify-between py-2 border-b">
            <span className="text-slate-500">Kết nối Database</span>
            <span className={`font-bold ${status?.dbConnected ? 'text-green-600' : 'text-red-600'}`}>
              {status?.dbConnected ? 'Hoạt động' : 'Mất kết nối'}
            </span>
          </div>
          <div className="flex justify-between py-2">
            <span className="text-slate-500">Uptime</span>
            <span className="text-slate-700 font-medium">{status?.uptime ? `${Math.floor(status.uptime / 60)} phút` : '--'}</span>
          </div>
        </div>
      </div>

      <div className="bg-white p-6 rounded-xl border shadow-sm">
        <h3 className="font-bold mb-4 flex items-center gap-2">
          <i className="fa-solid fa-database text-orange-500"></i> Cơ sở dữ liệu
        </h3>
        <p className="text-sm text-slate-500 mb-6 leading-relaxed">
          Ứng dụng sử dụng PostgreSQL (Google Cloud SQL) để lưu trữ vĩnh viễn. 
          Trong trường hợp mất kết nối, dữ liệu sẽ được lưu tạm tại trình duyệt.
        </p>
        <button className="w-full bg-slate-800 text-white py-2 rounded-lg font-bold text-sm hover:bg-slate-900 transition-colors">
          Đồng bộ thủ công LocalStorage
        </button>
      </div>
    </div>
  );
};

